INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('index', 'Home', '<h1>WELCOME TO THE BMW CAR CLUB CANBERRA</h1>
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('merchandise', 'Merchandise', '<div><div><div><table><tbody><tr><td><div><div><div><div><h1>BMW Car club Canberra merchandise</h1></div></div><div><div><p><span><span>Celebrate Our Club''s 40th Anniversary with Limited Edition Merchandise!</span></span></p><p><span><span><span>To mark this milestone, we’re releasing exclusive 40th Anniversary merchandise featuring premium embroidered polo shirts, jackets, and caps. This is your chance to own a piece of our club’s history and wear it with pride.</span></span></span></p><p><span><span><span>All merchandise is proudly sourced and professionally embroidered by a Canberra-based business, helping us support our local community.</span><br></span></span></p><p><strong>How to Order:<br></strong>To access special member pricing, log in to the website and place your order below.<br><strong>Be quick, orders close 15 June 2025</strong>, and we don’t want you to miss out!</p><p><strong>Important:<br></strong>Only fully paid orders will be sent to the vendor for production, so please complete payment promptly!</p><p><strong>Payment Options:</strong><br>PayPal via website on checkout.<br>Direct Bank Transfer to the club''s account (details below).</p><ul><li>Account Name: BMW Car Club Canberra</li><li>BSB: 633-000</li><li>Account Number: 125925727</li><li>Reference: xSURNAME+Club Merchx</li></ul><em>For those wanting to make direct payment, please ensure you email treasurer@bmwclubcanberra.org.au with payment confirmation once complete.</em><p><strong>Pickup &amp; Delivery:<br></strong>All orders will be sent to the vendor after 15 June, and production will take approximately 5 to 10 business days.<br>We’ll arrange pickup times and locations once the merchandise is ready. If you’re located interstate (outside Canberra and surrounds), we’ll post your order to you.</p><p><br></p></div></div></div></div></td></tr></tbody></table></div><div><table><tbody><tr><td></td></tr></tbody></table></div><div><table><tbody><tr><td></td><td></td><td></td></tr></tbody></table></div><div><p>There are no products to display</p></div><div><table><tbody><tr><td></td><td></td><td></td></tr></tbody></table></div><div><table><tbody><tr><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table></div><div><table><tbody><tr><td></td><td></td><td></td></tr></tbody></table></div></div></div>', false, true, 2, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('magazine', 'Magazine', '<div><div><div><table><tbody><tr><td><div><div><div><div><p><span><span><span><strong>THE CAPITAL ROUNDEL MAGAZINE</strong></span><br></span><span><br>The Capital Roundel magazine is sent via email to all members on a quarterly basis and is one of the benefits of membership.</span></span></p><p><span>Content varies from issue to issue, but the publication mostly contains information on new releases and initiatives from BMW, reviews of cars and products, etc. There are also historical and topical articles submitted by members or written by our Editor.</span></p><p><span>We encourage our members to submit articles about recent events, or profiles of themselves and their cars and other topics of interest to be published in the magazine and on the website. Articles and comments on the magazine can be emailed to the editor@bmwclubcanberra.org.au.</span></p><p><br></p></div></div></div></div></td></tr></tbody></table></div><div><table><tbody><tr><td><div><div><div><div><p><br></p></div></div></div></div></td><td></td><td><div><div><div><div><p><span>Check out the latest copy of the Capital Roundel</span></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/capital-roundel-1-2026-083272b2-f38bfe6e.pdf" target="_blank">Capital Roundel</a><br></p><p><br></p></div></div></div></div></td><td></td><td><div><div><div><div><p><br></p></div></div></div></div></td></tr></tbody></table></div></div></div>', false, true, 4, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('motorsport', 'Motorsport', '<div><div><div><table><tbody><tr><td><div><div><div><div><p><span><strong><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-australia-member-club-300x142-a8879ebd-0ea35890.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-australia-member-club-300x142-a8879ebd-eea8341c.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-australia-member-club-300x142-a8879ebd-eea8341c.webp" loading="lazy" alt="About Our Club | Gold Coast Tweed Motorsporting Club"></picture><br></strong></span></p><p><span><strong>M</strong></span><span><strong>OTOR</strong></span><span><strong>SP</strong></span><strong>ORT</strong></p><p><span>The Motorsport division of the BMW Car Club Canberra is dedicated to setting Motorsport events that allow members to not only learn to drive their cars faster on the racetrack, but also in a safer manner on the road. We are affiliated with Motorsport Australia under a ''Sporting Club''.</span></p><p><span>We have an enthusiastic group of members that enjoy driving their cars as BMW intended. Our Motorsport events are orientated towards fun and safety. We want every car and person to go home as they started the day, only with a bigger smile on their face. The team are available to assist in obtaining a<span>Motorsport Australia</span>and AASA track licences for members who require them, and the Club recommends anyone who participates in track activities should get one for the additional insurance coverage they provide. We have former competitive race drivers who help out at club track days.</span></p><p>DRIVER TRAINING</p><p><span>The club promotes safe driving at all times, and to this end we have some experienced driver trainers who are willing to instruct at our track days. Track days take place at Sutton Road Training Centre (near Queanbeyan), Wakefield Park (near Goulburn), Eastern Creek (in Sydney) and Morulan Driver Training Centre with the BMW Club NSW.</span></p><p><span>BMW Driving Experiences run by BMW Australia are also a great way of getting some track experience. Anyone who purchases a genuine M Car (with WBS VIN) new from BMW is invited to participate in a complimentary BMW driving experience and receives 1 year free membership of BMW Car Club Canberra.</span></p><p><br></p></div></div></div></div></td><td></td><td></td><td></td><td><div><div><div><div><p><br></p></div></div></div></div></td></tr></tbody></table></div></div></div>', false, true, 5, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('join-us', 'Join Us', '<div><div><div><div><h1><span>Join us</span></h1><p><span>Since 1985 we’ve been driving through some of the area’s best driving roads, organising track days, social dinners, driver training, show ''n'' shines, inter-club meetings, and much more! Whether you’re driving a new, old or modified BMW, we’re all about the driving experience and welcome anyone from Canberra and surrounding areas who owns a BMW to get involved.</span></p><p><span><span><strong>BENEFITS</strong></span></span></p><ul><li>Access to the wealth of BMW knowledge, help and support</li><li>Life-long friendships</li><li>Fun and family environment to share your interest in BMWs with like-minded people</li><li>Great variety of events and opportunities including social meets, car shows, tech nights and club drives</li><li>Driver training, skid pan and track events (We are also Motorsport Australia affiliated)</li><li>Access to the ACT and NSW Concessional Registration Schemes (CRS) for eligible motor vehicles</li><li>Exclusive access to member-only events and tours globally</li><li>International Connections with BMW enthusiasts and ability to attend events when travelling.</li></ul><p>Financial:</p><ul><li>*10% discount on Genuine BMW parts, BMW servicing &amp; BMW driver experiences through Canberra BMW</li><li>Access to the BMW Corporate Advantage program when buying a new BMW or MINI at Canberra BMW and MINI Garage</li><li>*Special discounted hourly labour rate at Advanced Tech Automotive and Anthony Costello Automotive</li><li>*Exclusive discount at Autobarn Tuggeranong</li><li>*15% discount on Jay Leno''s Garage Australia products</li><li>*10% discount at BEST EXHAUST</li><li>*Special discount at Prestige Collectables</li><li>Discounted entry to Official BMW Club events Nationally.</li></ul><p><span>*P</span><em><span>resent proof of current membership card to be eligible</span></em></p></div></div></div></div>', false, true, 6, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('contact-us', 'Contact Us', '<div><div><div><div><h1><span>Contact us</span></h1></div></div><div><table><tbody><tr><td><div><div><div><div><p><span><span>Please feel free to contact us with questions about the Club, or reach out to us on Facebook. The BMW Car Club Canberra is run by volunteers.</span></span></p><p><strong><span>MAILING ADDRESS</span></strong></p><p><span>BMW Car Club Canberra<br>PO Box 546,</span><span>C</span><span>urtin ACT 2605</span></p><p><span><strong>SOCIALS</strong><br>We''ve got an active Facebook community so feel free to reach out to us with your BMW questions.</span></p></div></div></div></div></td><td></td><td></td><td></td><td><div><div><div><div><p><br></p></div></div></div></div></td></tr></tbody></table></div><div><div><ul><li><a href="https://www.facebook.com/BMWCCACT" title="Facebook" target="_blank" rel="noopener">Facebook</a></li><li><a href="https://x.com/wildapricot" title="X" target="_blank" rel="noopener">X</a></li><li><a href="https://www.instagram.com/bmwclubcanberra/" title="Instagram" target="_blank" rel="noopener">Instagram</a></li></ul></div></div></div></div>', false, true, 7, true);
