INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3177936, 'Poker Run', '<p>Annual Poker Run, dvcSVSCVsvSVsvsVSSVSSVSV SDDVssdsdsCscsdsSDvS SDVss ssSSS S SVSsvSVSvSVSDVSvsdvvSVSvs sc s s sdsvsVsvsvssvsdvv</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/imagewa-413d4b69-5303a438.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/imagewa-413d4b69-aa4f55de.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/imagewa-413d4b69-aa4f55de.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', '', '2019-02-05T07:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/imagewa-413d4b69-aa4f55de.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3177938, 'Nowra Run', '<p><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', '', '2019-02-16T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3321571, 'Phillip Island Classic - Club run', '<p><span><span>For those that have never been to Phillip Island you need to add it to your list!</span></span><br><br><span><span>Recognised as one of the world’s largest historic motor racing events on the international calendar by the number of entries and races held over the three days, the Phillip Island Classic is expected to once again draw more than 500 entries with vehicles from around the world.</span></span><br><br><span><span>2019 marks the 30th Phillip Island Classic event along with other significant anniversaries such as the 60th anniversary of Formula Ford, the 60th anniversary of the Mini, the 50th anniversary of the Holden Dealer Team which first raced at Sandown in 1969, the 50th anniversary of the Alfa Romeo Car Club, 50 years of Formula Ford and 51st year of Porsche and it’s also the 50th year of the Bolwell Nagari.</span></span><br></p>', 'Back Beach Road, Cowes, Victoria', '2019-03-07T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3330813, 'Members Meeting', '<p><span>Join us for a meal and a chat upstairs at the East Lake Football Club for our regular club meeting on the first Wednesday of the month.</span></p><p><span>The BMW club Canberra members meeting is a great opportunity to chat with other members, enjoy a nice dinner and find out what is going on with your Car Club. Members and non-members are welcome to attend.</span></p><p><span>The club’s committee members will be available to answer your questions and assist with membership and club plate applications.</span></p><p><span>The downstairs bar is open for drinks and meal orders in the lead up to the meeting.</span></p><p><span>Dinner from around 6.00pm,</span><span>The meeting starts around 7.30pm<br></span><span>Members, visitors, friends, relatives all welcome!</span></p><p><span>Eastlake Football Club<br><span><span>3 Oxley St, Griffith Canberra ACT 2603</span></span></span></p><p><span><span><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-ed77559d-29de4060.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-ed77559d-b2a3a822.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-ed77559d-b2a3a822.webp" loading="lazy" alt="" title=""></picture><br></span></span></span></p><p><br></p><p><br></p><p><br></p>', 'East Lake Football Club - Griffith', '2019-04-02T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-ed77559d-b2a3a822.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3330814, 'BMW Club Araluen run', '<p>Before the weather cools down, a short run down to Araluen for lunch. A chance to blow the cobwebs out of the car and enjoy the company of our fellow BMW fans. Route info tho follow but mark it in your calendars. Please indicate by commenting how many people will be in your group so that we can give the pub numbers for catering.. Hope to see you all there.</p><p><br></p>', 'Start at Sutton Bakery', '2019-04-12T23:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3321568, 'BMW Clubs Australia Nationals 2019', '<p><span><span>Proudly hosted by BMW Car Club of Victoria and supported by BMW Clubs Australia as well as Liquimoly and Shannons..</span></span><br><br><span><span>Always a great weekend, the Nationals come around once Every 2 Years.</span></span><br><br><span><span>The Last Nationals were is Brisbane and set the bar high for all Nationals to follow.It was a fabulous event but the distance made it hard for most to attend. Only Don and I represented the Canberra Club. Melbourne is a lot more achievable for the long weekend and we will be going in the opposite direction to most Melbournites.</span></span><br><br><span><span>It includes a weekend of runs, motorsport, museums meals and even a night at the iconic Luna Park for the young and young at heart.</span></span><br><br><span><span>So guys, lets get a group of us to make the pilgrimage</span></span><br><br><span><span>You can view the full Itinerary and register for the event on the official website here:</span></span><a href="http://www.bmwcanationals.com.au/index.php?fbclid=IwAR0jtkvl4Tz3IYXVYWVL7Ta7io0BvxVIrP44g88BpLgLWlHbvx67Ml_sISo" target="_blank" rel="noopener"><span><span>http://</span><span>www.bmwcanationals.com.au/</span>index.php</span></a><br></p>', 'Melbourne, Victoria, Australia', '2019-04-18T23:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3330815, 'BMW Car Club Canberra Presentation day', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p><em><span>R<strong>egretfully we wish to advise that we are fully booked at Grazing, but members are more than welcome to come for the run out to Wee Jasper and a Coffee Break/light meal at Roses (on the left, bottom end of the main street in Yass).</strong></span></em></p><p><em><span><strong>We will advise if there are any cancellations that may come available.</strong></span></em></p><p>We will be holding our Presentation day at Grazing Gundaroo commencing at 1.30PM and not 12.00PM as previously advertised to accommodate the restaurant.</p><p>For those who wish to cruise and takee left the gentle run out that is one option or for those who want work up an appetite before lunch. Meet at Mt Stromlo Observatory car park at 10.30 for a re run of the Wee Jasper, Yass (late morning tea at Roses) and onto Gundaroo via the Barton Highway and Murrumbateman Road.</p><p>Bring some extra cash with you for raffles and bidding for some very special items and enjoy the wonderful food and hospitality of Grazing. Please ensure that you put this date into your calendar for a very special day regardless of the road that you take. We will be requesting numbers after Easter for catering purposes and please advise of any special dietary requirements.</p><p>There will be a choice of 2 or 3 meal courses and the Club with contribute to member meal costs. All drinks will be at the members expense. The meals will be a choice of two per course and will be an alternate arrangement. Please RSVP ASAP so that we can advise the restaurant for catering requirements. Special dietary meal/s will be arranged on the day.</p><p>It would be great to see a big roll up to celebrate the past year and provide an update on the activities planned for the coming year. Updates of the event will be also posted on facebook.</p>', 'Grazing Gundaroo', '2019-05-05T03:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3330816, 'High Country Club Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture><br></p><p>The High Country Run is currently blanketed in snow and the forecast is for more on Sunday!</p><p>Sooo, We will drive down to Cooma and Tony Nassar has said he can provide a banquet at his restaurant Roses, serving a feast of Lebanese cuisine.</p><p>Anyone who came to the Snowie run last year can attest to the quality and variety that Tony and his staff puts on. Cost per head is $30 and I can guarantee you will not go away hungry.</p><p>After the meal, he has kindly offered to open the club rooms of the Cooma Monaro Historic Vehicle Club and he will provide coffee and desert. If you have not been to the club rooms, it is a former indoor tennis centre that they bought some years ago and members store their vehicles there so it takes on the atmosphere of a classic car museum. A great collection of cars to view.</p><p>So why not come on a shorter drive and enjoy the company of other club members and the Hospitality of our friends in Cooma.</p><p>As before we will meet at Chisholm shops but at the later time of 10am for coffee and then drive down to Cooma.</p><p>BMW Car Club Canberra</p><p><br></p>', 'Cooma', '2019-06-02T00:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3367369, 'Obsession Car Detailing Information & Demonstration Evening', '<p>We are glad to offer our first workshop of the year being held at Obsession Car Detailing in Mitchell. Some of our members have used Saad services and can personally testify the result/s.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/733803608-7cbe2d44-13c386bf.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/733803608-7cbe2d44-bb1d8339.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/733803608-7cbe2d44-bb1d8339.webp" loading="lazy" alt="" title=""></picture></p><p>Information will include the do''s and don''ts of caring of exterior and interiors of your pride and joy. Information will include colour restoration through to high end finishes using Opti Coat ceramic products.</p><p>Please join us for a information packed evening with light refreshments and enjoy Saad excellent coffee making skills.</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><p><br></p>', 'Unit 8, 15 Darling Street Mitchell', '2019-07-03T09:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/733803608-7cbe2d44-bb1d8339.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3453122, 'Christmas in July', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture><br></p><p><span>This year’s Christmas in July will be held on the 27/28 July 19.</span></p><p><span>Come along and enjoy the back roads to Bathurst, visit the Car Museum and laps of the iconic track at 60KMPH.</span></p><p><span>For our Canberra members, meet on Saturday at the Federal Highway ACT/NSW Boarder Truck Stop at 8.00 AM for a 8.30 AM sharp departure. Route to Bathurst to follow but will include plenty of bends and scenery. Morning tea will be at Goulburn and lunch at Bathurst, aiming to be at the Bathurst Museum by 1.30 pm. Anticipate 1.5 hrs at the museum and then a few laps plus a group photo on the iconic Bathurst Circuit.</span></p><p><span>Depart 4.00 pm to Orange where we will be staying at the<strong><span>Best Western Ambassador Orange, 174 Bathurst Road Orange.</span></strong></span></p><p><strong><span>Please contact Renee directly on 02 63937500</span></strong><span>and make reference to the<strong><span>BMW Car Club Canberra</span></strong>to obtain the special rate. Please be advised that you need to book quickly as I have indicated 15 varying rooms at this stage.</span></p><p><span>Rates are:</span></p><p><span>Family (4 people) $295.00 = $73.75 per person including hot breakfast, (please be advise only 2 family rooms were available as at 13/6/19).</span></p><p><span>Executive Room (2 people) $195.00 = $97.50 per person including hot breakfast.</span></p><p><span>Deluxe Room (2 people) $175.00 = $87.50 per person including hot breakfast.</span></p><p><span>Single Room (1 person) $160 including hot breakfast.</span></p><p><span>Dinner at the same venue is 2 coarse $39 and 3 coarse $49, kids are $15.00.</span></p><p><span>The menu is extensive (refer attached)and special dietary requirements can be catered for. Please advise at the time of booking accommodation.</span></p><p><span>We would like to do Chris Cringle again as it was a success last year (Craig had a ball!). Present is not to exceed $20.00 and everyone to be included.</span></p><p><span>Sundays drive will be via Trunkey Creek including a visit to the Abercrombie Caves for a self tour. Lunch will be en route to Canberra at Crookwell.</span></p><p><span>I hope you can join us and this event and will be extended to our fellow NSW and Victorian Clubs.</span></p><p><span><strong>Please do not leave your booking too late to avoid disappointment.</strong></span></p><p><span>BMW Car Club of Canberra</span></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/set-menu-2-or-3-course-a23b5f5b-b64975db.docx" target="_blank">Set Menu 2 or 3 course.docx</a><br></p>', 'ACT/NSW Boarder Truck Stop Federal Highway Depart 8.30 Sharp', '2019-07-26T22:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3367408, 'Museum of Australia Historic Cars', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p>Wakefield Park will be the place to view the Museum of Australia collection of Historic Cars. Many of you have seen these cars as static displays only, but come and hear them in anger as they lap the Wakefield Park circuit.</p><p>Of particular note is the Brabham BT23.</p><p>Meet at the Truck Bay on the Federal Highway for a 9.00AM departure.</p><p><strong><em><span>Sign up to Shannons Club and receive a 50% on the entry to the event.</span></em></strong></p><p><strong><em><span>You do not need to hold a policy with Shannons to be eligible to join.</span></em></strong></p><p><strong><em><span>$9.01 for Shannons Club Members and twice that if you are not. You can join the Shannons Club at Shannons.com.au and get tickets here:</span></em></strong></p><p><strong><em><span>https://www.eventbrite.com.au/e/a-chequered-past-vehicles-from-the-national-museum-of-australia-tickets-58403719096?aff=ebdssbdestsearch#tickets</span></em></strong></p><p><strong><em><span>We should stress that this is the first and possibly the last time that these vehicles will be on a race track.</span></em></strong></p><p><br></p>', 'Wakefield Park', '2019-08-16T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3502173, 'Motorsport Skidpan Driver Training', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p><span>We are happy to announce our 1st Motor sport event for the year on the Skidpan at Sutton Park on Sunday 8th of September 2019.</span></p><p><span><span>Ever wondered how that car you saw facing the wrong way on the freeway ended up that way?</span><br></span></p><p><span><span><span>Ever wondered</span></span><span>how you lost control of your own car? Why the car did what it did? Why it went sideways?</span></span></p><p><span><span>Well wonder no more…</span><span>.</span></span></p><p><span>Come along to our Club Skidpan Day on Sunday 8<span>th</span>September 2019 and learn all the answers to those questions.</span></p><p><span>Sutton Road Driver Training Centre, Sutton Road, Majura - 10am to 3pm - $120 per driver.</span></p><p><span>This day will be a day of fun and learning. Once you learn the why, and then the how, you can then do!</span></p><ul><li><span>First we will teach you how to put the car into a skid</span></li><li><span>Then we will teach you how to recover half way through the skid – so you know to get out of one</span></li><li><span>Then we will teach you how not to get into that skid in the first place!</span></li></ul><p><span>This day is a great learning event for the whole driving family. Mum, Dad and Teen Drivers alike. Skills that can be used on the everyday road driving, can save lives.</span></p><p><span>So bring your wife, bring your husband, bring your teenage driving kids. Everyone will benefit.</span></p><p><span>Also note – it’s a great precursor to going to the track. Knowing how to manage your car purely by throttle control is a huge advantage.</span></p><p><span><span>Please bring your own snacks, drinks, lunch and if you have a radio bring that along to cheer your friends or pass on bragging rights!</span><br></span></p>', 'Sutton Park', '2019-09-08T00:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3502065, 'German Auto Day (GAD) Dinner', '<picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwcc-logo2-cb0ea0b7-b5bac606.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwcc-logo2-cb0ea0b7-b96477e4.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwcc-logo2-cb0ea0b7-b96477e4.webp" loading="lazy" alt="" title=""></picture><p>The German Auto Day (GAD) Dinner is being held on the 21st September 2019 at the Harmonie German Club commencing at 6.30 PM for a 7.00 PM Dinner.</p><p>Come along to like minded people with the passion of German machinery.</p><p>Costs are $50.00 per person (Full Buffet Dinner) for Club Members and $60.00 per person (Full Buffet Dinner) for Non- Club Members.</p><p>Prices exclude drinks.</p><p>Final numbers and payment are due 2 weeks prior to the event - Friday 6th of September 2019.</p><p>Payment arrangements to follow.</p><p><br></p><p><br></p>', 'Harmonie German Club', '2019-09-21T08:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwcc-logo2-cb0ea0b7-b96477e4.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3558464, 'German Auto Day - Show n Shine entry', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gad2018-9c1cea76-bfe835c7.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gad2018-9c1cea76-b0985d42.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gad2018-9c1cea76-b0985d42.webp" loading="lazy" alt="" title=""></picture>To avoid delays and to assist us in running the day please ensure you register your vehicle/s in advance.</p><p>Our preferred payment method is online at checkout. Alternatively you can transfer to the club account:</p><p><span>Bendigo Bank:<br>Name:</span><span>BMW Car Club Act Inc<br>BSB: 633-000<br>Account: 125 925 727 – reference GAD2019 and your name</span></p><p><span>There will be facitilities on the day for late registrations.</span></p><h3>Registration</h3><ul><li>Guest Entry – $20.00 Entry fee for all non-members.NOTE: Members of official BMW Clubs in Australia are considered club members and are entitled to Member pricing.If you are a member of another club (e.g. BMW DC NSW, BMW DCM, BMW CCV) please ensure you advise us on the day.</li><li>Member Entry – $15.00 Member''s only priceNOTE: Membership will be confirmed prior to judging commences on the day. If you are a member of another official BMW Club please advise us on the day.</li></ul>', 'Canberra Greyhound Racing Club, 235 Narrabundah Lane, Symonston ACT', '2019-09-21T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gad2018-9c1cea76-b0985d42.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3558510, 'We need you! Volunteers for GAD', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/judge-9763cd79-b3ecb720.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/judge-9763cd79-e17aea8b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/judge-9763cd79-e17aea8b.webp" loading="lazy" alt="" title=""></picture></p><p>Calling all judges!</p><p>Do you have an eye for detail? Have you judged before and keen for more action?! Never done it but keen to help out your favourite club?!</p><p>Well..... We want you!</p><p>Please register your interest to let us know, it saves us chasing volunteers on the day :)</p><p>And for your troubles, the President will shout you a coffee! There may even be some cake too.....</p><h3>Registration</h3><ul><li>Judge Registering to assist with judging cars at German Auto Day 2019</li></ul>', 'Canberra Greyhound Racing Club, 235 Narrabundah Lane, Symonston ACT', '2019-09-22T00:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/judge-9763cd79-e17aea8b.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3440587, 'German Auto Day', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture><br></p><p>Come join us for the German Auto Day 2019 and see some great machinery from all German makes - From Auto Union to Volkswagen and everything between!</p><p>There will be plenty for the whole family - Food, coffee and activities to keep the kids entertained.</p><p>General Admission: Gold coin donation, all proceeds going to SoldierOn.</p><p><br></p>', 'Canberra Greyhound Racing Club, 235 Narrabundah Lane, Symonston ACT', '2019-09-22T00:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3502233, 'Wakefield Park Tuesday 15th October 2019', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p>We have approached Gulsons of Canberra and have been invited to participate in their Wakefield Park track day on the 15th of October 2019.</p><p>The track days are a great opportunity to experience the potential of your car and hone your driving skills. It is also a great opportunity to show your family and friends how awesome your cars is, as passengers are allowed in your vehicle (with the exception of the timed session at lunch time). Any passengers need to sign a waiver and wear appropriate clothing/helmet.</p><p>To avoid any disappointment, we ask you to confirm your place now by completing the forms (trackday@gulson.com.au) and finalising payment. The number of cars is limited to ensure everyone has a great day.</p><p>Entry Fees (Payed prior to the 8th of October)</p><p>Standard $250 inclusive of lunch,</p><p>Additional driver $200 inclusive of lunch,</p><p>Guest $30 please advise prior to the 8th of October,</p><p>Late Entry $280 after the 8th of October or on the day.</p><p>Booking confirmation and payment can be made by bank deposit credit card or PayPal or call in, have a coffee and pay at the dealership. (Please send an email to markw12958@gmail.com and I will send an email with the links).</p><p>You will need either a current CAMS licence or Wakefield Park licence which is available online at: https://aasa.com.au/licences/day-licence-application/</p><p>Indemnity form needs to be completed on the day or again I can forward the links to complete in advance.</p><p>You must have a helmet and also need ankle to wrist clothing coverage.</p><p>Advance driving instructors are available for some basic tuition and in car instruction.</p><p>If you have any questions please direct them to Tania Bennett from Gulson Canberra on 6162 0997 or 0418 622 233.</p><p>Get in early to avoid disappointment.</p>', 'Wakefield Park', '2019-10-14T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3536198, 'Girder Fork Rally, Junior Development Program, Cooma Motorfest & Hill Climb Weekend', '<p>Cooma Car Club events this Spring are:</p><p>Girder Fork Rally Friday 18 October to Sunday 20th October 2019, based from the Cooma Car Club Clubhouse, 11 Bolaro Street Cooma.</p><p>Junior Development Motorkhana, 9.30AM Sunday 27th October 2019 at The Long House, Polo Flat Road, Cooma.</p><p>Mount Gladstone Hill Climb Weekend, Saturday 23rd to Sunday 24th of November 2019 at Mount Gladstone Road (4km west of Cooma).</p><p>Details and entry forms www.coomacarclub.com.au or contact Ian Hampton on 0400 528 115.</p><p><br></p>', 'Various locations in and around Cooma, refer to web site', '2019-10-17T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3602195, 'MG Car Club of Canberra Motorkhana', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p>The MG Car Club are holding a motorkhana this Sunday (sorry for the late notice) at Sutton Transport Industries Skill Centre. You are required to have a current CAMS licence and proof of a member of a CAMS affiliate Club which we are.</p><p>Cost is $50.00 and will comprise of 6 patterns set up with 2 runs on each pattern.</p><p>There were limited numbers to that prescribed in the CAMS Permit.</p><p>Please email me directly (markw12958@gmail.com) if you are interested and I forward on the details.</p><p>Or alternatively contact Kent Brown 0412 558 029 or email kjpbrown@bigpond.com from the MG Club of Canberra.</p><p>My apologies sorry for the late notice.</p>', 'Sutton Transport Industries Skill Centre', '2019-10-26T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3502054, 'Cooma 20th Anniversary Motorfest', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p>The Cooma 20th Anniversary Motorfest is being held at the Cooma Showgrounds on Saturday the 2nd of Nov 2019.</p><p>Displays of Street Machines, Hot Rods, Vintage, Classic Cars, Muscle Cars, Military Vehicles, Motor Bikes, Tractors, Rocker Cover Racing, Trucks &amp; Stationary Engines.</p><p>Trade Displays, Live Music, Swap Meet &amp; Kids Entertainment.</p><p>Entry forms and more information can be down loaded from: www.coomacarclub.com.au</p><p>For those that wish to attend, meeting location and departure time will be published closer to the event.</p><p><br></p><p><br></p><p><br></p>', 'Cooma Showgrounds', '2019-11-01T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3568438, 'Nissan Sports Car Club Wakefield 9/11/2019 Track Day', '<p><span>The BMWCCC has been contacted by the Nissan Sports Car Club (NSCC) who are holding a track day on Saturday the 9th of November 2019 at Wakefield.</span></p><p><span>The day is run under cams and includes fire, rescue and timing.</span></p><p><span>It will run in groups of no more than 10 cars and max 65 entries.</span></p><p><span>The groups will be decided based on previous PB times on Natsoft.</span></p><p><span>NSCC are a cams affiliated club with a wide variety of cars running times from around the 60sec mark through to the 90sec mark and aim to ensure entrants gain the most amount of track time possible in the safest possible way.</span></p><p><span>Costs are $220 for the day not including Cams or Wakefield licence. Standard safety equipment is required for a L2S day (details on the website).</span></p><p><span>Entrants can enter and pay online by following the link below. Enquires to be directed to Matt Robinson on 0408 022 992.</span></p><p><a href="http://www.nissansportscarclub.org/" target="_blank" rel="noopener"><span><span>http://www.nissansportscarclub.org/</span></span></a></p><p><span>We will continue to include these opportunities as they are brought to our attention on our web site and advise accordingly for our track focused members.</span></p><p><span>BMW Car Club Canberra</span></p><p><br></p>', 'Wakefield Race Track', '2019-11-08T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3579806, 'M Town Roadshow Rolfe BMW', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture><br></p><p>The M Town Roadshow is on at Rolfe BMW on Saturday the 9th of November 2019.</p><p>Come and admire, dream and test drive the amazing M cars on display. Book a drive in your dream M car via the Rolfe Classic link below.</p><p>https://www.rolfeclassicbmw.com.au/openday</p><p>Some of our members M Cars will also will be there to enjoy.</p><p>Do not miss out on this special day and support our major club sponsor.</p><p>Subject to interest we may do a short run after the event.</p><p>Look forward to seeing you there!</p><p><br></p>', 'Rolfe BMW 2 Botany Street Phillip', '2019-11-08T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3599914, 'Ford vs Ferrari Movie Night', '<span><blockquote><blockquote><blockquote><p><span><span><span><span><span><span>This looks like a great film and we have been invited to tag along with the Fiat and Alfa Car Clubs.</span></span></span></span></span></span></p><p><br></p><p><span><span><span><span><span><span>We arrive from 8pm, and kick the film off from 8.30pm - give those who''d like to a chance to get a meal or drink or both in Manuka beforehand. Sounds like a plan. It''s not a fund-raiser - just a chance for car lovers to come out and see a great film about cars and car racers. (For the very few of you who haven''t seen the trailer, I''ve included the link below.)</span></span></span></span></span></span></p><p><br></p><p><br></p></blockquote></blockquote></blockquote></span><p>https://www.youtube.com/watch?v=zyYgDtY2AMY<br></p><p><br></p>', 'Manuka Cinema', '2019-11-14T09:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3502059, 'BMW Car Club Canberra Annual General Meeting (AGM)', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p>The BMW Car Club Canberra will be holding the Annual General Meeting (AGM) on Tuesday 19th of November 2019. All Committee positions will be vacated and nominations forms will be made available closer to the event.</p><p>Please consider becoming an active committee member of the Club, or come along and provide your thoughts of what you would like to get out of the club, do or contribute in the direction of the club.</p><p>Finger food and non-alcoholic drinks will be provided from 6.30 PM and the AGM will commence at 7.30 PM sharp.</p><p>We look forward to your attendance.</p><p><br></p>', 'Eastlake Football Club Upstairs Function Room', '2019-11-19T08:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3556904, 'Multi Club Weekend | Canberra, Melbourne and NSW Clubs', '<p><strong><br></strong></p><h3><span>A 3-club drive organised by BMW Drivers Club Melbourne, BMW Drivers Club NSW and BMW Car Club Canberra.</span></h3><p><span>All financial members of these 3 clubs - along with family members and significant others are welcome.</span></p><p><span>The event will be based in beautiful Merimbula on the NSW South Coast where all the clubs will meet on Friday night. We have arranged to meet at the Merimbula RSL at 6pm for a meet and greet and we will enjoy a 2 course meal, which we can<span>pre-order</span>, the cost is $30 per head. Please download and return your order form with your registration to<a href="mailto:events@bmwdcm.com.au"><span>events@bmwdcm.com.au</span></a>.</span></p><p><span>On Saturday we’ll head up into the mountains on scenic, sweeping roads. Then there’s a choice of a brilliant, twisty driving road or a cruise on more sweeping roads, both ending at Marlo on the Snowy River for lunch. The afternoon includes sweeping roads through the mountains before a final run up the coast back to Merimbula.</span></p><p><span>Sunday will take us on enjoyable roads through the Bega Valley, before heading up the mountains to Cooma for lunch. From there, the clubs will head to their home cities. For the Melbourne club, this means twisty roads across the mountains to an overnight stop in Corryong, followed by an excellent drive along the Murray River to Albury and back to Melbourne (everyone is welcome to join part or all of this, of course).</span></p><h2><span><span>Itinerary Outline</span></span></h2><h4><span><strong>ACCOMMODATION FOR FRIDAY AND SATURDAY:</strong></span></h4><p><span>We will be staying at the<a href="https://www.sapphirevalleycaravanpark.com.au/" target="_blank" rel="noopener"><span>Sapphire Valley Caravan Park</span></a>on both Friday and Saturday night. Motel Style cabins start from $153 for 2 night (no breakfast included).</span></p><p><span>You can book by calling (02) 6495 1746 to get the discounted rates, ensure you use<strong>BMW Club</strong>as your reference at the time of booking.</span></p><h4><span>ACCOMMODATION FOR SUNDAY:</span></h4><p><span>For those travelling back to Melbourne on the extended drive, we are staying at the<a href="https://www.mountain-view.com.au/" target="_blank" rel="noopener"><span>Mountain View Motel</span></a>Corryong. Motel rooms start at $90 per night, including a continental breakfast.</span></p><p><span>Please book by calling (02) 6076 1766 to get the discounted rates, ensure you use<strong>BMW Club</strong>as your reference at the time of booking.</span></p><h4><span>PLEASE MAKE YOUR ROOM BOOKINGS EARLY, AS THIS IS A BUSY TIME OF THE YEAR AND ROOMS WILL SELL OUT QUICKLY</span></h4><h4><span>DRIVE INSTRUCTIONS TO FOLLOW.</span></h4><table><tbody><tr><td><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-club-logo-approved-c47384a2-71a5e732.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-club-logo-approved-c47384a2-f304f506.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-club-logo-approved-c47384a2-f304f506.webp" loading="lazy" alt=""></picture></td><td><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-logo-31796ef6-d360cd47.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-logo-31796ef6-ee80be0d.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-logo-31796ef6-ee80be0d.webp" loading="lazy" alt=""></picture></td><td><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/nsw-logo-90f9fc55-5ed1e0a1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/nsw-logo-90f9fc55-b1494bd8.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/nsw-logo-90f9fc55-b1494bd8.webp" loading="lazy" alt=""></picture></td></tr></tbody></table><br><p><br></p><h3>Registration</h3><ul><li>Attendee</li></ul>', 'Merimbula - South East NSW & Eastern Victoria', '2019-11-28T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3502201, 'Cherry Festival Young', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p>Join us as we attend the Cherry Festival in Young. The trip will include enjoyable roads, good food and the consumption of cherries.</p><p>Please reserve this day in your diaries as this will be the last drive day for 2019.</p><p>Meeting location is the wayside stop at the ACT/NSW Boarder on the Barton Highway at 8.30AM for a 9.00AM departure.</p><p>Morning tea at Boorowa then onto Young for lunch and exploring the Cherry Festival. Depart Young via Wallendbeen, afternoon tea at Bowning and return to Canberra.</p><p><br></p>', 'Young', '2019-12-06T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3647893, 'The LAST Shannon''s Canberra Cars, Bikes n Coffee Event', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p>Come and join fellow Car n Bike enthusiasts for the<strong>"Last Shannon''s Canberra Cars, Bikes n Coffee"</strong>at Exhibition Park.</p><p>This event will attract a large audience of motor car lovers and we would like to have a strong presence of our vehicles.</p><p>Shannon''s will be collecting money to donate to the RFS and victims of the dreadful fires in NSW/QLD . Bring some extra cash to donate and the Club will also be donating.</p><p>Please arrive at 8.00 for a 8.30 park up.</p><p>We look forward to seeing many of you in the last ever Shannon''s Canberra Cars, Bikes n Coffee event.</p>', 'Exhibition Park in Canberra', '2019-12-07T21:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3502248, 'Merry Christmas BMW Car Club Canberra BBQ Dinner', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p>The final get together for the year with friends and cars. A special prize will be given to the person/couple or family that can theme Friday the 13th and Christmas together, get your thinking caps on!</p><p>Please bring your own food and drinks, that way you will not be disappointed. We will try and secure a BBQ for those that wish to consume burnt offerings.</p><p>We hope you can join us to celebrate the year it was, the festive season and Friday the 13th..........</p><p>Meet at Winston Park on Pescott Lane, Weston Park. Subject to available parking and BBQ will determine final location.</p><p><br></p>', 'Winston Park, Pescott Lane Weston Park', '2019-12-13T05:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3425438, 'Bathurst 12 Hour', '<br>After missing the 2019 event we are more eager than ever to get back to the mountain!<br>For those that have attended in previous years it has been a great weekend each and every time, revhead relaxation at it''s finest.<br>Come join us for what will be a weekend filled with Motorsport, a glorious soundtrack and great company. As always, we will endeavour to set up the marquees at the end of Conrod straight. Our friends in other BMW Clubs will undoubtedly have their spots set up as well.<br>If you are interested in coming along please email Luke: president@bmwclubact.asn.au<br>More information will be added once plans firm up.<h3>Registration</h3><ul><li>attending</li><li>Camping attending and camping with other club members.</li></ul>', 'Bathurst, NSW', '2020-01-30T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3732147, 'BMW Nationals planning', 'Afternoon tea and drinks will be provided.<h3>Registration</h3><ul><li>Attendee</li></ul>', 'Wanniassa', '2020-02-09T03:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3716453, 'Batemans Bay Fish & Chip Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/batemans-bay-497258e7-de7be5a9.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/batemans-bay-497258e7-cf1c9857.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/batemans-bay-497258e7-cf1c9857.webp" loading="lazy" alt="" title=""></picture></p><p>Lets help our friends in the immediate region impacted by the fires by spending money in their business.</p><p>Turn up hungry and thirsty as we will stop in Braidwood for morning tea and continue onto Batemans Bay for fish and chips or food of your choosing.</p><p>Spend a few hours at the Bay, wet a rod, cruise the shops, have a swim, hire a Jetski or what ever takes your fancy.</p><p>Come with a few shekels to spend in the community to help with recovery from the terrible fires.</p><p>Propose to be back in Canberra by no later than 5.00PM.</p><p></p><p><br></p>', 'ACT/NSW Boarder Truck Stop Federal Highway', '2020-02-15T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/batemans-bay-497258e7-cf1c9857.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3712606, 'MG Car Club Canberra Multi-club Motorkhana', '<p>Due the inclement weather last Sunday the MG Club of Canberra Motorkhana at Sutton was postponed and is being held tomorrow Sunday the 16th March 2020.</p><p>Please email directly and I can provide the details or contact Kent Brown at kjpbrown@bigpond.com. Numbers are limited so do not leave you registration with the MG Club to late.</p><p>One of members has assisted with the event and highly recommends coming along to at least watch and possibly be involved in future events.</p><p><br></p><p><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Vehicle Manoeuvring Area (VMA) Transport Industries Skills Centre Sutton', '2020-02-15T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3712224, 'Shannons Wheels 2020', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-9462-e9220103-27f881cb.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-9462-e9220103-972cc6f1.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-9462-e9220103-972cc6f1.webp" loading="lazy" alt=""></picture><br></p><p>The<strong>Shannons Wheels 2020</strong>is being held at the Queanbeyan Showground on<strong>Sunday the 1st March 10am - 3pm.</strong>General public entry is a<strong>Gold Coin</strong>donation with proceeds to Cancer Council ACT.</p><p>Last year we had a terrific representation of BMW vehicles. Lets rally together and beat last years vehicle display.</p><p>For those who will be displaying their vehicle/s, entry is via the Main Gate on<strong>Glebe Avenue (Opens at 7.00)</strong>and we are required to have all vehicles on display no later than<strong>9.30AM</strong>. Display vehicles are also to contribute with a Gold Coin and can not leave any earlier than<strong>1.00PM</strong>due to restrictions of public liability insurance cover.</p><p>We are required to provide the number of vehicles that will be displayed by the<strong>14th Feb</strong>and ask that you<strong>only register your attendance if you are displaying your vehicle/s.</strong></p><p>We will have Club Merchandise for sale on the day and look forward to seeing you all.</p><p><br></p>', 'Queanbeyan Showgrounds', '2020-02-29T20:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-9462-e9220103-972cc6f1.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3713775, 'Phillip Island Festival of Speed 2020', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/classic-cars-113-7bc20361-0edf7ce0.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/classic-cars-113-7bc20361-317c2063.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/classic-cars-113-7bc20361-317c2063.webp" loading="lazy" alt="" title=""></picture><br></p><p>Injunction with our friends from BMW Drivers Club of Melbourne joins us to experience Historical cars, Formula 5000, International GT, F1 , Appendix J, Group C and many more at the iconic Phillip Island race track.</p><p>Watch the races, walk in the paddocks and pits, talk with the drivers and crews, marvel up close at the machinery, smell the fumes and enjoy motor racing history up close and personal.</p><p>We will ensure that the route to Phillip Island will not be all highway and will include some windy bits (subject to the recent fires).</p><p>Travel dates consist of two options being:</p><ol><li>Depart Friday 6th, attend racing on the 7th and drive back on the 8th, or</li><li>Depart on the Sat 7th, attend racing on the 8th and drive home on 9th (Canberra Day Holiday).</li></ol><p>Depending on interest will determine travel dates. Accommodation options are available including camping at the track.</p><p>Look forward to a strong attendance.</p><p><br></p>', 'Phillips Island Race Circuit', '2020-03-06T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/classic-cars-113-7bc20361-317c2063.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3770254, 'BMW Nationals Planning', 'Come join the team!<br>The BMW Car Club Canberra is hosting the 2021 BMW Clubs Australia Nationals, let''s show the rest of Australia how awesome the Nation''s Capital really is!<br><br>As you know, many hands make light work. We''d love to have your support and assistance if you''re willing and able.<br><br>The meeting will be held fortnightly, if you can make it we''d love to have you, if you can''t make all meetings that''s fine too.<h3>Registration</h3><ul><li>Attendee</li></ul>', 'Eastlake Football Club', '2020-03-10T07:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3764337, 'Bermagui Fish and Chip Run', '<p><br></p><p><br></p><p>Unfortunately due to the lack of interest, we have decided to cancel this weekends event (15th March 20), with a view in hold the event later in the year.</p><p>Our apologies for any inconvenience.</p><p><br></p><p>Regards</p><p>BMW Car Club of Canberra</p><p><br></p>', 'Calwell Carpark off Webber Crescent near Caltex Service Station', '2020-03-14T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3741196, 'BMSC Netier National Capital Rally', '<span><span>The Brindabella Motor Sports Club</span></span>would like to invite us to participate in the BMSC Netier National Capital Rally. I understand that members from our club have provided assistance previously.<p>If you can assist, please contact Cheryl directly (details at the bottom of this event notice).</p><p>The dates are Friday 20th March to Sunday 22nd March. The event will be conducted in Kowen Forest on Saturday afternoon and around Tidbinbilla Forests on Sunday.</p><p><span>They need the following volunteers:</span></p><p><span><strong>Friday</strong></span></p><p><span>10 Road Closures - AM</span></p><p><span>10 Road Closures - PM</span></p><p><span><strong>Saturday</strong></span></p><p><span>8 Stage Officials</span></p><p><span>11 Road Closures</span></p><p><span>10 Spectator Marshalls</span></p><p><span>4 Gate Marshalls</span></p><p><span><strong>Sunday</strong><br></span></p><p><span>40 Stage officials</span></p><p><span>24 Road Closures</span></p><p><span>30 Spectator Marshalls</span></p><p><span>If you are able to help us out please respond by return email with the</span></p><p><span>following information:</span></p><table><tbody><tr><td><span>Mobile Number<br></span></td><td><br></td></tr><tr><td><span>Address<br>Incl state/postcode<br></span></td><td><br></td></tr><tr><td><span>Emergency Contact<br>(someone not at the rally)<br></span></td><td><br></td></tr><tr><td><span>Emergency contact phone<br></span></td><td><br></td></tr><tr><td><span>Any known Allergies<br></span></td><td><br></td></tr><tr><td><span>Shirt Size<br></span></td><td><br></td></tr><tr><td><span>Availability<br></span></td><td><br></td></tr><tr><td><span>Preferred Role ie<br>Stage official<br>Road Closure<br>Spectator Marshall<br></span></td><td><br></td></tr></tbody></table><p><span>I look forward to seeing you then and for your information I have attached the 2020 Rally calendar.</span></p><p><span>Kind regards</span></p><p><span>Cheryl Holberton</span></p><p><span>Volunteers Co-ordinator</span></p><p><span>Brindabella Motor Sport Club</span></p><p><span>Canberra</span></p><p><span>0408 103 234</span></p><p><br></p>', 'Kowen and Tidbinbilla Forests', '2020-03-19T21:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3712306, 'BMW Car Club of Canberra Snowy Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-f7e721d1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-87eeaa5a.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-87eeaa5a.webp" loading="lazy" alt="" title=""></picture><br></p><p><span>Cancelled</span></p><p>Unfortunately due to ever increasing travel, restaurant restrictions and no doubt further tightening the Snowy Run for this weekend is cancelled for the time being. When we come out of this crisis, the Snowy Run will be one of the first events that will be held.</p><p>As per the Presidents recent email, please keep safe distances, wash your hands regularly, look after you and yours and spend time making your BMW''s shiner and ready for future events.</p><p><br></p><p><br></p><p><br></p>', 'Snowy Mountains Southern NSW', '2020-04-03T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-87eeaa5a.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3741226, 'BMW Club of Canberra Presentation Lunch', '<p></p><p><span>Cancelled</span></p><p><span>Due to COVID-19 the Presentation Lunch has been cancelled. When life returns to some form of normality we re schedule.</span></p><p><span><span>The 2020 Annual Lunch and Presentation afternoon will be held at (Venue to be confirmed). Social and Motorsport awards will be presented at this event.</span></span></p><p><span><span>It will be a day to remember including a run before hand for those interested (similar to last year to work up an appetite) and then celebrate all the winners of our Motorsport and Club awards. There will be raffles, silent auctions and other prizes to be won.</span></span></p><p><span><span>The Club will be contributing to the cost of meals and drinks are to purchased by attendees.</span></span></p><p><span><span>So join us for a fantastic lunch and afternoon.</span></span></p><p><span><span>PLEASE NOTE ANY DIETARY REQUIREMENTS IN ADVANCE.</span></span></p><p><span><strong>BMW Car Club of Canberra</strong></span></p>', 'TBC', '2020-05-16T23:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3856161, 'Coming out of COVID-19 Drive', '<p><span>NOTE change in Departure location</span></p><p>Hello everyone, as we slowly drag ourselves out of the COVID-19 hibernation going into winter? I trust you have survived and ready for a run!</p><p>As the restrictions have somewhat been lifted, it provides the opportunity to undertake a short local run and what better than a leisurely drive to Wee Jasper return. I must admit I have only travel north on the road and never south, so why not!</p><p>Bring a thermos and morning tea to share on our arrival at Wee Jasper and maybe arrange a takeaway lunch back in Canberra on our return.</p><p>The run takes about 1hr 15 each way, so aim to be back in Canberra by 12.30.</p><p>Will try and get some trips plan in the coming weeks.</p><p><strong><span>Please, NOTE change of meeting point being McDonalds Molongo (New) on Kirpatrick Street off Cotter Rd. The RSPCA ACT is on the same road. This gives you all a chance to get a brew and something to eat before we leave at 9.00AM sharp.</span></strong></p><p>Look forward to see you all as it has been some time and please observe social distancing and appropriate hygiene.</p><p>Regards</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-807f0e46.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p>', 'McDonalds Molongo', '2020-06-06T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3918016, 'Canberra Five Peaks Cruise', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20180901-155226-dfdd69fc-da64f833.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20180901-155226-dfdd69fc-58a01d45.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20180901-155226-dfdd69fc-58a01d45.webp" loading="lazy" alt="" title=""></picture>As advertised on our Facebook page please come out and enjoy a cruise around the five Peaks of Canberra comprising of Mt Ansile, Red Hill, Arboretum, Mt Stromlo and Black Mountain Tower. Group/individual photos at each location is a must. Finishing off with lunch at the Botanical Gardens or similar (TBA due to COVID restrictions on catering).</p><p><span>We must stress that if you are not a current financial member of the Club you will be not covered by our insurance.</span>So those who are attending and or other members whose membership have expired (Only $50.00 for 12 months individual &amp; $60.00 Family) could you please pay the fee. Payment can be processed on line through our web page.</p><p>For those who are not current members please join the club and enjoy drives, social events, showing /admiring BMW''s and talking cars.</p><p>Web page: BMW Car Club Canberra</p><p>Look forward to seeing you on Sunday.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-8def9afb.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" loading="lazy" alt="" title=""></picture><br></p>', 'Defence Russell Car Park Lakeside', '2020-07-25T23:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20180901-155226-dfdd69fc-58a01d45.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3987489, 'Coffee & BMW''s', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/showandshine-e73007d5-d5096f7a.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/showandshine-e73007d5-4526622a.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/showandshine-e73007d5-4526622a.webp" loading="lazy" alt="" title=""></picture><br></p><p>Good morning/afternoon BMW Car Club of Canberra members!</p><p>With the relaxing of COVID-19 restrictions and diminishing hot spots, we will be filling your calendar with events during spring so stay tuned.</p><p>The first event is a meet and greet for coffee (and Tea) and admire your fellow members polished, modified, new acquisition or your steed with other like minded lovers of all things BMW .</p><p>We may arrange a cruise afterwards for those interested or some of you may wish to stay and have lunch.</p><p>Please ensure that you strictly adhere to COVID-19 requirements and in particular social distancing.</p><p>Please register your attendance so that we can advise the venue for seating and catering.</p><p>We look forward in seeing you soon.</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-8def9afb.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Coffee n Beans Red Hill', '2020-09-27T00:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/showandshine-e73007d5-4526622a.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3993103, 'Araluen Pub Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mg-2773-7c039072-17f06cf1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mg-2773-7c039072-0340c46f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mg-2773-7c039072-0340c46f.webp" loading="lazy" alt="" title=""></picture></p><p><span>Araluen Pub Run</span></p><p>Its time to sample pastries and coffee at The Baker at Sutton and then enjoy the country atmosphere, meals and refreshments hosted by Norm at the Araluen Pub.</p><p>Come and enjoy the spring blossom of the Araluen Valley and some twisty bits on route. We had a fabulous turn out last year and is a great little drive in our backyard.</p><p>We will be departing Sutton at 10.00AM sharp via Shingle Way, Bungendore, Tarago, Braidwood onto Araluen.</p><p>Please ensure your coffees and pastries are consumed prior to 10.00AM.</p><p>Registration and numbers are a must as we need to advise the Araluen Pub for catering.</p><p>On the way home some of you may choose to explore Braidwood or Bungendore.</p><p>To assist the Club and protect yourself please ensure that you are financial member/s. You can validate and pay your membership on the Web page.</p><p>As always COVID-19 requirements must be strictly adhered too and in particular social distancing.<br></p><p>We look forward in seeing you all soon.</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-8def9afb.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" loading="lazy" alt="" title=""></picture><br></p>', 'The Baker at Sutton', '2020-10-10T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mg-2773-7c039072-0340c46f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (3987505, 'BMW Car Club of Canberra Snowy Run Version 3.0', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-f7e721d1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-87eeaa5a.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-87eeaa5a.webp" loading="lazy" alt="" title=""></picture><br></p><p><span><span><strong>Note: Revised date, now 1 Nov due to major Rain Event this Weekend (25 Nov)</strong></span></span></p><p><br></p><p><span><span>The Snowy Run is on again!</span></span></p><p>We are pleased to announce the Snowy Run is back on the agenda.</p><p>We will be leaving the<strong>Calwell Shopping Centre Car Park at 8.30 AM Sharp!!!!</strong></p><p>The run will retrace in reverse, the 2018 M Muster Route and will include a variety of open and twisty bits. Route will be via Dalgety, Beloka, Jindabyne (Lunch), Rocky Plain, Cootralantra, Cooma and home. Lunch will be at the Wild Brumby distillery @ 1pm, afternoon tea/regrouping point will be at the Cooma Car Club.</p><p>Morning tea will be in Cooma and an opportunity for a quick splash for those people with high consumption.</p><p>To be covered by our event insurance you must be a current financial member or pay $10.00 on the day to become an associated member for the day.</p><p>We will have club merchandise available for purchase as well.</p><p>Estimated drive time is 4.5 hrs.<br></p><p>I hope you can join us for one of the more epic regional drives.</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-8def9afb.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><p><br></p>', 'Meet at Calwell Shopping Centre Car Park', '2020-10-31T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-87eeaa5a.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4000509, 'BMW Car Club Canberra Annual General Meeting 17th November 2020', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-3e0d2edc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp" loading="lazy" alt="" title=""></picture></p><p>The BMW Car Club Canberra will be holding the Annual General Meeting (AGM) on Tuesday 17th of November 2020 at Eastlakes Football Club. All Committee positions will be vacated and nominations forms are available on the web site or email: president@bmwclubact.asn.au</p><p>Please consider becoming an active committee member of the Club, or come along and provide your thoughts of what you would like to get out of the club and contribute in the direction of the club.</p><p>Please note that you must be a current financial member of the club to nominate or stand for a position on the committee.</p><p>Finger food and non-alcoholic drinks will be provided from 6.30 PM and the AGM will commence at 7.30 PM sharp.</p><p>We look forward to your attendance.</p><p><br></p>', 'Eastlake Football Club Upstairs Function Room', '2020-11-17T08:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-120-7c0a71ca-7c759432.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4151128, 'BMW Drivers Club NSW Supersprint Rounds 1-7', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-9254-7e5dd920-43a91197.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-9254-7e5dd920-bc954dab.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-9254-7e5dd920-bc954dab.webp" loading="lazy" alt="" title=""></picture></p><p><span>The BMW Drivers Club NSW have extended an invitation for our members to attend their Supersprint events. Some of our older members will already know about this arrangement and participate, but many of our recent members maybe unaware.</span></p><p><span>There is specific documentation, licence, vehicle and protective clothing/helmets etc required to participate and details are listed on the web site detailed below.</span></p><p><span>The Supersprints are being held on the 21/2/21, 18/4/2021, 8/5/2021, 20/6/2021, 3/7/2021, 21/8/2021 &amp; 12/9/2021.</span></p><p><span>View the details at<a href="https://www.bmwclubnsw.asn.au/events" target="_blank" rel="noopener"><span>https://www.bmwclubnsw.asn.au/events</span></a></span></p><p><span>Contact Bob Williams for more details at<a href="mailto:president@bmwclubnsw.asn.au"><span>motorsport@bmwclubnsw.asn.au</span></a>or phone 0418 284 323.</span></p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-8def9afb.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" loading="lazy" alt="" title=""></picture><br></p>', 'Round 1 SMSP', '2021-02-20T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-9254-7e5dd920-bc954dab.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4127497, 'Shannons Wheels 2021', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/210228-wheels2021-poster-cf218963-39766d4a.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/210228-wheels2021-poster-cf218963-a1d7fb1a.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/210228-wheels2021-poster-cf218963-a1d7fb1a.webp" loading="lazy" alt="" title=""></picture><br></p><p>The<strong>Shannons Wheels 2021</strong>is being held at the Queanbeyan Showground on<strong>Sunday the 28th February 10am - 1.30pm.</strong>General public entry is a<strong>Gold Coin</strong>donation with proceeds to Technology for Aging &amp; Disability ACT.</p><p>Last year we had a terrific representation of BMW vehicles. Lets rally together and beat last years vehicle display.</p><p>For those who will be displaying their vehicle/s, entry is via the Main Gate on<strong>Glebe Avenue (Opens at 7.00)</strong>and we are required to have all vehicles on display no later than<strong>9.30AM</strong>. Display vehicles are also to contribute with a Gold Coin and can not leave any earlier than<strong>1.00PM</strong>due to restrictions of public liability insurance cover.</p><p>We are required to provide the number of vehicles that will be displayed,<u><strong>please</strong><strong>only register your attendance if you are displaying your vehicle/s.</strong></u></p><p>We will have Club Merchandise for sale on the day and look forward to seeing you all.</p><p>Please ensure that COVID-19 requirements are strictly adhered too.</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-8def9afb.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p>', 'Queanbeyan Showgrounds', '2021-02-27T20:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/210228-wheels2021-poster-cf218963-a1d7fb1a.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4199244, 'Bowning, Boorowa, Crookwell & Gundaroo', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20210115-131041-2-4b4e1ec8-6ee174c9.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20210115-131041-2-4b4e1ec8-39fad29b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20210115-131041-2-4b4e1ec8-39fad29b.webp" loading="lazy" alt="" title=""></picture><br></p><p>Come and join us on a local run to the north of Canberra and enjoy a mix of roads, scenery and local hospitality. Morning tea at Boorowa and lunch at The Criterion Hotel (Middle Pub) in Crookwell.</p><p>Will investigate places of interest or other events that can be included during the journey.</p><p>Departing from Hall General Store at 8.30AM as the Barton Highway rest area is closed due to commencement of the duplication of the Barton Highway.</p><p>As always please observe COVID-19 requirements.</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-807f0e46.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><h3>Registration</h3><ul><li>Bowing, Boorowa, Crookwell &amp; Gundaroo</li></ul>', 'Hall General Store', '2021-03-20T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20210115-131041-2-4b4e1ec8-39fad29b.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4150960, 'MG Car Club of Canberra Motorkhana (4 Events)', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-6625-cropped-768x578-8f1f2de5-f10b5d77.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-6625-cropped-768x578-8f1f2de5-8aacd3ca.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-6625-cropped-768x578-8f1f2de5-8aacd3ca.webp" loading="lazy" alt="" title=""></picture></p><p>The MG Club of Canberra are holding four (4) Motorkhana days at the Sutton Driving Facility that we are invited to attend.</p><p>Motorkhana''s provide the ability for our younger drivers to commence their learning of driving and car control.</p><p>The Motorkhana''s are being held on 28/3/2021, 6/6/2021, 5/9/2021 &amp; 14/11/2021.</p><p>Register at<a href="https://mgcccanberra.org.au/?page_id=2528" target="_blank" rel="noopener">https://mgcccanberra.org.au/?page_id=2528</a>or for more details email Ken Brown at<a href="mailto:kjpbrown@bigpond.com">kjpbrown@bigpond.com</a></p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-8def9afb.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" loading="lazy" alt="" title=""></picture><br></p>', 'TISC Facility Sutton Park', '2021-03-27T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-6625-cropped-768x578-8f1f2de5-8aacd3ca.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4151056, 'BMW Drivers Club NSW Motorkhana Skid Pan (5 Events)', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/55576516-1233812590117950-6653630594703949824-o-0241f6e8-50dff51c.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/55576516-1233812590117950-6653630594703949824-o-0241f6e8-6da7116f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/55576516-1233812590117950-6653630594703949824-o-0241f6e8-6da7116f.webp" loading="lazy" alt="" title=""></picture></p><p>The BMW Drivers Club NSW have extended an invitation for our members to attend their Motorkhana events. Some of our older members will already know about this arrangement, but many of our recent members may not.</p><p>The attendance is limited and you need to be fast as registration is only open for a short duration before each event.</p><p>The Motorkhana''s are being held on the 28/3/2021, 30/5/2021, 25/7/2021, 25/9/2021 &amp; 31/10/2021.</p><p>View the details at<a href="https://www.bmwclubnsw.asn.au/events" target="_blank" rel="noopener">https://www.bmwclubnsw.asn.au/events</a></p><p>Contact Alex Wong for more details at<a href="mailto:president@bmwclubnsw.asn.au">president@bmwclubnsw.asn.au</a>or phone 0422 809 393.</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-8def9afb.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo-6f7fa431-0a623501.webp" loading="lazy" alt="" title=""></picture><br></p>', 'Sydney Motor Sport Park', '2021-03-27T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/55576516-1233812590117950-6653630594703949824-o-0241f6e8-6da7116f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4228051, 'Beemers & Bangers', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/westonpark-be9d215c-20634170.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/westonpark-be9d215c-24deeba9.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/westonpark-be9d215c-24deeba9.webp" loading="lazy" alt="" title=""></picture></p><p><span>The Banger''s are the sausages and not aimed at unloved or long term projects and Beemer''s is pretty self-explanatory.</span></p><p><span>Come and join us for a low key social event to gather with other likeminded car lovers and share a snag on the BBQ and a beer/wine. The club will provide salads and breads and a few burnt offerings, but ask that you generally cater for your own meat/drinks and other needs.</span></p><p><span>Club merchandise will be available for purchase on the day.</span></p><p><span>We hope you can join us and ask that appropriate COVID-19 requirements are observed.</span></p><p><br></p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-807f0e46.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" loading="lazy" alt="" title=""></picture><p><br></p><h3>Registration</h3><ul><li>Beemers &amp; Bangers</li></ul>', 'BBQ Area Weston Park Pescott Lane - Opposite Play Station', '2021-04-18T01:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/westonpark-be9d215c-24deeba9.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4231598, 'BMW M3/M4 G80 Information Evening (Take 2)', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-m3-g80-m-performance-parts-02-6e8c3f15-6dbedadf.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-m3-g80-m-performance-parts-02-6e8c3f15-a60ea781.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-m3-g80-m-performance-parts-02-6e8c3f15-a60ea781.webp" loading="lazy" alt="" title=""></picture></p><p><span>BMW M3/M4 Information Evening (Take 2)</span></p><p>We are pleased to inform you all that Rolfe BMW have kindly offered an evening to introduce members to the all new BMW M3/M4 (Hopefully the 2 cars do not sell as quickly). The evening will include catering and technical overview similar to the release of the M5 in 2019.</p><p>Please arrive at 5.30 for a 6.00 PM start and the evening will conclude at 7.30PM.</p><p>This is a BMW Car Club Canberra official event and you are required to register on the web site<a href="http://www.bmwclubact.asn.au/" target="_blank" rel="noopener">www.bmwclubact.asn.au</a>to attend.</p><p>If you would like to attend and not a member, join up on line to reserve your attendance to this event and other events held by the club and associated benefits.</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-807f0e46.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>BMW M3 G80 Dinner and Information Evening</li></ul>', 'Rolfe BMW Phillip', '2021-04-28T07:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-m3-g80-m-performance-parts-02-6e8c3f15-a60ea781.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4246102, 'Snowy High Country Overnight Run', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-f7e721d1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-87eeaa5a.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-87eeaa5a.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>This is an Official BMW Car Club event for members and our first overnight run for the year. This drive will be on some of the most scenic and greatest driving roads in Australia with great stopovers and photo opportunities.</span></p><p><span>Unfortunally we will not be able to complete the full loop due to road damage from the 2019/2020 fires, though what we have planned is epic!</span></p><p><span>Depart Calwell Shopping Centre Car Park at 8.00am sharp on Saturday, driving through Cooma, Dalgety, Beloka onto Jindabyne for morning tea. Depart Jindabyne via the Alpine Way to Khancoban Roadhouse via Crackenback and Thredbo.</span></p><p><span>Lunch at Khancoban then return back to Jindabyne for afternoon tea and onto Cooma either directly or for those that want more, via Rocky Plan, Cootralantra, Middlingbank, Coolringdon and Cooma.</span></p><p><span>For those that have not travelled this road please have a look on Google Maps to appreciate the windy bits after Thredbo.</span></p><p><span>We have arranged a special deal at the Altair Motel (192 Sharp Street) for $130.00 per single/twin share room. Ring Charlie on 6452 1211 to reserve your room. We will try and arrange breakfast there as well.</span></p><p><span>Cooma Car Club are holding their Surf to Summit Run on the same Saturday and we are arranging to join them for Dinner at the Cooma Car Club. Dinner including drinks will be in the $40-$50 00 per head region.</span></p><p><span>After breakfast we will leave Cooma for Tumut via Middlingbank, Adaminaby, Kosciuszko National Park, Talbingo (Morning Tea) and onto the Tumut River Brewing Company (1/5 Capper Street) for lunch. Afternoon tea will be at Jugiong before heading back to Canberra.</span></p><p><span>This is a drive not too be missed! We have reserved 8 double rooms but currently there are 18 rooms available. BOOK NOW!</span></p><p><span>Please register on line to assist with catering and accommodation requirements.</span></p><p><span>Not a member and want to join us, become a member on line at<a href="http://www.bmwclubact.asn.au/" target="_blank" rel="noopener">www.bmwclubact.asn.au</a></span></p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-807f0e46.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Snowy High Country Overnight Run</li></ul>', 'Calwell Shopping Centre Car Park', '2021-04-30T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc02608-f76b18cc-87eeaa5a.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4228171, 'Binalong, Boorowa, Crookwell, Gunning & Gundaroo Run (Take 2)', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20210115-131041-2-4b4e1ec8-6ee174c9.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20210115-131041-2-4b4e1ec8-39fad29b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20210115-131041-2-4b4e1ec8-39fad29b.webp" loading="lazy" alt="" title=""></picture></p><p><span>Come and join us on a second attempt (the first was cancelled due to heavy rains in the area) to the north of Canberra and enjoy a mix of roads, scenery and local hospitality. Morning tea at Binalong and lunch at The Criterion Hotel (Middle Pub) in Crookwell.</span></p><p><span>This is an "Official" BMW Car Club event and to attend you must be an financial member. You can join the club for as little as $50.00 per year</span><span>online at<a href="http://www.bmwclubact.asn.au/" target="_blank" rel="noopener">http://www.bmwclubact.asn.au</a></span></p><p><span>We will investigate places of interest or other events that can be included during the journey.</span></p><p><span>Departing from Hall General Store at 8.30AM as the Barton Highway rest area is closed due to commencement of the duplication of the Barton Highway.</span></p><p><span>As always please observe COVID-19 requirements.</span></p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-807f0e46.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Binalong, Boorowa, Crookwell, Gunning &amp; Gundaroo</li></ul>', 'Hall General Store', '2021-05-22T22:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20210115-131041-2-4b4e1ec8-39fad29b.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4228108, 'Motorsport Skidpan Driver Training & Fun', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1598869021090-b9cb3f6a-4b57c8d7.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1598869021090-b9cb3f6a-f9e2194f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1598869021090-b9cb3f6a-f9e2194f.webp" loading="lazy" alt="" title=""></picture></p><p><span>We are happy to announce our 1st Motor sport event for the year on the Skidpan at TISC Sutton Park on Sunday 6th of Jun21 between 9.00Am to 3.00PM.</span></p><p><span>Ever wondered how that car you saw facing the wrong way on the freeway ended up that way?</span></p><p><span>Ever wondered how you lost control of your own car? Why the car did what it did? Why it went sideways?</span></p><p><span>Well wonder no more….</span></p><p><span>Come along to our Club Skidpan Day and learn all the answers to those questions.</span></p><p><span>This day will be a day of fun and learning. Once you learn the why, and then the how, you can then do!</span></p><p><span>·</span><span>First we will teach you how to put the car into a skid</span></p><p><span>·</span><span>Then we will teach you how to recover half way through the skid – so you know to get out of one</span></p><p><span>·</span><span>Then we will teach you how not to get into that skid in the first place!</span></p><p><span>This day is a great learning event for the whole driving family. Mum, Dad and Teen drivers alike. Skills that can be used on the everyday road driving, can save lives.</span></p><p><span>This is a self-catering event so please bring your own snacks, drinks and lunch or drive to nearby Queanbeyan.</span></p><p><span>Based on 15 attendees cost will be $88.00 per driver, the more drivers the cheaper it gets!</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-807f0e46.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><br></p><h3>Registration</h3><ul><li>Motorsport Skidpan Driver Training &amp; Fun – $88.00</li></ul>', 'TISC Sutton Park', '2021-06-05T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1598869021090-b9cb3f6a-f9e2194f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4318472, 'BMWDCM Port Fairy Whale Watching', '<h1><span>PORT FAIRY - WHALE WATCHING - QUEENS BIRTHDAY LONG WEEKEND</span></h1><p>The BMW Driver Club Melbourne are hosting a whale watching event at Port Fairy and have extended the invitation to the members of the BMWCC.</p><p>Please follow the link below for more details and register.</p><p>https://bmwdcm.com.au/event-3775247</p><p><br></p><p><br></p><h3>Registration</h3><ul><li>BMWDCM Port Fairy Whale Watching BMWDCM are holding a drive to Port Fairy over the Queens Birthday weekend to Whale Watch. All details on the event including registration are via the provided event link.</li></ul>', '', '2021-06-11T23:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4228328, 'Beemers & Coffee', '<picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20200927-113227-090bde0e-03e23b9f.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20200927-113227-090bde0e-e6cc4a22.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20200927-113227-090bde0e-e6cc4a22.webp" loading="lazy" alt="" title=""></picture><p><span>Postponed until lockdown ceases, will be first event after announcement.</span></p><p><span>Enjoy a meet/greet for coffee/tea/savouries and admire your fellow members polished, modified, new acquisition or your steed with other likeminded lovers of all things BMW.</span></p><p><span>This event is open to all BMW enthusiasts and you do not need to be a member to attend.</span></p><p><span>Please ensure that you strictly adhere to COVID-19 requirements and in particular social distancing.</span></p><p><span>Club clothing will be available for purchase and happy to discuss the</span><span>benefits of becoming a member.</span></p><p><span><span>We look forward in seeing you soon.</span></span></p><p><span><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-807f0e46.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/club-logo2-5a33eb79-f2d40160.webp" loading="lazy" alt="" title=""></picture><br></span></span></p><h3>Registration</h3><ul><li>Beemers and Coffee</li></ul>', 'Coffee n Beans Red Hill Lookout', '2021-09-12T00:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20200927-113227-090bde0e-e6cc4a22.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4579295, 'BMWs & Coffee', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20200927-113227-090bde0e-03e23b9f.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20200927-113227-090bde0e-e6cc4a22.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20200927-113227-090bde0e-e6cc4a22.webp" loading="lazy" alt="" title=""></picture><br></p><p><span>BMWs &amp; Coffees</span></p><p><span>Enjoy a meet/greet for coffee/tea/savouries and admire your fellow members polished, modified, new acquisition or your steed with other likeminded lovers of all things BMW.</span></p><p><span>This event is open to all BMW enthusiasts and you do not need to be a member to attend.</span></p><p><span>Please ensure that you strictly adhere to COVID-19 requirements and in particular social distancing.</span></p><p><span>Club clothing will be available and happy to discuss the benefits of becoming a member. Also provide an update on the BMW Clubs Australia Nationals 11-14th March 2022 being held in Canberra</span></p><p><span>We look forward in seeing you soon.</span></p><p><br></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></span></p>', 'Red Hill Lookout Carpark', '2021-12-04T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/20200927-113227-090bde0e-e6cc4a22.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4683220, 'Cars & Coffee', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-8311d268-8fe21f87.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-8311d268-9883e248.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-8311d268-9883e248.webp" loading="lazy" alt="" title=""></picture><br></p><p><span><strong>Cars and Coffees (plus lots of sweet things)</strong></span></p><p><span>Enjoy a meet/greet for coffee/tea/savouries/cakes and more cakes and...... plus admire your fellow members polished, modified, new acquisition or your steed with other likeminded lovers of all things BMW.</span></p><p><span>This event is open to all BMW enthusiasts and you do not need to be a member to attend.</span></p><p><span>Please ensure that you strictly adhere to COVID-19 requirements and in particular social distancing.</span></p><p><span>Club clothing will be available and happy to discuss the benefits of becoming a member. Also provide an update on the BMW Clubs Australia Nationals 11-14th March 2022 being held in Canberra and how you can help.</span></p><p><span>We look forward in seeing you soon.</span></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Cars &amp; Coffees Sutton Bakery</li></ul>', 'Sutton Bakery', '2022-02-12T22:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-8311d268-9883e248.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4654532, 'Wheels 2022', '<p><br></p><p>The<strong>Shannons Wheels 2022</strong>is being held at the Queanbeyan Showground on<strong>Sunday the 6th March 10am - 1.30pm.</strong>General public entry is a<strong>Gold Coin</strong>donation with proceeds to Technology for Aging &amp; Disability ACT and The Stroke Foundation.</p><p>This year will mark 40 years that this event has been on and, a achievement in itself.</p><p>Last year we had a terrific representation of BMW vehicles. Lets again rally together and beat last years vehicle display.</p><p>For those who will be displaying their vehicle/s, entry is via the Main Gate on<strong>Glebe Avenue (Opens at 7.00)</strong>and we are required to have all vehicles on display no later than<strong>9.30AM</strong>. Display vehicles are also to contribute with a Gold Coin and can not leave any earlier than<strong>1.00PM</strong>due to restrictions of public liability insurance cover.</p><p>We are required to provide the number of vehicles that will be displayed,<strong><u>please</u></strong><u><strong>only register your attendance if you are displaying your vehicle/s.</strong></u></p><p>We will have Club Merchandise for sale on the day and look forward to seeing you all.</p><p>Note that the Nationals start on the following Friday and we will be asking for assistance to run some of the events.</p><p>Please ensure that COVID-19 requirements are strictly adhered too.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><p><br></p><p><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/220306-wheels-poster-d212c178-26f49d65.pdf" alt="" title="" loading="lazy"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/220306-wheels-poster-d212c178-26f49d65.pdf" alt="" title="" loading="lazy"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/220306-wheels-poster-d212c178-26f49d65.pdf" alt="" title="" loading="lazy"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/220306-wheels-poster-d212c178-26f49d65.pdf" alt="" title="" loading="lazy"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/220306-wheels-poster-d212c178-26f49d65.pdf" alt="" title="" loading="lazy"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/220306-wheels-poster-d212c178-26f49d65.pdf" alt="" title="" loading="lazy"><br></p><h3>Registration</h3><ul><li>Wheels 2022</li></ul>', 'Queanbeyan Showground', '2022-03-05T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4568164, 'BMWCA Nationals 2022', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-nationals-merch-edit-3-02-e8da9b62-ac5e0555.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-nationals-merch-edit-3-02-e8da9b62-887fef94.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-nationals-merch-edit-3-02-e8da9b62-887fef94.webp" loading="lazy" alt="" title=""></picture><br></p><p>Sorry, Registration for the BMWCA Nationals are now closed.</p><p>We start at 5.30PM Friday afternoon at Canberra BMW for welcoming speeches, catch-up with old/new friends, food/drinks compliments of Patrick and his team at Canberra BMW. Registration includes a bag with a few goodies unique to these Nationals.</p><p>Saturday starts with a run out to Wee Jasper then back to Concours, Show N Shine held at ANU University and Kambri Precinct. We will ensure those that wish to compete in the Show N Shine will be back in time to prepare their cars for the event. Those not competing will continue on a longer run but finishing at Concurs, Show N Shine venue by 12.00.</p><p>We have arranged discounts vouchers with local Waves Car Wash (In registration bags) for those preparing their cars prior to the Show N Shine or just wish to ensure those bugs on the drive to Canberra are removed.</p><p>Concurs, Show N Shine entry includes a Nationals Corflute drip tray with the image above. There are categories for all cars including "X" and the "Peoples Choice and, Concours" winners cars will be present inside the National Museum in the middle of Gala Dinner tables.</p><p>Saturday afternoon will include a drive out to the Cotter/Tharwa/Honeysuckle Creek. Saturday night is a free night so that everyone can catch up with interstate friends that have not been seen due to COVID restrictions.</p><p>Canberra "enlightenment" is back on this year so enjoy the major institution buildings cover in an array of colours and images.</p><p>Sunday starts off with a re run out to Wee Jasper then back to Sutton TISC Motorsport venue. Activities include Skidpan, Motorkhana, Dyno, and Boot sale (bring your excess parts). Lunch will be catered on site and the winners of the 2 x Amphicar raffles winners will depart for a drive on and around Lake Burley Griffin and coffees at Kingston foreshore.</p><p>Sunday nights Gala Dinner will be held in the foyer of the National Museum and will include guest speaker, presentation of trophy winners for events various awards including club attendance and, raffles items which all funds will go to our nominated charity Marymead.</p><p>Nationals shirts have arrived and, available for collection when registering on Friday and Saturday or on Sunday at the TISC MotorSport venue. Shirts can be ordered on line or purchased at registration on on Sunday at the Motorsports venue.</p><p>If you choose not to participate in any events, we require various helpers, drive leaders, general assistance. If you can spare some time or require further assistance please contact<strong>Mark Wilson on 0432 443 072</strong>or email:<a href="mailto:vicepresident@bmwclubcanberra.org.au"><span>vicepresident@bmwclubcanberra.org.au</span></a></p><p><br></p><h3>Registration</h3><ul><li>BMW Car Club Nationals</li></ul>', 'Canberra, ACT', '2022-03-11T06:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-nationals-merch-edit-3-02-e8da9b62-887fef94.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4654618, 'BMWCCC Annual General Meeting', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-ed77559d-29de4060.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-ed77559d-b2a3a822.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-ed77559d-b2a3a822.webp" loading="lazy" alt="" title=""></picture><br></p><p><strong><span>Annual General Meeting</span></strong></p><p><span>The BMW Car Club Canberra (BMWCCC) will be holding the Annual General Meeting (AGM) on Tuesday 26th of April 2022 at Eastlakes Football Club.</span></p><p><span>All Committee positions will be vacated and nominations forms are available by emailing:</span><a href="mailto:vicepresident@bmwclubcanberra.org.au"><span><span><span>president@bmwclubcanberra.org.au</span></span></span></a></p><p><span>Please consider becoming an active committee member of the Club, or come along and provide your thoughts of what you would like to get out of the club and contribute in the direction of the club.</span></p><p><span>Please note that you must be a current financial member of the club to nominate or stand for a position on the committee.</span></p><p><span>Finger food and non-alcoholic drinks will be provided from 6.30 PM and the AGM will commence at 7.30 PM sharp.</span></p><p><span>We look forward to your participation and attendance.</span></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><h3>Registration</h3><ul><li>BMWCCC AGM</li></ul>', 'Eastlakes Football Club Upstairs Meeting Room', '2022-04-26T08:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-ed77559d-b2a3a822.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4806725, 'BMW Club Community Management Team live from Munich', 'The next BCCM Live Session direct from BMW Classic in Munich will take place on Friday, April 29th at 8pm Australian Time.<br><br>These webcasts are very informative and only run for 30 minutes, so make some time in your calendar to log in.<br><br>If you want to join, please follow the link<a href="https://teams.microsoft.com/l/meetup-join/19%3ameeting_NThkOTQ1YTMtZmNhMi00N2IzLTlhYWEtOTg4Zjg0MjY5Y2Q5%40thread.v2/0?context=%7b%22Tid%22%3a%22ce849bab-cc1c-465b-b62e-18f07c9ac198%22%2c%22Oid%22%3a%228fdb57e6-8d4c-47a9-a634-b8de32e2965a%22%7d" target="_blank" rel="noopener">BCCM Live April 2022</a><br><br>Please include BMWCCC in your display name in the meeting.<br><br><br>How does it work?<br>We set up a MS Teams Meeting, please share the link above with your club members. In order to have the best possible quality, we ask you to deactivate your camera and also mute your microphones. There will be time for Q&amp;A during the meeting and you can send your questions via chat.<br><br>What will the sessions be about?<br>We want to keep it casual. It´s just us members of the BCCM that will give you updates on news from the network, the BMW Group and other things that are keeping us busy. There will be also a chance for you asking questions.<br><br>Further information about the content will follow prior to the session within a reminder.<br><br>We will keep it simple: No studio, spectacular camera angles or sophisticated graphics.<br>As the format is still pretty new, we kindly ask for your understanding in case something should not work 100%. There will be always room for improvement and we also want to learn in every session what is most relevant for you.<br><br>We are pretty sure, we will have a good time at both events.<br>Looking forward to a lot of you joining soon.<br><br>Mit freundlichen Grüßen,<br><br>BMW Club and Community Management Team<br><br><h3>Registration</h3><ul><li>BMW Club Community Management Team live from Munich</li></ul>', 'Your Home Computer', '2022-04-29T10:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4791978, 'BMW Cars & Coffee', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/billy-t-4aac759b-51046002.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/billy-t-4aac759b-0f8f5f9d.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/billy-t-4aac759b-0f8f5f9d.webp" loading="lazy" alt="" title=""></picture><br></p><p><span><strong>Cars and Coffee..... and all the delicious things!</strong></span></p><p><span>Enjoy a meet n greet for a beverage and bite to eat @ Billy T''s and admire your fellow enthusiasts polished, modified, new acquisition or daily steed with other like-minded lovers of all things BMW.</span></p><p><span>Billy T''s is a landmark cafe &amp; coffee shop within Dirty Jane''s warehouse - selling every form of treasure including furniture, garden wares, ornaments, paintings, collectibles, jewellery, vintage clothing and decorator items.</span></p><p><span>This event is open to all BMW enthusiasts, no need to be a member to attend.</span></p><p><span>Club clothing will be available and happy to discuss the benefits of becoming a member.</span></p><p><span><span>If there is enough interest on the day, there may be a drive to follow.</span></span></p><p><span>We look forward in seeing you soon!</span></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Cars &amp; Coffee Cars and Coffee entry</li></ul>', 'Billy T''s Canberra', '2022-05-01T00:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/billy-t-4aac759b-0f8f5f9d.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4683291, 'Liqui-Moly Bathurst 12 Hour 2022', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/12-hour-2022-5b62d175-3b88aded.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/12-hour-2022-5b62d175-6a8f07b2.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/12-hour-2022-5b62d175-6a8f07b2.webp" loading="lazy" alt="" title=""></picture></p><p>A group of members and friends are heading to the mountain to camp and attend this years Liqui-Moly 12 hour.</p><p>If you wish to attend please contact<strong>Luke Wise</strong>on<strong>0410 333 540</strong>to discuss camping and related arrangements.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><h3>Registration</h3><ul><li>Liqui Moly 12 Hour</li></ul>', 'Bathurst, NSW', '2022-05-12T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/12-hour-2022-5b62d175-6a8f07b2.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4791977, 'Wheels of Wamboin', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheelspanorama-8ca2a39c-d11d4781.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheelspanorama-8ca2a39c-b9f55a71.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheelspanorama-8ca2a39c-b9f55a71.webp" loading="lazy" alt="Community Groups ~ Wheels of Wamboin"></picture><br></span></p><p><span>The Wheels of Wamboin is on this year!</span></p><p><span><span>Wheels of Wamboin is a motoring enthusiasts'' event with vintage, classic and street machines - from Model ''T''s to Tesla and everything in between!</span></span></p><p><span><span><span><span>The Wamboin Home Produce Market will also be on (Wamboin Community Hall, next to Wamboin Oval ). There will be a v</span></span></span>ariety of stalls, including lots of fresh fruit &amp; vegies, healthy juices, coffee, egg &amp; bacon rolls, jewellery, cards, lollies, dried fruits &amp; nuts, cakes, sausage rolls, quiches, craft, knitting, preserves, and more!</span></p><p><span><span><span>So bring your German automotive marvel, have a great coffee and grab a egg and bacon roll. What more could you ask for to make a day of democracy worthwhile. It’s a great opportunity to take your Bimmer for a run and stretch some legs.</span></span><br></span></p><p>Venue: Wamboin Oval - off Norton Road (adjacent to the Wamboin Community Hall)</p><p>Time: 09:00am to 1:00pm</p><p>Entry: Gold coin donation - proceeds to Wamboin RFS</p><p>For those wanting to convoy in and park together, please meet at the Sutton Road Driver Training centre @ 8:30am sharp!</p><p>Please check the<a href="https://www.facebook.com/wheelsofwamboin/posts/910761312963903" target="_blank" rel="noopener"><span>Wheels of Wamboin</span>Facebook page</a>for updates.</p><h3>Registration</h3><ul><li>Wheels of Wamboin 2022</li></ul>', 'Wamboin Oval - - off Norton Road (adjacent to the Wamboin Community Hall)', '2022-05-20T22:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheelspanorama-8ca2a39c-b9f55a71.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4822397, 'Exclusive BMW K1600 Motorcycle Launch Event', '<p><br></p><p><span>Canberra BMW have kindly invited us (BMWCCC) to the Exclusive K1600 Motorcycle Launch Event on the 23rd of May 2022.</span></p><p><span>I know many of you are interested in or have BMW Motorcycles as well (like myself).</span></p><p><span>If you would like to attend,<strong>YOU MUST<span>get your tickets</span></strong>for the event via this link:<a href="https://www.eventbrite.com.au/e/the-bmw-k1600-exclusive-launch-event-tickets-330230677847" target="_blank" rel="noopener"><span>https://www.eventbrite.com.au/e/the-bmw-k1600-exclusive-launch-event-tickets-330230677847</span></a></span></p><p><span>If you don’t register via the Eventbrite link you will not be able to attend.</span></p><p><span><strong><span>Event Details below:<br><br></span></strong><span>As a valued customer of the Canberra BMW Group, you are invited to attend the new BMW K1600 Launch Event, and be among the first to preview this new motorbike.</span></span></p><p><span>This is an<strong>invite-only</strong>event. Should you wish to invite a plus one, please advise<a href="mailto:marketing@canberrabmw.com.au">marketing@canberrabmw.com.au</a>and we will put your plus one on our waiting list. They will be contacted directly and asked to RSVP asap, should a spot become available.</span></p><p><span>We expect tickets to this event will go quickly. Therefore, if you wish to join us, please ensure you secure yours as soon as possible.</span></p><p><strong><span>The Finer Details:</span></strong></p><p><span><span>✨</span><span>5:30pm - 7:30pm, Monday the 23rd of May 2022.</span></span></p><p><span><span>✨</span><span>Canberra BMW Motorrad, 2 Botany Street Phillip ACT 2606.</span></span></p><p><span><span>✨</span><span>Smart casual attire.</span></span></p><p><span><span>✨</span><span>Complimentary gourmet canapes catered by The Lazy Grazer. Please advise<a href="mailto:marketing@canberrabmw.com.au">marketing@canberrabmw.com.au</a>of any dietary requirements<strong>TODAY</strong>(apologies for the short notice) Monday the 9th of May, 2022.</span></span></p><p><span><span>✨</span><span>Complimentary refreshments provided (both alcoholic, and non-alcoholic options).</span></span></p><p><span>Regards,<br><br>Graham Ball<br>Vice President | BMW Car Club Canberra<br>Official BMW Club<br>0421 342 347<br><a href="/"><span>BMW Car Club Canberra</span></a></span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Canberra BMW Motorrad, 2 Botany Street Phillip ACT 2606', '2022-05-23T07:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4792054, 'Movie Night - Adrenalin: The BMW Touring Car Story', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/adrenalin-9ddd6a23-d4fc4f97.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/adrenalin-9ddd6a23-4c169aaa.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/adrenalin-9ddd6a23-4c169aaa.webp" loading="lazy" alt="" title=""></picture></p><p>What''s there to do on a cold winter''s night? Let''s get the blood pumping! There''s plenty of Adrenalin: The BMW Touring Car Story</p><p>Come join us for a night in at the club. A meal in the bistro, a beverage and head upstairs to watch a sensational movie that will keep you glued to the screen for the duration.</p><p>Covering BMW Touring Cars throughout its history, this movie will take us back through some of the most violent and exciting decades of ///Motorsport. From the early starts after the World War II ended, all the way to modern racers.</p><p>Register so we know how many people to expect, bring a friend. Movie snacks will be provided.</p>', 'Eastlake Football Club, Kingston', '2022-06-08T08:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/adrenalin-9ddd6a23-4c169aaa.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4824230, 'Sunday Morning Cotter Run', '<p><br></p><p>Come join us for a Windy roads Winter Run.<br><br>This will be one of a series of drives in which we explore some of the great backroads in the ACT. It will be a great opportunity to stretch the legs on your pride and joy.<br><br><strong>Attention Classic and Modified crew:</strong>We want to see you!</p><p>Starting at the Tharwa Country Store (08:30am for a 09:00am start), grab a hot beverage to warm up before we head off.</p><p>First stop: Honeysuckle Creek – The site that was once home to the Tracking Station assisting the first moon landing. We’ll convene here for a quick break.<br><br>On to Corin Dam to enjoy the beautiful scenery!<br><br>For the last leg, we’ll head to Cotter Bend (Cotter Reserve, where the playground and BBQ area is).</p><p>Be sure to bring some snacks, El Presidente will be making cake!</p><p><strong>Map of the drive:</strong><br><br><span>Note: Drive route subject to change in the event of road closures and the like</span>.</p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Tharwa Country Store', '2022-06-18T22:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4843180, 'Tech Night: Obsession Car Detailing', '<p><br></p><p>Join us for the first workshop event of the year: Obsession Car Detailing (OCD) in Mitchell.</p><p>OCD provides high end and professional detailing services for the most discerning automobile connoisseurs. Specialising in car paint correction, car ceramic coatings, and car paint protection film (PPF) for Canberra and the surrounding region.</p><p>The evening will include Information &amp; Demonstrations on the dos and don’ts of caring for your cars exterior and interiors, colour restoration through to high end finishes using Opti Coat ceramic products and paint protection film (PPF).</p><p>Some of our members have used Saad''s services and can personally testify to the amazing results.</p><p>It will be an information packed evening with pizza and soft drinks for everyone.</p><p>Please ensure you register for this event, it will help ensure there is sufficient catering. Looking forward to seeing you there.</p><h3>Registration</h3><ul><li>RSVP</li></ul>', '4/12 Cheney Place, Mitchell ACT', '2022-06-22T08:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4884718, 'BMW Cars & Coffee', '<p><br></p><p>Cars and Coffee.... and all the delicious things!</p><p>Enjoy a meet n greet for a delicious cup of coffee, something for breakfast or a sweet treat @ As Nature Intended and admire your fellow enthusiasts polished, modified, new acquisition or daily steed with other like-minded lovers of all things BMW.</p><p>As Nature Intended stock fresh organic fruit, vegetables, and lots of other products, including bulk foods and natural cleaning products. The café menu has something for everyone, with all dietary requirements catered for. They have plenty of delicious cakes, freshly baked breads and muffins made in house by their amazing chefs.</p><p>This event is open to all BMW enthusiasts, no need to be a member to attend.</p><p>Club clothing will be available and happy to discuss the benefits of becoming a financial member.<br><br>Please see the below map on where to park.</p><p><br></p><p>We look forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'As Nature Intended, 4/1 Dairy Road, Fyshwick', '2022-07-30T22:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4891465, 'BMW Drivers Club NSW Supersprint Rnd.5 at Wakefield Park', '<p><br></p><p><span>BMW Car Club Canberra members are invited to attend the<span>BMW Drivers Club NSW</span>Supersprint Rnd.5 at Wakefield Park.</span></p><p><span>After the pandemic holiday since 2019,<span>BMW Drivers Club NSW</span></span>are all looking forward to the opportunity to return to one of their favourite circuits, Wakefield Park. Registration for this Supersprint will open<a href="https://www.bmwclubnsw.asn.au/event-details?id=8f1dbf71-0d2e-ec11-813a-001e671e9ed8" target="_blank" rel="noopener">here</a>on 13 July or when the Supp. Regs. are approved. They would like to see a full field. Registration will be limited to members of BMWDCNSW and members of official BMW Clubs Australia clubs CQ, CGC, CCC, DCM, CCV, CCB, DCSA and CWA.</p><p><span>Registration Cost: Early, $270 13/07/2022 to 1/08/2022 Late: $310 2/08/2022 to 9/08/2022</span></p><p><span>All drivers need a Motorsport Australia Speed Licence and all cars will be required to pass the Motorsport Australia / BMWDCNSW Scrutiny Check.<br>Supp. Regs., Driver Information, Disclaimer and Scrutiny documentation will be published here on 13 July and early registration is recommended.</span></p><p><span>All competitors who enter BMW Drivers Club NSW Supersprints must submit a BMW Drivers Club NSW 2022 Annex-C form for their car. This is the requirement for the first event that you enter for the year and again whenever a Class-changing modification is completed on your car. If you have not submitted your Annex-C form for this year then download, complete it with your car’s base points and modification status so that your vehicle Class can be correctly established, sign it and email it to<a href="mailto:motorsport@bmwclubnsw.asn.au"><span>motorsport@bmwclubnsw.asn.au</span></a>.</span></p><ul><li><a href="https://www.wakefieldpark.com.au/" target="_blank" rel="noopener"><span>https://www.wakefieldpark.com.au</span></a></li><li><a href="https://www.bmwclubnsw.asn.au/Media/Default/Documents/Motorsport%202022/Annex%20C.pdf" target="_blank" rel="noopener"><span>Annex C</span></a></li><li><a href="https://www.bmwclubnsw.asn.au/Media/Default/Documents/Motorsport%202022/Scrutineer%20Compliance%20Form%20BMW%20Club%202022%20WP.pdf" target="_blank" rel="noopener"><span>Scrutineer Compliance Form BMW Club 2022 WP</span></a></li><li><a href="https://www.bmwclubnsw.asn.au/Media/Default/Documents/Motorsport%202022/2022%20Motorsport%20Australia%20Risk%20Warning,%20Disclaimer%20and%20Indemnity.pdfh" target="_blank" rel="noopener"><span>2022 Motorsport Australia Risk Warning, Disclaimer and Indemnity</span></a></li><li><a href="https://www.bmwclubnsw.asn.au/Media/Default/Documents/Motorsport%202022/Supplementary%20Regulations%20222-1308-04%20Approved-2.pdf" target="_blank" rel="noopener"><span>Supplementary Regulations 222-1308-04 Approved-2</span></a></li></ul><p><span>Please note - this event is organised by<span>BMW Drivers Club NSW</span>, any questions or concerns please email</span><a href="mailto:motorsport@bmwclubnsw.asn.au"><span>motorsport@bmwclubnsw.asn.au</span></a>or click<a href="https://www.bmwclubnsw.asn.au/event-details?id=8f1dbf71-0d2e-ec11-813a-001e671e9ed8" target="_blank" rel="noopener">here</a>.</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Wakefield Park Raceway, 4770 Braidwood Rd, Tirrannaville NSW 2580', '2022-08-12T21:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4928775, 'Sunday Morning Drive', '<p>What better way to kick off the day than with a coffee at Sutton bakery, followed by a leisurely drive through the countryside.</p><p>Everyone is welcome, please ensure you register prior to the event. Our destination will be the Harmonie German Club where the presentation lunch will be.</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'BP Watson', '2022-08-13T23:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4898111, '2022 Annual Presentation Lunch', '<p>After a hiatus from the schedule for the last two years, the 2022 Annual Presentation Lunch has returned! This year it will be held at The Harmonie German Club in Narrabundah. We’ll be having the “German Experience” menu. Some of the things we can expect on the table:</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/hgc-menu-5a7f45ba-44434885.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/hgc-menu-5a7f45ba-6c1d90d3.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/hgc-menu-5a7f45ba-6c1d90d3.webp" loading="lazy" alt="" title=""></picture><br></p><p>It will undoubtedly be a great day out. For those interested we will have a drive prior to lunch (details to come). The perpetual club trophies will be awarded as well. Lastly, there will be lucky door and raffle prizes, a silent auction and other prizes to be won.</p><p>Join us for a fantastic lunch and relaxing afternoon. We''re very much looking forward to catching up with everyone!</p><p>NOTE: If there are any dietary requirements, please let us know when registering.</p><p>Kind Regards<br>BMW Car Club Canberra<br>Official BMW Club<br><a href="/">BMW Car Club Canberra</a></p><h3>Registration</h3><ul><li>Presentation Lunch – $40.00 German Experience menu - 2 course, table share plates @ $40.00 pp</li></ul>', 'Harmonie German Club', '2022-08-14T02:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/hgc-menu-5a7f45ba-6c1d90d3.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4927282, 'Spring German Markets', '<p><br></p><p>Come and join us at the Spring German Markets!</p><p>The Spring German Market offers a variety of stalls offering German food such as homemade cakes, deli goods and groceries, as well as wine, beer, and schnapps.</p><p>They will have their much-loved sausage stall cooking fresh German sausages!</p><p>There will also be their beloved community stallholders with handmade crafts, other specialties and a free jumping castle for the kids and entertainment for all!</p><p>We will be having a Club display at the markets, to showcase some German automotive marvels… BMWs of course! ;)</p><p>We would love to give you the opportunity to display your BMW. So, if you are interested in having your car on display, please reply to this invite. There are only 5 spots available!</p><p><em>Note: Vehicles will not be allowed to travel within the grounds during the duration of the event to ensure public safety.</em></p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Harmonie German Club, 49 Jerrabomberra Avenue Narrabundah', '2022-09-10T23:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4975638, '*CALLING ALL CLASSIC CAR OWNERS* - Distinguished Gentleman’s Drive 2022', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-7d3d6ca1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-f309c37f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-f309c37f.webp" loading="lazy" alt=""></picture><br></p><p>We are proud to be hosting the Distinguished Gentleman’s Drive for the first time in Canberra!</p><p>An extremely well-run organisation, we’re looking forward to growing this event.</p><p>The Distinguished Gentleman''s Drive is a celebration of classic style. It is an on-road motoring event, uniting pre-80s designed classic cars, encouraging drivers and passengers around the world to dress dapper and drive for men''s health. All funds raised are invested in vital research and programs for prostate cancer and men''s mental health by Movember.</p><p>For those interested I would encourage you to come join us. As the first time in the region, we really would like to see some participation to raise awareness.</p><p>To join in the drive and be in the running for fundraising rewards, register at<a href="http://www.gentlemansdrive.com/" target="_blank" rel="noopener">www.gentlemansdrive.com</a>and select the Canberra event.</p><p>Important Information:</p><p>- The event is strictly for pre-80’s cars (built on or before December 31st, 1979)</p><p>- Registration are opened and required for participation</p><p>- Drive details are available on the website to registered drivers</p><p>- Local drive details are to remain confidential, do not share them</p><p>- Dress in-theme and visit our website for information prizes and rewards for 2022</p><p>- Follow the official Gentleman''s Drive pages on Facebook and Instagram (@gentlemansdrive)</p><p>If you have any questions, please don’t hesitate to ask.</p><p><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Canberra, Australia', '2022-09-23T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-f309c37f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4980059, 'Volunteers Needed: German Auto Day 2022 - 50 Years of ///M', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-244ab660.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp" loading="lazy" alt="" title=""></picture><br></p><h2><span>German Auto Day 2022 - 50 Years of ///M</span></h2><p><strong><span>When</span></strong><span>: 25 Sep 2022 8:30 AM, AEST<br><strong>Where</strong>: Queanbeyan Park, Campbell St, Queanbeyan</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-cc894e50.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><strong><em><span>German Auto Day 2022</span></em></strong><span>is set to be a sensational event, particularly for BMW. This will be something special, celebrating 50 years of BMW ///M.</span></p><p><span>It is also the day for the club’s annual<strong>Show ‘n Shine</strong>. We are looking for volunteers to help set up and to judge for the event. No experience in judging is strictly necessary but it will help, as will an eye for detail. For those without experience, guidance will be given before you start your duties. If you are entered in the Show ‘n Shine, you can still be a judge – except you will be allocated to a different category your car is entered.</span></p><p><span>Interested? Please contact Jon Havelock at</span><a href="mailto:editor@bmwclubcanberra.org.au"><span>editor</span></a><u><span>@bmwclubcanberra.org.au</span></u><span>if you can assist.</span></p><p><br></p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Help Set up Assistance setting up the grounds and lining cars up for display</li><li>Show n Shine Judge No experience necessary! This is a great opportunity to learn not only about judging, it will also provide you with insight as to what you can do to prepare your car for future events.</li><li>Traffic Management Help direct traffic and ensure cars entering are registered to attend</li></ul>', 'Queanbeyan Park, Queanbeyan', '2022-09-24T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4791763, 'German Auto Day 2022 - 50 Years of ///M', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-244ab660.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp" loading="lazy" alt="" title=""></picture><br></p><p>German Auto Day 2022 is set to be a sensational event, particularly for BMW. This will be something special, celebrating 50 years of BMW ///M.</p><p>In addition, there will be some great machinery from all German makes - Auto Union to Volkswagen and everything between!</p><p>We’ll also be holding the Clubs annual Show n Shine - Member Entry – $15.00 (entry fee goes towards trophies).</p><p>Please respond to the invitation so that adequate parking spaces can be secured.</p><p>There will be plenty to do and see for the whole family - Food, coffee and activities to keep the kids entertained.</p><p>This event is being hosted by the Mercedes car Club ACT.</p><p>General Admission: Gold coin donation</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>German Auto Day - Display Only</li><li>Show n Shine - Member Entry – $15.00 If you would like to enter your vehicle in the show n shine for judging please ensure you select this option</li></ul>', 'Queanbeyan Park, Queanbeyan', '2022-09-24T22:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4952905, '50 Years of ///M - Heritage Display at Canberra BMW', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-244ab660.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp" loading="lazy" alt="" title=""></picture><br></p><p>In celebration of 50 Years of ///M, our friends at Canberra BMW would like to have a weekly rolling display of the various generations of ///M cars.</p><p>As the local source of all things BMW, we would love to help Canberra BMW make this a reality. The month of October will be our time to shine!</p><p>We are hoping to provide two Motorsport cars each week for every week of October, with one special week featuring ALL SIX generations of the M3!</p><p>NOTE: This is a once in a lifetime opportunity to see not only one or two classic cars in the dealership but the entire family tree!</p><p>If you own a Motorsport BMW and would like to see your pride and joy on display, please register and let us know what your preferences are. I will be in contact with individual registrants in due course.</p><p>P.S. There will be a special surprise for those selected to be on display.</p><p>If you have any questions please don’t hesitate to ask.</p><p><br></p><p>Regards,<br>Luke Wise<br>President | BMW Car Club Canberra<br>Official BMW Club<br>0410 333 540<br><a href="/">BMW Car Club Canberra</a></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Group Display - Heritage Display at Canberra BMW Confirming availability for group display in addition to the individual display week</li><li>Single Week - Heritage Display at Canberra BMW Availability for display during a single week</li></ul>', 'Canberra BMW', '2022-09-30T22:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4929679, 'Club Cruise to the NSW Hillclimb Championship', '<p><br></p><p>Join us for a cruise out to Fairbairn Park Hillclimb Circuit (<a href="https://www.sdmahillclimb.com.au/" target="_blank" rel="noopener">SDMA Hillclimb</a>) to watch Round 9 of the NSW Hillclimb Championship.</p><p>Meet at Three Mills Bakery Fyshwick for a coffee and a bite to eat, we’ll then cruise on out to the Hillclimb Circuit.</p><p>Entry is off Sutton Road, next to the Driver Training Centre. There is spectator seating and food available.</p><p>Matthew Anderson (Regional Development Executive for Motorsport Australia (NSW/ACT &amp; QLD) will also be there to answer any questions you might have about how to get involved in motorsports, motorsport officiating,<span><span>motorsport</span></span><span><span>licences</span></span>etc.</p><p>So come along and check out some local motorsport!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Three Mills Bakery, 5 Leeton St Fyshwick', '2022-10-01T21:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4891480, 'Whale Watching Tour', '<p><br></p><p>Whale hello there!</p><p>We are seeking an expression of interest to see who would be interested in joining the Club for a whale watching tour on Sunday 9 October 2022 at Merimbula.</p><p><a href="https://www.sapphirecoastaladventures.com.au/" target="_blank" rel="noopener">Sapphire Coastal Adventures</a>run 2-hour morning tours at 9am out of Merimbula for $75 adults and $50 children. The boat can take about 40 people.</p><p>The Club will organise the tour booking with members to pay the Club directly.</p><p>You will need to organise your own accommodation for the Saturday night (8 October). There is currently accommodation at Sapphire Valley Caravan Park for that weekend.</p><p>We will also incorporate other things like a drive, dinner etc. on that weekend.</p><p>Please let us know by selecting either<em>Yes, Maybe or No</em>.</p><p>More information will be provided once we have a firm date and numbers.</p><p>It’s sure to be a whale of a time!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Merimbula NSW', '2022-10-07T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4988776, 'Bimmers in the Bay', '<p><br></p><p>Join us, along with the Volkswagen Club, for a Fish &amp; Chip run to Batemans Bay.</p><p>7:30am meetup in front of Old Parliament House, 8:00am departure to cruise the Kings Highway to the Coast. We’ll be stopping in at Nelligen Pub at 10:00am to meet anyone from the South Coast who wish to join us, before continuing to Corrigans Beach for lunch and the Rotary Markets (weather permitting).</p><p>Reminder: with the recent amount of rain, there are a lot of potholes on the roads. So please be on the lookout!</p><p>The Volkswagen Club will be collecting donations for Camp Quality.</p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Meetup in front of Old Parliament House', '2022-10-15T20:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5006774, 'Midweek Catch-Up', '<p><br></p><p>Join us for a causal midweek get-together at the The ''G'' Spot, Gungahlin.</p><p>Enjoy a bite to eat and admire your fellow enthusiasts polished, modified, new acquisition or daily steed with other like-minded lovers of all things BMW!</p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/menu-ad2bbd08-1d30fc06.pdf" target="_blank" rel="noopener">The ''G'' Spot Menu</a></p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'The ''G'' Spot, Gungahlin Lakes Golf Club Carpark', '2022-11-02T07:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4871898, 'Cooma Motorfest 2022', '<p><br></p><p>Join us for Motorfest 2022 which is set to be a sensational event.</p><p>Every two years, the Cooma Car Club hosts the regions'' largest festival of motoring - Motorfest.</p><p>Over 400 cars, trucks and motorbikes are displayed. Together with corporate displays and entertainment, the event takes on a carnival atmosphere where the public can admire the contribution to motoring history that members of the Cooma Car Club have collected, restored, and maintained. The event attracts over 4,000 visitors!</p><p>The Cooma Car Club has decided to waive the registration fees for this year''s Motorfest - that''s right, all vehicles can be entered for FREE! No charge to display your vehicle and be in the running for a share of the trophies. There is just a $5 per person general entry fee.</p><p>If you wish to display your car, you<u>MUST</u>register via<a href="https://www.coomacarclub.com.au/event-4624824/Registration" target="_blank" rel="noopener">Cooma Car Club - Motorfest 2022</a></p><p>For those wanting to convoy and park together, please meet at Calwell Shopping Centre Car Park, we’ll departing @ 7:00am sharp!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Cooma Showground', '2022-11-04T21:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5009136, '2022 Annual General Meeting (AGM)', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-cf086f7e-d0c9d715.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-cf086f7e-4ac7257b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-cf086f7e-4ac7257b.webp" loading="lazy" alt="EASTLAKE FOOTBALL CLUB, Canberra - Restaurant Reviews, Photos &amp; Phone Number - Tripadvisor"></picture><br></p><p>I am pleased to advise that the 2022 Annual General Meeting (AGM) of the BMW Car Club Canberra will be held immediately following the Extraordinary General Meeting which starts at<strong>7:30 pm on Tuesday 15 November 2022 in the MacDonald Room</strong>at the Eastlakes Football Club, 3 Oxley Street in Kingston.</p><p>The agenda for the AGM will be:</p><ul><li>Confirmation of the minutes of the previous 2021 AGM (held April 2022)</li><li>President’s Report</li><li>Financial Report</li><li>Election of Committee (as per section 8 of the Constitution of the BMW Car Club Canberra)</li><li>General Business</li></ul><p>During the AGM, an election will take place to appoint the President and Committee for the 2022-2023 year. All current financial members are encouraged to nominate for committee positions which are listed below.</p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/bmw-car-club-canberra-committee-roles-and-responsibilities-9a1a783c-3c10822f.pdf" target="_blank">BMW CAR CLUB CANBERRA - Committee Roles and Responsibilities</a><br></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/nomination-form-bmw-car-club-canberra-tuesday-15-november-2022-47ec65ab-9c35b6ff.docx" target="_blank">Committee Nomination form BMW CAR CLUB CANBERRA - Tuesday 15 November 2022</a></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/postal-voting-form-bmw-car-club-canberra-a9ad4b84-11e7b3f3.docx" target="_blank">Postal voting form BMW CAR CLUB CANBERRA</a></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/proxy-form-bmw-car-club-canberra-9a6a5d5c-43f9943e.docx" target="_blank">Proxy form BMW CAR CLUB CANBERRA</a><br></p><p>Only financial members as at Tuesday 15 November 2022 are eligible to vote. If you are unable to attend the AGM, you may choose to nominate a proxy to vote on your behalf, submit a nomination or send a postal vote, however these must be lodged with the Secretary by emailing<a href="mailto:secretary@bmwclubcanberra.org.au">secretary@bmwclubcanberra.org.au</a>.</p><p>I hope you can attend the AGM and look forward to your continued support and involvement in the activities of the BMW Car Club Canberra.</p><p>Regards</p><p>Lorna Kunz<br>Secretary – BMW Car Club Canberra</p><p><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Eastlakes Football Club, 3 Oxley Street Kingston', '2022-11-15T08:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-cf086f7e-4ac7257b.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4995711, 'BMW Cars & Coffee', '<p><strong><br></strong></p><p><strong><span>Cars and Coffee.... and all the delicious things!</span></strong></p><p><span>Enjoy a meet n greet for a beverage and bite to eat @ Billy T''s and admire your fellow enthusiasts polished, modified, new acquisition or daily steed with other like-minded lovers of all things BMW.</span></p><p><span>Billy T''s is a landmark cafe &amp; coffee shop within Dirty Jane''s warehouse - selling every form of treasure including furniture, garden wares, ornaments, paintings, collectibles, jewellery, vintage clothing, and decorator items.</span></p><p><span>This event is open to all BMW enthusiasts, no need to be a member to attend.</span></p><p><span>Club clothing will be available and happy to discuss the benefits of becoming a member.</span></p><p><span>If there is enough interest on the day, there may be a drive to follow.</span></p><p><span>We look forward in seeing you soon!</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Billy T''s Canberra', '2022-11-19T22:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5020276, '2022 Christmas Party - Final Event Of The Year', '<p><br></p><p><span>Join us at the Ginseng Chinese Restaurant at the Hellenic Club, Woden, for our final event of the year on Saturday 17 December at 6.30pm. Come and enjoy a lovely meal, relax, and chat with other members and end 2022 in a great way!</span></p><p><span>We are offering a Banquet menu. The cost will be<strong>$40 per adult</strong>and<strong>$20 per child (5–12 years)</strong>.</span></p><p><span>For the children who may prefer something else to eat, Ginseng offer<strong>Chicken bites and chips $10</strong>and<strong>Fried fish and chips $10</strong>—note this is for children (5–12 years).</span></p><p><strong><span>Banquet Menu</span></strong></p><ul><li><span>Ginseng Favourite entree platter—Spring roll, Dim Sim and fried seafood dumpling</span></li><li><span>5 spiced crispy chicken</span></li><li><span>Pepper beef tenderloin steak</span></li><li><span>Lemon chicken</span></li><li><span>Sweet and sour pork</span></li><li><span>Fish fillet with Asian greens, ginger, and shallots - GF</span></li><li><span>Poached mixed vegetables with sesame, peanut, and soy sauce</span></li><li><span>Steamed rice</span></li></ul><p><span>If you are Gluten free please choose an entrée, a couple of the dishes and steamed rice from the below Gluten free menu options and send an email with your choices to Yvonne (<span><span>treasurer@bmwclubcanberra.org.au)</span></span>and she will send this through at the time of confirmation.</span></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/ginseng-gluten-free-menu-6fdb3b8c-5d928883.pdf" target="_blank">Gluten Free Menu</a><br></p><p><strong><span>Important Note—</span><span>If you have paid and can''t make it, please let us know before the 14<span>th</span>December when we confirm numbers and we can refund your money. After 14 December if you don''t attend then you forfeit your payment as the Club will be asked to pay for those who attend and also those who don''t show on the night.</span></strong></p><p><span>Lastly, if you would like confirmation that your payment has been received, please contact Yvonne Wise, our Treasurer by emailing her at</span><a href="mailto:treasurer@bmwclubcanberra.org.au"><span><span>treasurer@bmwclubcanberra.org.au</span></span></a><span>or call her on 0428 488 053 and she will be happy to confirm for you.</span></p><span>Looking forward to seeing you there!</span><h3>Registration</h3><ul><li>Banquet Menu - Adult – $40.00 Ginseng Favourite entree platter—Spring roll, Dim Sim and fried seafood dumpling5 spiced crispy chickenPepper beef tenderloin steakLemon chickenSweet and sour porkFish fillet with Asian greens, ginger, and shallots - GFPoached mixed vegetables with sesame, peanut, and soy sauceSteamed rice</li><li>Banquet Menu - Child (5–12 years) – $20.00 Ginseng Favourite entree platter—Spring roll, Dim Sim and fried seafood dumpling5 spiced crispy chickenPepper beef tenderloin steakLemon chickenSweet and sour porkFish fillet with Asian greens, ginger, and shallots - GFPoached mixed vegetables with sesame, peanut, and soy sauceSteamed rice</li><li>Children''s Menu (5–12 years) – $10.00 For the children who may prefer something else to eat, Ginseng offer Chicken bites and chips $10 and Fried fish and chips $10.</li></ul>', 'Ginseng Chinese Restaurant, Hellenic Club Woden', '2022-12-17T07:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5071096, 'Afternoon Drive and Picnic', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/18256837442-9190cf7f22-b-b2552ade-9b698249.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/18256837442-9190cf7f22-b-b2552ade-b63d5727.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/18256837442-9190cf7f22-b-b2552ade-b63d5727.webp" loading="lazy" alt="Arboretum | The National Arboretum in Canberra. Sunset was l… | Flickr"></picture><br></p><p><span>Join us for our first event for 2023!</span><span>A relaxing scenic drive, exploring some of Canberra''s spectacular landscape and mountainous peaks.</span></p><p>Starting off with Red Hill then onto Mount Ainslie ending up at the National Arboretum where we will gather for a picnic to watch the crimson colours of the setting sun.</p><p>Bring a chair, a bottle of your favourite beverage and something to eat, a gourmet hamper or your favourite summer foods - what a way to end the week!</p><p><strong>Meeting Place: Carpark behind Hyatt Hotel (near the fitness centre).</strong></p><p><strong>Time: 5pm for a 5:30 Departure.</strong></p><p>Please drink responsibly.</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Carpark behind Hyatt Hotel (near the fitness centre)', '2023-01-20T06:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/18256837442-9190cf7f22-b-b2552ade-b63d5727.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5076712, 'Go-Kart Racing', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/p90174512-24th-february-2015-bmw-fibt-bob-skeleton-world-championships-2-c3e2ec99-08fb904b.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/p90174512-24th-february-2015-bmw-fibt-bob-skeleton-world-championships-2-c3e2ec99-f11e4b5a.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/p90174512-24th-february-2015-bmw-fibt-bob-skeleton-world-championships-2-c3e2ec99-f11e4b5a.webp" loading="lazy" alt="BMW Kart Challenge: Bob stars including Holcomb, Friedrich and Melbardis burn rubber as World Championship opens with a bang."></picture><br></p><p>Come and join us for the first of many go-karting sessions planned for the year!</p><p>Power Kart Raceway is Canberra''s ultimate go-karting experience, featuring world class electric go-karts on an F1 style indoor circuit. Come and race against fellow members or come along and cheer them on. This will also be a great warm-up for our upcoming track day at pheasant wood and it’s an excellent opportunity for the youngsters to gain experience behind the wheel and help them in developing essential skills for driving.</p><p>Details:</p><ul><li>7:00-9:00pm $80 (plus $10 for annual license) for 2 hours of unlimited racing!</li><li>Please arrive by 6:30 for sign-in</li><li>Children 12 &amp; 148cm also welcome</li></ul><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Power Kart Raceway', '2023-02-01T07:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/p90174512-24th-february-2015-bmw-fibt-bob-skeleton-world-championships-2-c3e2ec99-f11e4b5a.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5027140, 'Bathurst 12 Hour 2023 Run – Drive to Motorsport Mecca', '<p><br></p><p><span>Join us for a casual drive,</span><span><span>as we make the</span>annual<span>pilgrimage to the ‘Mountain’</span>. T<span>he LIQUI-MOLY Bathurst 12 Hour 2023 (Australia’s International Endurance Race)</span>is<span>on Sunday 5 February.</span></span></p><p><span>Due to a lack of interest in camping for the weekend, we have decided to do a day trip instead.</span></p><p><span>The race will return to embracing a fully professional outright class at the top of the field, with teams featuring all-pro driving line-ups to be welcomed for the first time since 2020.</span></p><p><span>Away from the racing on track, see the latest road cars from the world’s premium manufacturers ranging from high powered performance vehicles to the latest in EV technology up close</span><span>,<span>all in one place.</span></span></p><p><span>Unique and classic cars will be on display, entertainment and food offerings add to the motoring festival feel, the LIQUI MOLY Bathurst 12 Hour delivers an unforgettable experience!</span></p><p><span><strong>Please see the below details for the drive.</strong></span></p><p><span><strong>Meet at 7am for a 7:30 departure @ The Baker at Sutton, 1 Victoria St, Sutton NSW 2620</strong></span></p><p><span><strong>Stopping in at Crookwell for a pit stop, then heading onto Mount Panorama.</strong><br><br><a href="https://www.google.com/maps/dir/The+Baker+at+Sutton,+Victoria+Street,+Sutton+NSW/Crookwell+NSW/-33.4385054,149.5594826/@-34.2865071,149.8930305,8.97z/data=!4m15!4m14!1m5!1m1!1s0x6b1657b7fb1de583:0x7dfc8007177d94ba!2m2!1d149.2529149!2d-35.1641348!1m5!1m1!1s0x6b11366de06c253d:0x40609b49043dd00!2m2!1d149.4702871!2d-34.4580448!1m0!3e0" target="_blank" rel="noopener">Drive Route here</a></span></p><p><span><strong>Buy tickets below or on the day.</strong></span></p><a href="https://premier.ticketek.com.au/shows/show.aspx?sh=BATH12HR23" target="_blank" rel="noopener"><span>https://premier.ticketek.com.au/shows/show.aspx?sh=BATH12HR23</span></a><p><span><span>The Paddock is free with your event ticket, giving you behind the scenes access to watch the teams in action in the garages!</span></span></p><p><span>Kids 12 and under receive FREE General Admission entry when accompanied by a paying adult.</span></p><p><span>There’s so much to see and do at the Bathurst 12 Hour, we hope that you can join us!</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Mount Panorama, Bathurst', '2023-02-04T20:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5003868, 'Pheasant Wood Track Day', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-244ab660.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp" loading="lazy" alt="" title=""></picture><br></p><p>The event you’ve all been waiting for!</p><p>Come join us for a very special event. This will be the first Track Day hosted by BMW Car Club Canberra and is proudly supported by Canberra BMW.</p><p>On top of being an already impressive day, we will have prizes for a number of categories as well. This will be a well-kept secret until our big day. Make sure you are there to find out!</p><p>NOTE: Our original driver training and Motorsport professional is not available for the new date. We are working on something special and will provide updates as soon as we have confirmation.</p><p>For those that have not attended a track day before, this will be a great introduction.</p><p>There are some mandatory requirements to attend:</p><ul><li>Long sleeve cotton shirt, full length pants and enclosed footwear</li><li>Helmet: hire may be available</li><li>Motorsport (Motorsport Australia or AASA) or track (Pheasant Wood) licence: A day licence can be purchased for $30 @ the track. Note: Can be upgraded on the day to an annual licence for an additional $69</li></ul><p>This will be a fully catered event. Your registration fee includes all lunch, snacks and drinks (water, soft drink, tea and coffee). Simply turn up and enjoy the day.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-race-44574a5e-114f24d8.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-race-44574a5e-be22f78b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-race-44574a5e-be22f78b.webp" loading="lazy" alt="" title=""></picture></p><p><strong>Early Bird pricing: $200 for members of any official BMW Club (verification of current membership will be required), $250 for non-members. This will be available until 31 December 2022.</strong></p><p>Club merchandise will also be available for purchase on the day.</p><p>Registrations are limited, be sure to register ASAP to avoid disappointment.</p><p>If you have any questions please don’t hesitate to ask.</p><p>Regards,<br>Luke Wise<br>President | BMW Car Club Canberra<br>Official BMW Club<br>0410 333 540<br><a href="/">BMW Car Club Canberra</a></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Viewing Guest Registration – $25.00 This is for all participants that are attending to watch the day and wish to be catered for.Price includes, lunch, snack, drink, etc.</li></ul>', 'Pheasant Wood Circuit, Marulan', '2023-02-10T20:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5150775, 'Charity Hot Laps - Pheasant Wood Track Day', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-244ab660.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp" loading="lazy" alt="" title=""></picture><br></p><p>Come join us for a very special event. This will be the first Track Day hosted by BMW Car Club Canberra and is proudly supported by Canberra BMW.</p><p>We are excited to announce that we have not one but THREE Motorsport professionals secured for our first track day. With some seriously impressive experience! Two of whom are members of OUR CLUB!!</p><p>This is a fantastic opportunity to take a ride with a professional driver in a race car, at race pace. Hot laps are $100 each with all proceeds going to Marymead to continue the great work they do. Places may be available on the day however, please register ASAP to assist with planning.</p><p>Please join us in welcoming Damien Lomax, Reece McIntosh and Phil Alexander to what will be the start of a new era for BMW Car Club Canberra. Between them there are 60+ years of racing experience at some of the most grueling international circuit events including: The Bathurst 6 hour, Bathurst 12 hour and Nurburgring 24 hour.</p><p>In addition to the paid hot laps, Damien, Reece and Phil will also be on hand to offer advise and driver tutelage at Pheasant Wood so we can safely enjoy ourselves and explore our car’s potential.</p><p>There are some mandatory requirements to attend:</p><ul><li>Long sleeve cotton shirt, full length pants and enclosed footwear</li><li>Helmet (can be supplied if you don''t have one)</li></ul><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-race-44574a5e-114f24d8.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-race-44574a5e-be22f78b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-race-44574a5e-be22f78b.webp" loading="lazy" alt="" title=""></picture></p><p>Club merchandise will also be available for purchase on the day.</p><p>Registrations are limited, be sure to register ASAP to avoid disappointment.</p><p>If you have any questions please don’t hesitate to ask.</p><p>Regards,<br>Luke Wise<br>President | BMW Car Club Canberra<br>Official BMW Club<br>0410 333 540<br><a href="/">BMW Car Club Canberra</a></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Hot Lap entry – $100.00 Registration for a ride with one of our professional drivers</li></ul>', 'Pheasant Wood Circuit, Marulan', '2023-02-10T23:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/50yearsm-f3af1004-4a858e0e.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5026889, 'Shannons Wheels 2023', '<p><br></p><p><span>Join us for<span><span>the 41st edition of ''Wheels'', the Region''s Summer vehicle display!</span></span></span></p><p><span>The Shannons Wheels charity car and bike display will be held at the Queanbeyan Showground on Sunday 19 February 2023.</span></p><p><span>The 41st display is being organised by the Canberra Antique and Classic Motor Club on behalf of the Council of ACT Motor Clubs for it''s 78 affiliated clubs.</span></p><p><span>The show features all types and marques of vehicle, from the early days of motoring right up to the latest generation of EVs.</span></p><p><span>The 2023 show also adds another dimension by turning a spotlight on a particularly interesting era, the 1950s.</span></p><p><span>The "Back to the 1950s" spotlight displays will bring back many memories of the fins and chrome era, with American and British cars easily recognisable by their shape and style.</span></p><p><span>There will be a special one-off trophy for the club with the best display of 1950s vehicles.</span></p><p><span>As in previous years, the Shannons Wheels event will be raising funds for local charities.</span></p><p><span>Looking forward to seeing you there!</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Queanbeyan Showgrounds', '2023-02-18T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5072230, 'Fish n Chip Run', '<p><br></p><p>Join us for a Fish &amp; Chip run to Batemans Bay!</p><p>9:30am meetup at Supercheap Auto Queanbeyan car park, 9:45am departure to cruise the Kings Highway to the Coast. We’ll be stopping in at Nelligen Pub to re-group, then continuing to Corrigans Beach for lunch.</p><p>Looking forward to seeing you there!</p>', 'Meet-up at Supercheap Auto Queanbeyan Car Park', '2023-03-04T22:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (4929807, 'BMW Clubs Australia Nationals 2023', '<p><br></p><p><span>BMW Club Gold Coast with BMW Club QLD are hosting the BMW Clubs Australia Nationals based at the Sebel / Mantra Hotel at Twin Towns on the 17th - 20th of March 2023.</span></p><p><span>There will be two motorsport events, either side of this weekend, one at Lakeside Park Raceway, Kurwongbah on Friday 17th March and the second at Morgan Park, Warwick on Tuesday 21st March.</span></p><p><span>The BMW Clubs Australia Nationals is a chance for members of BMW car clubs across Australia to meet up and enjoy each other''s company and attend some great events. The BMW Nationals are run every 2 years with a different State/Territory hosting the event each time.</span></p><p><span>Please see the<a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/bmwca-2023-nationals-flyer-ver03-78d7bd13-27949ad7.pdf" target="_blank">BMW 2023 Nationals Flyer</a>for more information.</span></p><p><strong>**You MUST register to attend via the below link!**</strong><br><a href="https://www.bmwclubsaustralia.org.au/event-4813302" target="_blank" rel="noopener">https://www.bmwclubsaustralia.org.au/event-4813302</a></p><p>We’ll organise a 2-day trip from Canberra for those wanting to convoy together to the Nationals.</p><p><span>The BMW Nationals are great fun. Catch up with old friends, meet new people, attend some great events and enjoy your BMW!</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Queensland', '2023-03-16T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5228847, 'BMW CLUB COMMUNITY MANAGEMENT TEAM LIVE FROM MUNICH', '<p><br></p><p><span>Join us for the March BCCM Live Session direct from BMW Classic in Munich!</span></p><p><span><span><span>BMW Clubs and Community Management (BCCM), the department of BMW Classic at BMW Munich that looks after BMW Clubs around the world, has been running a series of live video sessions called BCCM Live. These very informative programs have been conducted by the staff of BCCM. There have been sensational sessions over the last 6 months, attended by BMW Club Members from all around the world.</span></span><br></span></p><p><span>This will take place on<strong><span>Friday, 31 March at 7pm Australian Time.</span></strong></span><span><span>Featuring presentation of new additions to the collection.</span></span></p><p><span>These webcasts are very informative and only run for 30 minutes, so make some time in your calendar to log in.</span><br></p><p><span><em><span><strong><span><span><span>**Please follow the link</span></span><a href="https://teams.microsoft.com/l/meetup-join/19%253ameeting_NThkOTQ1YTMtZmNhMi00N2IzLTlhYWEtOTg4Zjg0MjY5Y2Q5%2540thread.v2/0?context=%7B%22Tid%22%3A%22ce849bab-cc1c-465b-b62e-18f07c9ac198%22%2C%22Oid%22%3A%228fdb57e6-8d4c-47a9-a634-b8de32e2965a%22%7D" target="_blank" rel="noopener"><span><span>BCCM Live Session</span></span></a>to join.**</span></strong><br></span></em></span></p><p><span><strong><span>How does it work?</span></strong><br>We set up a MS Teams Meeting, please share the link above with your club members. In order to have the best possible quality,<em><span>we ask you to deactivate your camera and also mute your microphones</span></em>. There will be time for Q&amp;A during the meeting and you can send your questions via chat.<br><br><strong><span>What will the sessions be about?</span></strong><br>We want to keep it casual. It´s just us members of the BCCM that will give you updates on news from the network, the BMW Group and other things that are keeping us busy. There will be also a chance for you asking questions.<br><br>Further information about the content will follow prior to the session within a reminder.<br><br>We will keep it simple: No studio, spectacular camera angles or sophisticated graphics.<br>As the format is still pretty new, we kindly ask for your understanding in case something should not work 100%. There will be always room for improvement and we also want to learn in every session what is most relevant for you.<br><br>We are pretty sure, we will have a good time at both events.<br>Looking forward to a lot of you joining soon.<br><br>Mit freundlichen Grüßen,<br><br>BMW Club and Community Management Team</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Your Home Computer', '2023-03-31T08:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5191820, 'BMW Cars & Coffee', '<p><br></p><p>Join us for a casual meet-up at<a href="https://www.facebook.com/AsNatureIntendedCBR/" target="_blank" rel="noopener">As Nature Intended.</a>Enjoy a delicious cup of coffee, something for breakfast or a sweet treat and admire your fellow enthusiasts polished, modified, new acquisition or daily steed with other like-minded lovers of all things BMW.</p><p>E30 Enthusiasts Australia group will also be joining us!</p><p>As Nature Intended stock fresh organic fruit, vegetables, and lots of other products, including bulk foods and natural cleaning products. The café menu has something for everyone, with all dietary requirements catered for. They have plenty of delicious cakes, freshly baked breads and muffins made in house by their amazing chefs.</p><p>This event is open to all BMW enthusiasts, no need to be a member to attend.</p><p>Please see the below map on where to park.</p><p><br></p><p>P.S. This is not an April Fools joke, it''s really happening! haha. We look forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'As Nature Intended, 4/1 Dairy Road, Fyshwick', '2023-03-31T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5106795, 'Motorsport & Driver Training: Skidpan Day', '<p><br></p><p><span>We are excited to announce our 2nd Motorsport event and 1st training session for the year: The Skidpan at Sutton Road Driver Training Complex, Sunday 2 April 2023.</span></p><p><span>For those that aren''t familiar, the skidpan is a slippery circuit that replicates driving on snow/ice or hitting a patch of oil. It''s smooth concrete, water is applied to provide the slide..... Vehicle speeds are less than 50 km/h and as the<span>circuit</span>is so slippery, there is very little wear on tyres and very low risk. The fun factor is extreme as you attempt to control your car with little or no traction!</span></p><p><span><span><span>The Skidpan will help you to better understand your vehicle and car control in general, including what to do when there is understeer or oversteer.</span></span></span></p><p><span><span><span>This is a great learning event for everyone. We strongly encourage new drivers to come and learn more about their vehicle and for experienced drivers to refresh their skills and of course, have fun!</span></span></span></p><p><span><span><span>Skills learnt on the skidpan are invaluable and can save lives.</span></span></span></p><p><span><span><span>There will be people available on the day for those wanting instruction or support.</span></span></span></p><p><span>Light refreshments will be available (thanks to El Presidente''s baking). Please bring drinks and lunch, or drive to nearby Queanbeyan.</span></p><p><span><span><strong>Drivers briefing will be at 8:15am sharp. The fun begins at 8:30.</strong></span></span></p><p><span>NOTE: We''ve put together special pricing for everyone. $120 ($140 for non-members) is per vehicle with multiple drivers allowed, for the ENTIRE day. Places are limited, register early to avoid disappointment!</span></p><p><span><span>There will be some surprises on the day, including some special awards.</span><br></span></p><p><span>Looking forward to seeing you there!</span></p><h3>Registration</h3><ul><li>Motorsport Skidpan Day - Member Price – $120.00 Official BMW Club Member Price.Participants may share a car, however it is $120 per car to book a place on the day.</li><li>Motorsport Skidpan Day - Non-Member Price – $140.00 Non-Member Price.Participants may share a car, however it is $140 per car to book a place on the day.</li></ul>', 'Sutton Road Driver Training Complex', '2023-04-01T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5074823, 'Wheels of Wamboin 2023', '<p><br></p><p>Join us for Wheels of<span><span>Wamboin</span></span>2023!</p><p><span>Wheels of Wamboin is a motoring enthusiasts'' event with vintage, classic and street machines - from Model ''T''s to Tesla and everything in between!</span></p><p><span>The Wamboin Home Produce Market will also be on (Wamboin Community Hall, next to Wamboin Oval ). There will be a v</span><span>ariety of stalls, including lots of fresh fruit &amp; vegies, healthy juices, coffee, egg &amp; bacon rolls, jewellery, cards, lollies, dried fruits &amp; nuts, cakes, sausage rolls, quiches, craft, knitting, preserves, and more!</span></p><p><span><span>So, bring your German automotive marvel, have a great coffee, and grab an egg and bacon roll.</span></span></p><p><span>Venue: Wamboin Oval - off Norton Road (adjacent to the Wamboin Community Hall)</span></p><p><span>Time: 09:00am to 1:00pm</span></p><p><span>Entry: Gold coin donation - proceeds to Wamboin RFS</span></p><p><span><strong>For those wanting to convoy in and park together, please meet at the Sutton Road Driver Training centre @ 8:30am sharp!</strong></span></p><p><span>Please check the<a href="https://www.facebook.com/wheelsofwamboin/posts/910761312963903" target="_blank" rel="noopener"><span>Wheels of Wamboin</span><span>Facebook page</span></a>for updates.</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Wamboin Oval - off Norton Road (adjacent to the Wamboin Community Hall)', '2023-04-14T22:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5228856, 'BMW CLUB COMMUNITY MANAGEMENT TEAM LIVE FROM MUNICH', '<p><br></p><p><span>Join us for the<span><span>April</span></span>BCCM Live Session direct from BMW Classic in Munich!</span></p><p><span><span><span>BMW Clubs and Community Management (BCCM), the department of BMW Classic at BMW Munich that looks after BMW Clubs around the world, has been running a series of live video sessions called BCCM Live. These very informative programs have been conducted by the staff of BCCM. There have been sensational sessions over the last 6 months, attended by BMW Club Members from all around the world.</span></span><br></span></p><p><span>This will take place on<strong><span>Friday, 28<span><span>April</span></span>at 6pm Australian Time.</span></strong></span><span><span>Featuring presentation of new additions to the collection.</span></span></p><p><span>These webcasts are very informative and only run for 30 minutes, so make some time in your calendar to log in.</span><br></p><p><span><em><span><strong><span><span><span>**Please follow the link</span></span><a href="https://teams.microsoft.com/l/meetup-join/19%253ameeting_NThkOTQ1YTMtZmNhMi00N2IzLTlhYWEtOTg4Zjg0MjY5Y2Q5%2540thread.v2/0?context=%7B%22Tid%22%3A%22ce849bab-cc1c-465b-b62e-18f07c9ac198%22%2C%22Oid%22%3A%228fdb57e6-8d4c-47a9-a634-b8de32e2965a%22%7D" target="_blank" rel="noopener"><span><span>BCCM Live Session</span></span></a>to join.**</span></strong><br></span></em></span></p><p><span><strong><span>How does it work?</span></strong><br>We set up a MS Teams Meeting, please share the link above with your club members. In order to have the best possible quality,<em><span>we ask you to deactivate your camera and also mute your microphones</span></em>. There will be time for Q&amp;A during the meeting and you can send your questions via chat.<br><br><strong><span>What will the sessions be about?</span></strong><br>We want to keep it casual. It´s just us members of the BCCM that will give you updates on news from the network, the BMW Group and other things that are keeping us busy. There will be also a chance for you asking questions.<br><br>Further information about the content will follow prior to the session within a reminder.<br><br>We will keep it simple: No studio, spectacular camera angles or sophisticated graphics.<br>As the format is still pretty new, we kindly ask for your understanding in case something should not work 100%. There will be always room for improvement and we also want to learn in every session what is most relevant for you.<br><br>We are pretty sure, we will have a good time at both events.<br>Looking forward to a lot of you joining soon.<br><br>Mit freundlichen Grüßen,<br><br>BMW Club and Community Management Team</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Your Home Computer', '2023-04-28T08:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5072301, 'Snowy High Country Overnight Run', '<p><br></p><p><span>Join us for our first overnight run for the year! This drive will be on some of the most scenic and greatest driving roads in Australia, with great stopovers and photo opportunities along the way.</span></p><p><strong><span>DAY ONE</span></strong></p><p><span>Departing Calwell Shopping Centre Car Park at<strong>8.00am sharp</strong>on Saturday, driving through Cooma, Dalgety, Beloka onto Jindabyne for morning tea. Depart Jindabyne via the Alpine Way to Khancoban Roadhouse via Crackenback and Thredbo. Lunch at Khancoban then return back to Jindabyne for the afternoon/evening. There will be group dinner planned.</span></p><p><strong><span>DAY TWO</span></strong></p><p><span>After breakfast we will leave Jindabyne for Tumut, via Middlingbank, Adaminaby, Kosciuszko National Park, Talbingo (Morning Tea) and onto the Tumut River Brewing Company (1/5 Capper Street) for lunch. Afternoon tea will be at Jugiong before heading back to Canberra.</span></p><p><strong><span>ACCOMODATION</span></strong></p><p><span>We have arranged a special deal at<span><span><a href="http://www.lakejindabynehotel.com.au/" target="_blank" rel="noopener">Lake Jindabyne Hotel</a>, $150 for the night (Lakefront king with bunk) with c<span>ooked breakfast included! If you require a family room, this will be $20 extra. To book, please call Lake Jindabyne Hotel on<span>Phone:</span><span>(02) 6456 2203 or 1800 646 818 and<strong>quote r<span><span>eservation #</span></span></strong><span><strong>124493</strong>/ BMW Car Club Canberra to receive this special deal. Please note they have a<span><span>Cancellation Policy.</span></span></span></span></span></span></span></span></p><p><br></p><p><span><span><span><span><span><span><span><span><span><span>This drive is not to be missed!</span></span></span></span></span></span></span></span></span></span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Meet at Calwell Shopping Centre Car Park', '2023-05-26T22:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5076322, 'Southern Tablelands Drive', '<p><br></p><p>Come and join us on a local run to the north of Canberra (Binalong, Boorowa, Crookwell, &amp; Gundaroo) and enjoy a mix of roads, scenery, and local hospitality. We’ll stop at Binalong (Cafe on Queen, Binalong) for morning tea and lunch at The Criterion Hotel (Middle Pub) in Crookwell.</p><p>We will investigate places of interest or other events that can be included during the journey.</p><p><a href="https://www.google.com/maps/dir/McDonald''s,+2+O''Hanlon+Pl,+Nicholls+ACT+2913/Binalong+NSW/Boorowa+NSW/Crookwell+NSW/Gundaroo+NSW/@-34.7325966,149.0375718,9.89z/data=!4m32!4m31!1m5!1m1!1s0x6b17acbdc35b0257:0x474d20239a55e044!2m2!1d149.0819421!2d-35.189927!1m5!1m1!1s0x6b1741cf39562c45:0x40609b49043e5a0!2m2!1d148.6280964!2d-34.6708455!1m5!1m1!1s0x6b10ca96279a0199:0x40609b49043db10!2m2!1d148.7167614!2d-34.4364648!1m5!1m1!1s0x6b11366de06c253d:0x40609b49043dd00!2m2!1d149.4702871!2d-34.4580448!1m5!1m1!1s0x6b16fbc0026444e9:0x40609b49043de10!2m2!1d149.2547097!2d-35.0410869!3e0" target="_blank" rel="noopener">Drive Route</a></p><p>Departing from McDonald''s, Nicholls at 8.30AM sharp.</p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Departing from McDonald''s, Nicholls at 8.30AM sharp', '2023-06-10T22:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5309046, 'Bimmers & Burgers - The Darkest Day of the Year', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1685942065815-002-ac4bc990-1f60590e.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1685942065815-002-ac4bc990-8d141a2c.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1685942065815-002-ac4bc990-8d141a2c.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for our Winter Solstice meet-up at<a href="https://brodburger.com.au/" target="_blank" rel="noopener">Brodburger</a>Kingston.</p><p>Enjoy a delicious burger or hotdog and admire your fellow enthusiasts polished, modified, new acquisition or daily steed with other like-minded lovers of all things BMW!</p><p>It will also be a great opportunity to take some night photos of our cars on the d<span>arkest (</span>shortest) day of the year.</p><p>Kicking off from 5:30pm - Looking forward to seeing you there!</p><p>P.S. Don’t forget to rug-up.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-2023-06-05-160553-2390360b-77400191.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-2023-06-05-160553-2390360b-ada3e640.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-2023-06-05-160553-2390360b-ada3e640.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Brodburger Kingston', '2023-06-22T07:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1685942065815-002-ac4bc990-8d141a2c.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5329680, 'ACT FAST: Club Motorsport Shirts', '<p><span><span>We have the pleasure to present to you the following BMW Motorsport T-Shirts.</span></span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-other-side-1-8c24929f-74775115.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-other-side-1-8c24929f-b9fae26b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-other-side-1-8c24929f-b9fae26b.webp" loading="lazy" alt="" title=""></picture></span></p><p><span>They have been designed in-house by our very talented Josh Sellick with input from Marcus.</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-back-1-f1f94980-80ff57e5.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-back-1-f1f94980-b58bae7d.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-back-1-f1f94980-b58bae7d.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>These long sleeve T-shirts are 100% cotton and perfect for the next track day (shirts must be non-synthetic and long sleeve for track) and fashionable enough for any other club event.</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-front-1-5d465e48-83c13ef4.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-front-1-5d465e48-ed05d7a6.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-front-1-5d465e48-ed05d7a6.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>No BMW fan’s wardrobe is complete without this.</span><span>The cost is being subsidised by the club to make it an even $50 per shirt. NOTE: We need 25 shirts to be ordered to proceed, if you are considering buying one, please get on board ASAP.</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/ladies-size-chart-d1c9610a-27d0aac0.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/ladies-size-chart-d1c9610a-379bbea1.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/ladies-size-chart-d1c9610a-379bbea1.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>Please check attached sizing chart for ladies and mens options. There are no youth options available for this order.</span></p><p><span>Colours available are Grey or Black, o</span><span>rders can be placed through this event or the track day event.</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mens-size-chart-08731c40-a47b8858.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mens-size-chart-08731c40-c694feab.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mens-size-chart-08731c40-c694feab.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>There is a 3XL size for the Mens shirts although it is not listed on the chart.</span></p><p><span>FINAL NOTE: Orders<u><strong>MUST</strong></u>to be completed by July 5th @ 12:00pm, this will ensure all shirts are made and delivered in time for the track day on July 30th.</span></p><p><span>Any questions, please DM Marcus Hon</span></p><p>Regards,<br>Luke Wise<br>President | BMW Car Club Canberra<br>Official BMW Club<br>0410 333 540<br><a href="/">BMW Car Club Canberra</a></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Ladies Black long sleeve shirt – $50.00 Grab a killer shirt, perfect for track days! Cotton and long sleeve makes it track day approved</li><li>Ladies Grey long sleeve shirt – $50.00 Grab a killer shirt, perfect for track days! Cotton and long sleeve makes it track day approved</li><li>Mens Black long sleeve shirt – $50.00 Grab a killer shirt, perfect for track days! Cotton and long sleeve makes it track day approved</li><li>Mens Grey long sleeve shirt – $50.00 Grab a killer shirt, perfect for track days! Cotton and long sleeve makes it track day approved</li></ul>', '', '2023-07-04T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/motorsport-other-side-1-8c24929f-b9fae26b.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5230343, 'Christmas in July Lunch', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/george-276d40a5-a0279ccc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/george-276d40a5-f39cc664.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/george-276d40a5-f39cc664.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for "Christmas in July" Lunch at The George Bar &amp; Dining.</p><p>The George Bar &amp; Dining is located in the heart of the historic town of Bungendore. The restaurant offers an extensive A La Carte menu focusing on craft food with seating set around their feature fireplace. The GB&amp;D prides itself on its amazing selection of local Canberra District cool climate wines hand-picked by their sommelier as well as offering an extensive craft beer selection both on tap and in bottle. There’s also a children’s playground area – perfect for the little ones to burn off some energy!</p><p><strong>We have reserved seating for 45 people so don’t delay in reserving your seat/s! If you have registered and are no longer able to attend, please cancel your registration so others can attend.</strong></p><p>For those interested, we’ll be arranging a Club drive to Bungendore taking the back roads. Drive route and details provided closer to the date.</p><p>*If you are planning to drink alcohol, please ensure that you drink responsibly!</p><h3>Registration</h3><ul><li>Christmas in July Lunch at The George Bar &amp; Dining If you have registered and are no longer able to attend, please cancel your registration so others can attend.</li></ul>', 'The George Bar & Dining, Bungendore', '2023-07-09T02:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/george-276d40a5-f39cc664.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5272760, 'German Cars n Coffee', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-car-brands-9c17c4ba-51a6c04e.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-car-brands-9c17c4ba-222f1240.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-car-brands-9c17c4ba-222f1240.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us, along with other German Car Clubs (<span>Audi, Mercedes-Benz, Porsche, and Volkswagen</span>) for the inaugural German Cars n Coffee!</p><p>It’s sure to be a great morning. Enjoy meandering around German cars, catching-up with fellow club members while drinking a hot beverage or two... Don’t forget to rug up!</p><p>This event is hosted by the<span>Volkswagen</span>Club.</p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Spanish Club, 5 Narupai Place, Narrabundah', '2023-07-15T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-car-brands-9c17c4ba-222f1240.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5353746, 'Midweek Lunch', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/202716-p31309471-07ac61d7-57819ff1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/202716-p31309471-07ac61d7-832bf011.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/202716-p31309471-07ac61d7-832bf011.webp" loading="lazy" alt="" title=""></picture><br></p><p><span>We know that some of our members are not always confined to work during the working day so we thought we might arrange a trial midweek, midday lunch at Dirty Janes.</span></p><p><span>So if you are free please come along. We can peruse the wares on sale and then have something to eat and chat about life, the universe and everything--oh and looking at cars is also permitted!</span></p><p><span>Depending on interest, this could become a regular event at different venues both inside and outside of Canberra. Suggestions welcomed.</span></p><span><span>If you require any further information or assistance, please contact Lorna Kunz: lorna.e.kunz@gmail.com</span></span><p><span>Hope to see you there.</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Dirty Janes, 80 Collie St, Fyshwick (behind the Domayne building).', '2023-08-10T02:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/202716-p31309471-07ac61d7-832bf011.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5353620, 'Fish N Chip Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bimmers-in-the-bay-pic-2-b8cd6bf1-91da131c.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bimmers-in-the-bay-pic-2-b8cd6bf1-46442a20.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bimmers-in-the-bay-pic-2-b8cd6bf1-46442a20.webp" loading="lazy" alt="" title=""></picture><span><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/blue-white-modern-bold-charity-event-flyer-1-3e3f640e-a240d1b9.pdf" alt="" title="" loading="lazy"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/blue-white-modern-bold-charity-event-flyer-1-3e3f640e-a240d1b9.pdf" alt="" title="" loading="lazy"></span></p><p><span>Join us, along with the Volkswagen Club for Cookies Cycles annual Fish N Chip run to Corrigans Beach, Batemans Bay.</span></p><p><span>8:00am meetup in front of Old Parliament House, 8:30am departure to cruise the Kings Highway to the Coast. We’ll be stopping in at Braidwood for a coffee and then meeting the South coast guys at Nelligen pub, before continuing to Corrigans Beach for lunch. Corrigans Beach also has a big playground to keep the kids entertained, toilet amenities, covered eating areas and<span><span>shops nearby</span><span>.</span></span></span></p><p><span>The event is free to enter but they will be shaking the can for Cookies Cycles'' Camp Quality Super Heroes Cruise team.</span></p><p><span>Looking forward to seeing you there!</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/blue-white-modern-bold-charity-event-flyer-1-f8f14f9e-8cc167d3.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/blue-white-modern-bold-charity-event-flyer-1-f8f14f9e-a4d3a63a.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/blue-white-modern-bold-charity-event-flyer-1-f8f14f9e-a4d3a63a.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><br></p><p><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Corrigans Beach, Batemans Bay', '2023-08-19T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bimmers-in-the-bay-pic-2-b8cd6bf1-46442a20.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5191361, 'German Auto Show (Melbourne)', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-auto-show-2023-003-78718349-5b997fe7.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-auto-show-2023-003-78718349-180b8a90.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-auto-show-2023-003-78718349-180b8a90.webp" loading="lazy" alt=""></picture><br></p><p>BMW Drivers Club Melbourne have invited BMWCCC members to join them at the GERMAN AUTO SHOW in Melbourne.</p><p>The German Auto Show brings the best German vehicles together in Melbourne in one spot, with some of the quirky and now defunct brands being included.</p><p>It is not a concours, or even a show and shine, so any clean vehicle is very welcome. As long as it is German.</p><p>There is a prize for people''s choice, president''s choice and best of each marque, so you may even score a trophy!<br></p><p>The Thunderdome is a historic venue and what a great place to raise funds for a good cause, and with lots of interesting vehicles to look at and fascinating company.<br></p><p>In 2023, BMW Motorrad are celebrating 100 years of the R32 and what a better place to hold their celebration than at the German Auto Show.<br></p><p>If you are wanting accommodation for before or after the event, please use this<a href="https://businesstravel.accor.com/booking/advanced-search/index.en.shtml?identification.reserverType=SC&amp;identification.reserverId=SCP4197198&amp;identification.reserverContract=BM485AU173" target="_blank" rel="noopener">link</a>to book your accomodation, it''s only 12 minutes away from the Thunderdome and we have secured great discount pricing for this weekend.<br><span>(The discount codes are already pre selected when you use this link)</span></p><p><span><strong>**Please register via the below link if you are attending**</strong></span></p><p><a href="https://bmwdcm.com.au/event-5159446/Registration" target="_blank" rel="noopener">bmwdcm.com.au/event-5159446/Registration</a></p><p>PRE REGISTRATION WILL CLOSE ON 24 AUGUST. IF YOU DO NOT PRE-REGISTER, THE GATE FEE WILL BE $20.<br></p><p>The event is to raise much needed funds for Beyond Blue. Last year we raised over $10,500 and we are hoping to double that figure this year. Be part of history and lets make this one of the biggest German Auto Shows EVER.</p><p>All donations can be made<a href="https://fundraise.beyondblue.org.au/german-auto-show-2023" target="_blank" rel="noopener">here</a>.</p><p>There will be food for sale on the day and trade stalls too.</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Calder Park Thunderdome, 377 Calder Fwy, Calder Park VIC 3037', '2023-08-26T22:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-auto-show-2023-003-78718349-180b8a90.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5357878, 'Dinner, General Meeting and Movie Night', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-pic2-9e5737bd-63e308ba.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-pic2-9e5737bd-7e2e5691.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-pic2-9e5737bd-7e2e5691.webp" loading="lazy" alt="" title=""></picture><br></span></p><p>Celebrate the final hours of winter by joining the committee and fellow members for a cosy night in with a dinner, catch up and a movie on 31 August.</p><p>The committee will give you a quick update on how the club is doing and we want to hear your feedback or suggestions on how we can do things differently or better. Share your good ideas! After that we are planning to show a movie or short films on motorsport/BMW related topics. Topic(s) to be advised later.</p><p><strong>We have booked the MacDonald Room (up-stairs) at Eastlakes Football Club for the General Meeting at 7pm and we have also booked a table for 6pm if you would like to eat in the bistro beforehand.</strong><br></p><p>We will need to know if you are attending and choosing to eat at the club so we can arrange entrance for non-members of Eastlakes and to ensure sufficient seating in the room and the bistro.</p><p><strong>Discounted club merchandise will be available to purchase and there will also be lucky door prizes to be won!</strong></p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>Attending Dinner and General Meeting (6PM) We will need to know if you are attending and choosing to eat at the club so we can arrange entrance for non-members of Eastlakes and to ensure sufficient seating in the room and the bistro.</li><li>Attending General Meeting Only (7PM) 7PM start time for the General Meeting in the MacDonald Room (up-stairs) at Eastlakes Football Club</li></ul>', 'Eastlakes Football Club, 3 Oxley Street Griffith', '2023-08-31T08:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/eastlake-football-club-pic2-9e5737bd-7e2e5691.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5386490, 'Club Cruise to Fairbairn Park Hillclimb Circuit (SDMA Hillclimb)', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mighty-ti-at-hillclimb-d0e722e3-df773ce1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mighty-ti-at-hillclimb-d0e722e3-8e3c81c0.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mighty-ti-at-hillclimb-d0e722e3-8e3c81c0.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for a cruise out to Fairbairn Park Hillclimb Circuit (<a href="https://www.sdmahillclimb.com.au/" target="_blank" rel="noopener">SDMA Hillclimb</a>) to cheer on club members who are competing in the Hillclimb!</p><p>Meeting at Three Mills Bakery (<a href="https://www.google.com/maps/place/5+Leeton+St,+Fyshwick+ACT+2609/@-35.32267,149.1516309,17z/data=!3m1!4b1!4m6!3m5!1s0x6b164c57b9cb1871:0x9c08b4498b2d1c5!8m2!3d-35.32267!4d149.1516309!16s%252Fg%252F11c24yp781?entry=ttu" target="_blank" rel="noopener">5 Leeton St Fyshwick</a>) at 8am for a delicious coffee, baked pastries or a Bacon &amp; Egg Roll, we’ll then cruise on out to the Hillclimb Circuit.</p><p>Entry is off Sutton Road, next to the Driver Training Centre. There is spectator seating, food available and<span>toilet amenities</span>.</p><p>So come along and check out some local motorsport and cheer on your fellow club members!</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-hillclimb-set-up-74905fcf-669c99f1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-hillclimb-set-up-74905fcf-321ed764.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-hillclimb-set-up-74905fcf-321ed764.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Three Mills Bakery, 5 Leeton St Fyshwick', '2023-09-09T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mighty-ti-at-hillclimb-d0e722e3-8e3c81c0.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5383883, 'Volunteers Needed: German Auto Day 2023', '<h2><span>German Auto Day 2023</span></h2><p><strong><span>When</span></strong><span>: 24 Sep 2023 8:30 AM, AEST<br><strong>Where</strong>: Queanbeyan Park, Campbell St, Queanbeyan</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-cc894e50.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><strong><em><span>German Auto Day 2023</span></em></strong><span>is set to be a sensational event, particularly for BMW.</span></p><p><span>It is also the day for the club’s annual<strong>Show ‘n Shine</strong>. We are looking for volunteers to help set up and to judge for the event.</span></p><p><span>No experience in judging is strictly necessary but it will help, as will an eye for detail. For those without experience, guidance will be given before you start your duties. If you are entered in the Show ‘n Shine, you can still be a judge – except you will be allocated to a different category your car is entered.</span></p><p><span><span>If you need more information please don''t hesitate to ask.</span></span></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Help Set up Assistance setting up the grounds and lining cars up for display</li><li>Show n Shine Judge No experience necessary! This is a great opportunity to learn not only about judging, it will also provide you with insight as to what you can do to prepare your car for future events.</li><li>Traffic Management Help direct traffic and ensure cars entering are registered to attend</li></ul>', 'Queanbeyan Park, Queanbeyan', '2023-09-23T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5180476, 'German Auto Day 2023', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-658b99be-1dd195d3.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-658b99be-80cab0d3.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-658b99be-80cab0d3.webp" loading="lazy" alt="" title=""></picture><br></span></p><span><span>Join us for German Auto Day (GAD) 2023, as it returns to the Canberra region at the picturesque location of Brad Haddin Oval (Town Park) Queanbeyan, NSW.</span></span><p><span>GAD is a one day German automotive display event held each year in the Canberra region and is a collaboration event organised by local German branded marques, Audi, BMW, Mercedes Benz, Porsche and Volkswagen.</span></p><p><span><strong>We’ll also be holding the Clubs annual Show n Shine - BMWCCC Members Entry – $15.00 (entry fee goes towards trophies).</strong></span></p><p><strong><span>**Please respond to the invitation so that adequate parking spaces can be secured.<strong>If you have registered and are no longer able to attend, please cancel your registration so others can attend**.</strong></span></strong></p><p><span>There will be plenty to do and see for the whole family - Food, coffee and activities to keep the kids entertained!</span></p><p><span><span>There will be a gold coin donation for entry, all proceeds going to the nominated charity.</span></span></p><strong>IMPORTANT EVENT DETAILS BELOW</strong><p><span><strong>Day of event</strong></span></p><p><span>On the day of GAD, entrants can start arriving on site from 8:00am and to be in place before 10am on Sunday, 24 September 2023. We suggest getting in early to avoid access chaos.</span></p><p><span><strong>Entry to the venue for ALL GAD vehicles is from Lowe Street, Queanbeyan. Vehicles will proceed down Lowe Street and turn left on to Campbell Street.</strong></span></p><p><span><strong>Please be advised there is no entry onto Campbell Street (except for residents) from Canberra Avenue to reduce traffic gridlock.</strong></span></p><p><span><strong>Please follow event marshals directions on where to park your car for display.</strong></span></p><p><span>Queanbeyan City Council has requested that all vehicles use a drip tray on the day.</span></p><p><span>Food and drink will be available on site during the day, additionally, there are a number of options near by on Canberra Avenue.</span></p><p><span>There are also rest room facilities on site. One near the children''s playground next to the oval pavilion and the other is on Lowe Street toward the police station.</span></p><p><span>What happens if the weather is bad? We''ll make that call closer to the day.</span></p><p><span><strong>Parking</strong></span></p><p><span>There will be limited onsite parking for parking for persons with a disability and trailers. Please enter through the main venue entry and advise the traffic control officer of your requirements.</span></p><p>Looking forward to seeing you there!</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-1-98523b95-9fc0203b.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-1-98523b95-d0e884cb.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-1-98523b95-d0e884cb.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture></span><br></p><h3>Registration</h3><ul><li>German Auto Day - Display Only Please respond to the invitation so that adequate parking spaces can be secured. If you have registered and are no longer able to attend, please cancel your registration so others can attend.</li><li>Show n Shine - BMWCCC Members Entry Only – $15.00 If you would like to enter your vehicle in the show n shine for judging please ensure you select this option.</li></ul>', 'Queanbeyan Park, Queanbeyan', '2023-09-23T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-658b99be-80cab0d3.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5000974, '*CALLING ALL CLASSICS* - Distinguished Gentleman’s Drive 2023', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-7d3d6ca1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-f309c37f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-f309c37f.webp" loading="lazy" alt=""></picture><br></p><p>We are proud to be hosting the Distinguished Gentleman’s Drive for the second time in Canberra!</p><p>NOTE: Despite the name, this is open for everyone to enter. It''s sure to be a sensational event, one we can all enjoy and support a great cause.</p><p>An extremely well-run organisation, we’re looking forward to continuing to grow this event.</p><p>The Distinguished Gentleman''s Drive is a celebration of classic style. It is an on-road motoring event, uniting pre-80s designed classic cars, encouraging drivers and passengers around the world to dress dapper and drive for men''s health. All funds raised are invested in vital research and programs for prostate cancer and men''s mental health by Movember.</p><p>For those interested I would encourage you to come join us. As the first time in the region, we really would like to see some participation to raise awareness.</p><p>To join in the drive and be in the running for fundraising rewards, register at<a href="http://www.gentlemansdrive.com/" target="_blank" rel="noopener">www.gentlemansdrive.com</a>and select the Canberra event.</p><p>Important Information:</p><p>- The event is strictly for pre-80’s cars (built on or before December 31st, 1979)</p><p>- Registration are opened and required for participation</p><p>- Drive details are available on the website to registered drivers</p><p>- Local drive details are to remain confidential, do not share them</p><p>- Dress in-theme and visit our website for information prizes and rewards for 2023</p><p>- Follow the official Gentleman''s Drive pages on Facebook and Instagram (@gentlemansdrive)</p><p>If you have any questions, please don’t hesitate to ask.</p><p><br></p>', 'Canberra, Australia', '2023-09-23T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-f309c37f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5417638, 'Midweek Catch-Up', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/midweek-catch-up-pick-7d526fc9-ca2b6534.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/midweek-catch-up-pick-7d526fc9-0ed252c5.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/midweek-catch-up-pick-7d526fc9-0ed252c5.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for a causal hump day get-together at the The ''G'' Spot, Gungahlin.</p><p>Enjoy a bite to eat and admire your fellow enthusiasts polished, modified, new acquisition or daily steed with other like-minded lovers of all things BMW!</p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/menu-ad2bbd08-1d30fc06.pdf" target="_blank" rel="noopener">The ''G'' Spot Menu</a></p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'The ''G'' Spot, Gungahlin Lakes Golf Club Carpark', '2023-10-11T07:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/midweek-catch-up-pick-7d526fc9-0ed252c5.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5455681, 'Impromptu Coffee Catch-Up', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/cnc-pic-485ce2dd-833303c5.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/cnc-pic-485ce2dd-aa502f66.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/cnc-pic-485ce2dd-aa502f66.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for a i<span>mpromptu</span>casual meet-up at<a href="https://www.dirtyjanes.com/salters-canberra/" target="_blank" rel="noopener">Salters Café</a>at Dirty Janes (Behind Domayne). Enjoy a delicious cup of coffee, something for breakfast or a sweet treat and admire your fellow enthusiasts polished, modified, new acquisition or daily steed with other like-minded lovers of all things BMW!</p><p>Looking forward to seeing you there!</p><p><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Salters at Dirty Janes, Fyshwick (behind Domayne)', '2023-10-20T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/cnc-pic-485ce2dd-aa502f66.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5136574, 'Driver Training: Skidpan Day', '<p><br></p><p><span>We are excited to announce our 2nd driver training session for the year: The Skidpan at Sutton Road Driver Training Complex, Sunday 22 October 2023.</span></p><p><span>For those that aren''t familiar, the skidpan is a slippery circuit that replicates driving on snow/ice or hitting a patch of oil. It''s smooth concrete, water is applied to provide the slide..... Vehicle speeds are less than 50 km/h and as the<span>circuit</span>is so slippery, there is very little wear on tyres and very low risk. The fun factor is extreme as you attempt to control your car with little or no traction!</span></p><p><span><span><span>The Skidpan will help you to better understand your vehicle and car control in general, including what to do when there is understeer or oversteer.</span></span></span></p><p><span><span><span>This is a great learning event for everyone. We strongly encourage new drivers to come and learn more about their vehicle and for experienced drivers to refresh their skills and of course, have fun!</span></span></span></p><p><span><span><span>Skills learnt on the skidpan are invaluable and can save lives.</span></span></span></p><p><span><span><span>There will be people available on the day for those wanting instruction or support.</span></span></span></p><p><span>Light refreshments will be available. Please bring drinks and lunch, or drive to nearby Queanbeyan.</span></p><p><span><span><strong>Drivers briefing will be at 8:15am sharp. The fun begins at 8:30.</strong></span></span></p><p><span>NOTE: We''ve put together special pricing for everyone. $120 ($140 for non-members) is per vehicle with multiple drivers allowed, for the ENTIRE day. Places are limited, register early to avoid disappointment!</span></p><p><span>Looking forward to seeing you there!</span></p><h3>Registration</h3><ul><li>Motorsport Skidpan Day - Member Price – $120.00 Official BMW Club Member Price.Participants may share a car, however it is $120 per car to book a place on the day.</li><li>Motorsport Skidpan Day - Non-Member Price – $140.00 Non-Member Price.Participants may share a car, however it is $140 per car to book a place on the day.</li></ul>', 'Sutton Road Driver Training Complex', '2023-10-21T21:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5417610, 'Sunday Morning Coffee & Drive', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/morning-coffee-and-drive-2e4d4a69-04d685b6.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/morning-coffee-and-drive-2e4d4a69-dc3f6086.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/morning-coffee-and-drive-2e4d4a69-dc3f6086.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for a<span>Sunday Morning Coffee &amp; Drive.</span></p><p>Meeting at<a href="https://www.facebook.com/morningdewcanberra/" target="_blank" rel="noopener">Morning Dew Café</a>for a delicious ONA Coffee, we''ll then be heading out for a Cotter run via Uriarra Village (Uriarra Road) ending up at Point Hut Picnic Area (with some photo stops along the way).</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-20230519-114013-9140e7ce-3f2bbf30.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-20230519-114013-9140e7ce-15713150.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-20230519-114013-9140e7ce-15713150.webp" loading="lazy" alt="" title=""></picture><br></p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Denman Village Shops, 1 Felstead Vista, Denman Prospect Canberra', '2023-11-04T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/morning-coffee-and-drive-2e4d4a69-dc3f6086.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5442247, 'Marques In the Park 2023', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/marques-in-the-park-pic-1-a66545fd-e087edb6.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/marques-in-the-park-pic-1-a66545fd-16c957ba.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/marques-in-the-park-pic-1-a66545fd-16c957ba.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for Marques In the Park, as it returns for 2023 to a new location at the Deakin Stadium.</p><p><span><span>Marques in the Park</span>is Canberra’s spring time motoring display run by the American Car Club in conjunction with the Council of ACT Motor Clubs. After its inception in 2003, the event has grown from 200 to nearly 500 vehicles.</span></p><p><span>Marques in the Park is a community based family event bringing motoring enthusiasts together for a fun day out.</span></p><p><span>The event is all encompassing:<br>All makes and models of cars· Young and Old · People and Cars · Street Cars to Street Machines · Motorcycles to Scooters · Rusty to Restored · Street Hacks to Show Cars · Push Bikes to Drag Cars · Bog Stock to Hot Rod · Primers to Candies · Vintage Caravans to Transporters.<br><br></span><strong><span>**7:30am meeting at Wilson Parking - Deakin Bowling Club, 50 Kent St,<span>7:50am</span>we''ll then cruise together to Deakin Stadium.**</span></strong></p><p><span>Hope to see you there!</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Deakin Stadium, 14 Hannah Pl, Deakin', '2023-11-11T20:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/marques-in-the-park-pic-1-a66545fd-16c957ba.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5417614, 'German Cars and Coffee Fundraising Event', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-cars-and-coffee-0b42cb94-2fca83da.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-cars-and-coffee-0b42cb94-c5168c04.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-cars-and-coffee-0b42cb94-c5168c04.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us, along with other German Car Clubs (<span>Audi, Mercedes-Benz, Porsche, and Volkswagen</span>) for German Cars n Coffee!</p><p>It’s sure to be a great morning. Enjoy meandering around German cars, catching-up with fellow club members while drinking a hot beverage or two. We suggest getting in early to secure a spot!</p><p>We will be doing a bit of fund raising at this one, by way of donations with a number of us rattling the can as we walk around. The cause is for a young local woman who requires spinal fusion surgery and subsequent rehabilitation, all being done in Sydney. All this comes at a cost and she will also need to fund her accommodation during the rehab for up to 12 weeks. There is a go fund me page with further info on Hannah and details of her condition and surgery:<span><span><a href="https://gofund.me/4d0f10ec" target="_blank" rel="noopener">https://gofund.me/4d0f10ec</a></span></span></p><p>This event is hosted by the<span>Volkswagen</span>Club.</p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Spanish Club, 5 Narupai Place, Narrabundah', '2023-11-18T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/german-cars-and-coffee-0b42cb94-c5168c04.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5401489, '2023 Annual General Meeting (AGM)', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-event-pic-v2-1308e6e9-fba4e798.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-event-pic-v2-1308e6e9-2bfcf02a.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-event-pic-v2-1308e6e9-2bfcf02a.webp" loading="lazy" alt="" title=""></picture><br></p><p>I am pleased to advise that the 2023 Annual General Meeting (AGM) of the BMW Car Club Canberra will be held at<strong>7:30 pm on Tuesday 21 November 2023 in the MacDonald Room (upstairs)</strong>at the Eastlakes Football Club, 3 Oxley Street in Kingston. While the meeting starts at 7.30pm,<span><strong>there will be complimentary hot snacks in the MacDonald Room from 7pm.</strong>Come along and take the opportunity to meet fellow members and influence the direction of your Club.</span></p><p><strong>The agenda for the AGM will be:</strong></p><ul><li>Confirmation of the minutes of the previous 2022 AGM (held November 2022)</li><li>President’s Report</li><li>Financial Report</li><li>Election of Committee (as per section 8 of the Constitution of the BMW Car Club Canberra)</li><li>General Business</li></ul><p>During the AGM, an election will take place to appoint the President and Committee for the 2023-2024 year. All current financial members are encouraged to nominate for committee positions which are listed below.</p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/bmw-car-club-canberra-committee-roles-and-responsibilities-3b912453-bdaefd47.pdf" target="_blank">BMW CAR CLUB CANBERRA - Committee Roles and Responsibilities</a><br></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/committee-nomination-form-bmw-car-club-canberra-tuesday-22-november-20-ec443f94-bb3b1264.pdf" target="_blank">Committee Nomination form BMW CAR CLUB CANBERRA</a></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/postal-voting-form-bmw-car-club-canberra-2023-4edb3d3c-42bdbeda.pdf" target="_blank">Postal voting form BMW CAR CLUB CANBERRA</a><br></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/proxy-form-bmw-car-club-canberra-2023-49bdc6a4-fe1a3862.pdf" target="_blank">Proxy form BMW CAR CLUB CANBERRA</a><br></p><p>Only financial members as at Tuesday 21 November 2023 are eligible to vote. If you are unable to attend the AGM, you may choose to nominate a proxy to vote on your behalf, submit a nomination or send a postal vote, however these must be lodged with the Secretary by emailing<a href="mailto:secretary@bmwclubcanberra.org.au">secretary@bmwclubcanberra.org.au</a>. You can also nominate on the night. If you wish to raise a notice of motion at the meeting, please email your motion to the Secretary by Monday 23 October 2023.</p><p><strong>Function Attendee Information for entering an Eastlake Group Venue</strong></p><p>There is free parking available, enter the carpark via the boom gate next to the club and make sure to validate your parking ticket at reception on your way out.</p><ul><li>All attendees must present to Reception on arrival.</li><li>Eastlake Members can present/show their members card to our Receptionist, and head into the function space.</li><li>Non-member attendees must present photo ID (licence/proof of age card preferred) to the Receptionist and be signed in, before heading to the function space.</li></ul><p>Please Note: When signed into the venue as an attendee of a function, please be aware you are excluded from using any of the venue’s gambling facilities (poker machines &amp; TAB).</p>I hope you can attend the AGM and look forward to your continued support and involvement in the activities of the BMW Car Club Canberra.<p>Regards</p><p>Lorna Kunz<br>Secretary<br>BMW Car Club Canberra<br>secretary@bmwclubcanberra.org.au</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Eastlakes Football Club, 3 Oxley Street Kingston', '2023-11-21T08:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-event-pic-v2-1308e6e9-2bfcf02a.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5228831, 'Challenge Bathurst Regularity with BMWDCM', '<p><br></p>BMW Drivers Club Melbourne (BMWDCM) has secured a 55 car regularity group for this two-day event on Saturday 25 November and Sunday 26 November and have invited us (BMWCCC) to join them!<p><span><span><span>This is a fantastic opportunity to tick off one of your bucket list items and drive on one of the best circuits in the world. You only need a level 2 or above Motorsport Australia licence, you don''t need to have a fully prepared race car, any vehicle that you use at a normal sprint day will be eligible as long as it is a BMW and passes scrutineering.</span></span></span></p><p><span><span><span>BMWDCM</span></span><span><span>will need volunteers to help run the Team.</span></span></span></p><p><span>They will also be needing volunteers for this event to flag marshal.<strong>Each volunteer gets free camping or free accommodation at the Uni for 4 nights.</strong>You will only need to volunteer for 2 days but if you wish to stay on, you are most welcome. As per all motorsport events, you will be fed and watered while at the track.<span><span>Please register for the</span></span><strong><em><span>Volunteer Only</span></em></strong><strong><span>registration.</span></strong></span></p><p><span><strong><span><span>*All details are published on BMWDCM</span></span></strong><strong><span><span>website along with registration (link below).</span></span>*</strong></span></p><a href="https://bmwdcm.com.au/event-5188653" target="_blank" rel="noopener"><span>https://bmwdcm.com.au/event-5188653</span></a><p><span>Pleas note:<span><span><span>This is<span><span>only</span></span>available to<span>current members</span>of invited Official BMW Affiliated Clubs.</span></span></span></span></p><p><span>Don’t miss out on this<span><span>fantastic opportunity – Register ASAP!</span></span></span></p>', 'Mount Panorama Motor Racing Circuit, Bathurst NSW', '2023-11-24T21:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5461383, 'Christmas and Presentation Dinner', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/amas-image-253fc029-ca2839ff.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/amas-image-253fc029-b7d31733.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/amas-image-253fc029-b7d31733.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>Join us for our<span>combined Christmas and Presentation dinner at</span></span><span>Golden King Restaurant, Dundas Court, Phillip.</span></p><p>We''ll be awarding the perpetual President’s Award, New Member of the Year Award and the inaugural Don Campbell Memorial trophy for Member of the Year. There will also be lucky door and raffle prizes, a silent auction and other prizes to be won, courtesy from our friends at Canberra BMW.</p><p>We have arranged for a set menu for $34 per head. The menu is:</p><p><span>Sweet corn chicken soup</span><br><span>Spring rolls</span><br><span>Spicy Chicken Wing</span><br><span>Beef with Cantonese sauce</span><br><span>Mongolian Beef</span><br><span>Fillet Steak Chinese style</span><br><span>Combination Satay</span><br><span>Boneless Chicken with Plum sauce</span><br><span>Fried rice &amp; Boiled rice</span><br><span>Tea</span><br></p><p>There is a children’s menu for those aged to 10 years consisting of an entrée, a main course and a dessert for $20.</p><p>If you have any dietary requirements, please email Yvonne that way we have your advice in writing and can confirm on the night. Please send an email to y_wise@hotmail.com or treasurer@bmwclubcanberra.org.au and cc lorna.e.kunz@gmail.com.</p><p>The restaurant is fully licenced but if you would like to bring a bottle of wine, they do charge $6 corkage per bottle.</p><p><strong><u>We need to confirm numbers by Thursday 30th November 2023</u>.</strong>Once we have confirmed numbers the Club will be billed for that number of people.</p><p><strong>Please transfer $34 per adult and $20 per child, directly into the Club’s bank account and email treasurer@bmwclubcanberra.org.au to advise.</strong><br><br>The Club account is:</p><p><strong>Name:</strong>BMW Car Club ACT Inc<br><strong>BSB:</strong>633000<br><strong>Account No:</strong>159596998</p><p><span>**<strong>If you find you are unable to attend, please let us know as soon as possible and prior to the 30th November 2023, in order for us to issue you a refund.**</strong></span></p><p>Join us for a fantastic dinner and relaxing evening. We''re very much looking forward to catching up with everyone!</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/x-mas-pic-2-6aa478ad-501af491.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/x-mas-pic-2-6aa478ad-8fb6e9e2.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/x-mas-pic-2-6aa478ad-8fb6e9e2.webp" loading="lazy" alt="" title=""></picture><br></p>', 'Golden King Restaurant, Dundas Court, Phillip.', '2023-12-02T07:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/amas-image-253fc029-b7d31733.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503145, 'Club Drive: Lunch Run/Sapphire Coast Car Club Visit', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pambula-7f98ec27-dc8cadfd.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pambula-7f98ec27-688629c5.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pambula-7f98ec27-688629c5.webp" loading="lazy" alt="" title=""></picture><br></p><p>To kick things off in 2024 please join us for what will be a sensational drive to Pambula on some truly great driving roads! Route details will be sent to registrants closer to the date.</p><p>We''ll also be visiting the Sapphire Coast Car Club (guided tour). They have an extensive facility including a mechanical workshop, panel shop, clubroom with kitchen and two pavilions housing club member''s vehicles (THE DREAM!). There is a $10 donation per person which includes tea/coffee.</p><p>To ensure we keep everyone together, we will be trialling a two group driving arrangement. We will need volunteers to lead each group and be "tail end Charlie" to the destination.</p><p>If you are interested in assisting with either of these roles can you please choose the relevant registration option. NOTE: There is an expectation that you keep an eye out for who is behind you. i.e. don''t get too far ahead of the rest of the group.</p><p>The club has CB radios that can be used however, we encourage everyone to have their own.</p><p>Looking forward to seeing you there!</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/southcoasthistoric-66a400d7-2d86184e.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/southcoasthistoric-66a400d7-1f374c38.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/southcoasthistoric-66a400d7-1f374c38.webp" loading="lazy" alt="" title=""></picture><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/27fb5fb5d4074b3d'||'ae21b23671751d53-1ef1b1c5-4533e25f.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/27fb5fb5d4074b3d'||'ae21b23671751d53-1ef1b1c5-64850b29.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/27fb5fb5d4074b3d'||'ae21b23671751d53-1ef1b1c5-64850b29.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>General Driver No responsibility necessary, enjoy the drive!</li><li>Group 1 - leader Lead the way for group one, the ''spirited'' group</li><li>Group 1 - tail end Charlie Bring up the back of group one, the ''spirited'' group</li><li>Group 2 - leader Lead the way for group two, the ''cruising'' group</li><li>Group 2 - tail end Charlie Bring up the back of group two, the ''cruising'' group</li></ul>', 'Pambula, NSW', '2024-01-05T21:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pambula-7f98ec27-688629c5.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5548567, 'Cars and Coffee', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/jan-21-cars-and-coffee-event-pic-d2fcae90-39809452.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/jan-21-cars-and-coffee-event-pic-d2fcae90-124fd821.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/jan-21-cars-and-coffee-event-pic-d2fcae90-124fd821.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for Cars and Coffee hosted by the Canberra Cars n Coffee Group.</p><p>It’s sure to be a great morning. Enjoy meandering around cars, catching-up with fellow club members while drinking a hot beverage or two.</p><p><strong>We''ll meet at the<a href="https://www.google.com/maps/dir//-35.2982336,149.1250057/@-35.2978293,149.1248232,207m/data=!3m1!1e3!4m2!4m1!3e0?entry=ttu" target="_blank" rel="noopener">Hyatt Hotel car park on Kaye St</a>(opposite Albert Hall) at 8:30am, then cruise to the event at 8:50am as a Club.</strong></p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Kuttabul Pl, Acton ACT (Meet at Hyatt Hotel Car Park on Kaye St)', '2024-01-20T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/jan-21-cars-and-coffee-event-pic-d2fcae90-124fd821.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5499861, '2024 Poker Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/poker-run-pic-2-ce4130b2-bc5958aa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/poker-run-pic-2-ce4130b2-e1c15d89.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/poker-run-pic-2-ce4130b2-e1c15d89.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for our first Poker Run for 2024.</p><p>For those of you that have not attended a Poker Run before, you collect a card at five different locations and the best hand wins a prize!!</p><p>This year’s Poker run will start at<strong>McDonalds Molonglo on Kirkpatrick Street</strong>(1st card) departing at 10.00am sharp. Travel out the Cotter Road and turn right onto Brindabella Road passing Uriarra Village and turn right onto Uriarra Road (2nd card). Continue on Uriarra Road which turns into Fairlight Road and turn right onto Mountain Creek Road. Turn right onto Wee Jasper Road (3rd card), turn right onto Yass Valley Way (4th card) and turn right at the second round about onto the Barton Highway. Lunch will be at the Murrumbateman Pub where you will collect the 5th card.</p><p><a href="https://www.google.com/maps/dir/McDonald''s,+14A+Kirkpatrick+St,+Weston+ACT+2611/Uriarra+Village+ACT/Taemas+Bridge,+Wee+Jasper+Road,+Cavan+NSW/Murrumbateman+Country+Inn,+Barton+Highway,+Murrumbateman+NSW/@-35.0926364,149.0768774,10.79z/data=!4m31!4m30!1m5!1m1!1s0x6b17b3cef387775f:0x1facf1ceda7779cb!2m2!1d149.0565663!2d-35.3219007!1m10!1m1!1s0x6b17b756e9570ab1:0x986e1bf240ab21e1!2m2!1d148.9248239!2d-35.2958618!3m4!1m2!1d148.9505731!2d-35.2463242!3s0x6b17b044ad88c3bd:0xb5c72a85ecb5bbf8!1m5!1m1!1s0x6b17097c34537751:0x55578e270a44532b!2m2!1d148.8481134!2d-35.003359!1m5!1m1!1s0x6b1704ebeabe1b13:0xad08436a4afa44aa!2m2!1d149.0299224!2d-34.9691963!3e0?entry=ttu" target="_blank" rel="noopener">Drive Route Here</a></p><p>We intend to be at the Murrumbateman Pub by 12.00-12.30 so for those that do not want to drive the windy bits, come and join us for lunch for a catch-up and a chat.</p><p><strong>Please bring your UFH/CB radio if you have one, we''ll have some club ones available to borrow if needed. We''ll also nominate a Lead Driver and a Tail-End Charlie on the day to assist with keeping the group together.</strong></p><p>Registration is essential for catering, We look forward to seeing you on the Poker Run!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Start at McDonalds Molonglo, Lunch at Murrumbateman Pub', '2024-01-27T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/poker-run-pic-2-ce4130b2-e1c15d89.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503123, 'SDMA Hillclimb: 4 February - One lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-02-03T20:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5464907, 'Shannons Wheels - Show & Shine 2024', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/shannons-wheels-show-shine-2024-event-pic-8b86fb6d-55f5bd41.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/shannons-wheels-show-shine-2024-event-pic-8b86fb6d-a6bdf860.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/shannons-wheels-show-shine-2024-event-pic-8b86fb6d-a6bdf860.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>Join us for<span><span><span>Shannons Wheels 2024</span>, the region''s biggest car event outside of Summernats! Please note the updated date.</span></span></span></p><p><span>The Shannons Wheels charity Car, Bike &amp; Truck show will be held at the Queanbeyan Showground on<strong>Sunday 18 February 2024</strong>.</span><span>The annual display is organised by the Council of ACT Motor Clubs for it''s 78 affiliated clubs.</span></p><p><span>The show features all types and marques of vehicles, from the early days of motoring right up to the latest generation of EVs.</span></p><p><span><span><strong>This year the show is celebrating the "Hot Hatch", so let’s see all those BMW Hot Hatches!! We''ll endeavour to have them all lined-up together.</strong></span></span></p><p><span><strong>As in previous years, the Shannons Wheels event will be raising funds for local charities (gold coin donation for entry).</strong></span></p><p>Food and drink will be available on site during the day, additionally, there are several options nearby on Kings Highway (Canberra Avenue). You could even bring a picnic lunch! There are also rest room facilities on site.</p><p>There is limited seating, so best to bring your own camp chair/mat. We''ll have the clubs marquees, you are most welcome to make use of them!</p><strong>If you have reregistered and are no longer able to attend, please let us know!</strong><p><span>Looking forward to seeing you there!</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/240218-wheels24-poster-5feb7e8d-87e3d27d.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/240218-wheels24-poster-5feb7e8d-e3e60d04.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/240218-wheels24-poster-5feb7e8d-e3e60d04.webp" loading="lazy" alt="" title=""></picture><br></span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Queanbeyan Showgrounds', '2024-02-17T21:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/shannons-wheels-show-shine-2024-event-pic-8b86fb6d-a6bdf860.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5591767, 'February Cars and Coffee', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/feb-cnc-event-pic-b92d0045-f537d297.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/feb-cnc-event-pic-b92d0045-c9d24d2d.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/feb-cnc-event-pic-b92d0045-c9d24d2d.webp" loading="lazy" alt="" title=""></picture><br></p><p>Whether you''re driving the Daily Driver, the Weekender, the Project Car or the Garage Queen, come and join us for Cars and Coffee hosted by the Canberra Cars n Coffee Group!</p><p>It’s sure to be a great morning. Enjoy meandering around cars and bikes, catching-up with fellow club members while drinking a hot beverage or two!</p><p><strong><span>Please note the new meet time (the event now starts at 8am) - Meeting at the<a href="https://www.google.com/maps/dir//-35.2982336,149.1250057/@-35.2978293,149.1248232,207m/data=!3m1!1e3!4m2!4m1!3e0?entry=ttu" target="_blank" rel="noopener">Hyatt Hotel car park on Kaye St</a>(opposite Albert Hall) at 7:30am, we''ll then cruise to the event at 7:40am SHARP as a Club.</span></strong></p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Kuttabul Pl, Acton ACT (Meet at Hyatt Hotel Car Park on Kaye St)', '2024-02-24T20:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/feb-cnc-event-pic-b92d0045-c9d24d2d.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503124, 'SDMA Hillclimb: 3 March - One lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-03-02T20:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5602343, 'Araluen Pub Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mg-2773-7c039072-17f06cf1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mg-2773-7c039072-0340c46f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mg-2773-7c039072-0340c46f.webp" loading="lazy" alt="" title=""></picture></p><p>Come and enjoy the picturesque Araluen Valley and some twisty bits along the way for a great little Autumn drive to Araluen Pub for lunch!</p><p>We will be departing Sutton Bakery at 10.00AM sharp via Shingle Way, Bungendore, Tarago (Pit Stop), Braidwood onto Araluen Pub for Lunch.<a href="https://www.google.com/maps/dir/Little+Sutton+Bakehouse,+Victoria+Street,+Sutton+NSW/-35.0850648,149.2526967/-35.2537201,149.4382076/Tarago+Community+Playground,+2124+Braidwood+Rd,+Tarago+NSW+2580/Braidwood+NSW/Araluen+Valley+Hotel,+Araluen+Road,+Araluen+Queanbeyan%E2%80%93Palerang+Regional+Council,+NSW/@-35.1941779,149.539258,56885m/data=!3m1!1e3!4m28!4m27!1m5!1m1!1s0x6b1657b7fb1de583:0x7dfc8007177d94ba!2m2!1d149.2529703!2d-35.1641454!1m0!1m0!1m5!1m1!1s0x6b1691da9ea10ceb:0x32c35d916ee7af68!2m2!1d149.6556095!2d-35.0679788!1m5!1m1!1s0x6b15d3117cb5021b:0x40609b490440720!2m2!1d149.7990648!2d-35.4460326!1m5!1m1!1s0x6b160ac1fca99d8f:0x7d880a00125ab59d!2m2!1d149.8133122!2d-35.6427985!3e0?entry=ttu" target="_blank" rel="noopener">Drive Route Here</a></p><p>Please bring your UFH/CB radio if you have one, we''ll have some club ones available to borrow if needed. We''ll also nominate a Lead Driver and a Tail-End Charlie on the day to assist with keeping the group together.</p><p>On the way home some of you may choose to explore Braidwood (especially the Braidwood model car shop ;) ) or Bungendore.</p><p>Please register for this event, as we need to advise the Araluen Pub for catering. Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Little Sutton Bakehouse (1 Victoria St, Sutton NSW)', '2024-03-23T22:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/mg-2773-7c039072-0340c46f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5679707, 'Convoy to Pheasant Wood circuit', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-9254-7e5dd920-43a91197.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-9254-7e5dd920-bc954dab.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-9254-7e5dd920-bc954dab.webp" loading="lazy" alt="" title=""></picture><br></p><p>Come join us for a convoy to the Pheasant Wood circuit. We will be meeting across the road from BP Watson on Antill Street @ 6:15am, leaving 6:30am.</p><p>Please register for this event so we know who to expect.</p><p>Looking forward to seeing you EARLY on Saturday.</p><p>Regards</p><p><span><span>BMW Car Club Canberra | Official BMW Club</span></span><br></p><p><span><span>BMW Car Club Canberra</span></span></p>', 'Pheasant Wood Circuit', '2024-04-05T19:15:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-9254-7e5dd920-bc954dab.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5531649, 'Pheasant Wood Circuit Track Day', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-eb62e6d3.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-80610a9f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-80610a9f.webp" loading="lazy" alt="" title=""></picture><br></p><p>Whether you''re a seasoned driver, weekend warrior or first-timer, come and join us for a fun day at our Pheasant Wood Circuit Track Day! All enthusiasts welcome, BMW or otherwise.</p><p>With an open pit lane format, you''ll have the time you need to perfect your driving. There will be dedicated beginner sessions and passenger laps (non-timed) also. Our fun and welcoming environment will ensure you have a great time.</p><p>To re-cap, there are some mandatory requirements to attend:</p><ul><li>Long sleeve cotton shirt, full length pants and enclosed footwear</li><li>Helmet (hire is available)</li><li>Motorsport (Motorsport Australia or AASA) or track (Pheasant Wood) licence: A day licence can be purchased for $30 @ the track. Note: Can be upgraded on the day to an annual licence for an additional $69</li></ul><p>There will be people available to help you get the best out of the day, sharpen your skills and give you some tips and get the best out of your track time.</p><p><strong>This will be a fully catered event - Your registration fee includes all lunch, snacks and drinks (water, soft drink, tea and coffee). Simply turn up and enjoy the day!</strong></p><p><strong>Gates open at 7:30am. Everyone MUST Arrive no later than 8:15am (to complete sign on). There will be a drivers briefing commencing at 8:45am. All drivers MUST attend and be ready to hit the track at 9:00am.</strong></p><p>On top of being an already impressive day, we will have awards for a number of categories as well.</p><p>NOTE: We will need volunteers to assist in the café area and admin duties. Volunteers will be provided with lunch, snacks, drinks, etc.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pic2-7c1dc79d-ad633fa5.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pic2-7c1dc79d-c55aab93.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pic2-7c1dc79d-c55aab93.webp" loading="lazy" alt="" title=""></picture><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/track-day-event-pic-5-a7a6a58d-8713b692.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/track-day-event-pic-5-a7a6a58d-f77d56a6.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/track-day-event-pic-5-a7a6a58d-f77d56a6.webp" loading="lazy" alt="" title=""></picture><br></p><p>Registrations are limited, be sure to register ASAP to avoid disappointment!</p><p>If you have any questions please don’t hesitate to ask. Further information will be sent out to registrants closer to the day.</p><p>Come and practice, test your car or just play for the day - We hope to see you there!!</p><h3>Registration</h3><ul><li>Member Registration – $300.00 Members pricePlease include the club name and your club member number.</li><li>Member''s Guest Drive Registration – $300.00 Members pricePlease include the club name and your club member number.</li><li>Non-Member registration – $350.00 Non-member pricing</li><li>Viewing Guest Registration – $25.00 This is for all participants that are attending to watch the day and wish to be catered for.Price includes, lunch, snack, drink, etc.</li><li>Volunteer Registration This is for volunteers that are coming to watch and assist with organising the day. this includes catering and admin duties for the day.As a volunteer you will be provide with lunch, snacks, drinks, etc.</li></ul>', 'Pheasant Wood Circuit, Marulan', '2024-04-05T20:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-80610a9f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503125, 'SDMA Hillclimb: 7 April - One lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-04-06T21:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5644228, 'Page Community Day', '<p><span><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/duncans-plumbing-6400119a-51ad11ba.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/duncans-plumbing-6400119a-73c396f0.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/duncans-plumbing-6400119a-73c396f0.webp" loading="lazy" alt="" title=""></picture><br></span></span></p><p><span><span>The Page Community Day brings together the local community and is hosted by Duncan''s Plumbing, the Page Men''s Shed, local businesses, and a range of small businesses from across Canberra.</span></span></p><p><span><span>This event is held a few times each year at the Page shops with a car club in attendance. The BMW Car Club Canberra have been invited to attend on April 13th! It will be a show n shine style of event and there will be prizes.</span></span></p><p><span><span>There will be a free BBQ, market stalls, live music and more. Of the market stalls there is a local chocolatier and a candle maker as well.</span><br></span></p><p><span>The Page Shopping Centre is one of those lovely little spots that are dotted around Canberra, filled with nice people, including our new members, Kym and Jason!</span></p><p><span>The event runs from 12:00pm – 3.00pm however, cars must arrive by 11:30am.</span></p><p><span><span>The event itself is free however, entry for cars in the show n shine will be $10, with all proceeds going to the Men''s Shed.</span><span><span>Please register if you would like to enter show and shine, spaces are limited.</span></span></span></p><h3>Registration</h3><ul><li>Page Community day – $10.00 Entry for car only. Bring as many people as you like along to the event.</li></ul>', 'Page Place, Page, ACT', '2024-04-13T01:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/duncans-plumbing-6400119a-73c396f0.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5513862, 'Driver Training: Skidpan Day', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-90a679bd-3e73a8d3.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-90a679bd-d34c36fe.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-90a679bd-d34c36fe.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>We are excited to announce our 1st driver training session for the year: The Skidpan at Sutton Road Driver Training Complex, Sunday 14 April 2024.</span></p><p><span>For those that aren''t familiar, the skidpan is a slippery circuit that replicates driving on snow/ice or hitting a patch of oil. It''s smooth concrete, water is applied to provide the slide..... Vehicle speeds are less than 50 km/h and as the<span>circuit</span>is so slippery, there is very little wear on tyres and very low risk. The fun factor is extreme as you attempt to control your car with little or no traction!</span></p><p><span><span><span>The Skidpan will help you to better understand your vehicle and car control in general, including what to do when there is understeer or oversteer.</span></span></span></p><p><span><span><span>This is a great learning event for everyone. We strongly encourage new drivers to come and learn more about their vehicle and for experienced drivers to refresh their skills and of course, have fun!</span></span></span><span>Skills learnt on the skidpan are invaluable and can save lives.</span></p><p>Some important things to note:</p><ul><li>No burnouts or black marks to be left on the skid pan</li><li>Suitable clothing and appropriate footwear (no thongs, open-toed shoes, or high heels).</li><li>There are noise limits…..Vehicles must not exceed a noise limit of 85db at 30 meters. Any road registered vehicle *should* be less than this.</li><li>Participants are solely responsible for any property damages.</li><li>There will be more experienced members there to help out. If you would like some assistance please come see us after the briefing.</li></ul><p>If you would like to take passengers you are more than welcome to.</p><p>There will be light refreshments and tea/coffee facilities as well. We recommend bringing lunch with you however, if you need to buy lunch Queanbeyan is only a few minutes drive away....</p><strong>*Drivers briefing will be at 8:15am sharp. The fun begins at 8:30*.</strong><p><span>NOTE: We''ve put together special pricing for everyone. $120 ($140 for non-members) is per vehicle with multiple drivers allowed, for the ENTIRE day. Places are limited, register early to avoid disappointment!</span></p><p><span>We are looking forward to seeing you there and most of all have FUN!</span></p><h3>Registration</h3><ul><li>April Skidpan Day - Member Price – $120.00 Official BMW Club Member Price.Participants may share a car, however it is $120 per car to book a place on the day.</li><li>April Skidpan Day - Non-Member Price – $140.00 Non-Member Price.Participants may share a car, however it is $140 per car to book a place on the day.</li></ul>', 'Sutton Road Driver Training Complex', '2024-04-13T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-90a679bd-d34c36fe.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5578765, 'Wheels of Wamboin 2024 - 10th Anniversary Show', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-event-plug-2024-f728ed40-fb4ea7dd.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-event-plug-2024-f728ed40-aaa7289f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-event-plug-2024-f728ed40-aaa7289f.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for Wheels of<span><span>Wamboin</span></span>2024 to celebrate the<span>10th Anniversary of the show!</span></p><p><span>Wheels of Wamboin is a motoring enthusiasts'' event with vintage, classic and street machines - from Model ''T''s to Tesla and everything in between!</span></p><p><span>The Wamboin Home Produce Market will also be on (Wamboin Community Hall, next to Wamboin Oval ). There will be a v</span><span>ariety of stalls, including lots of fresh fruit &amp; vegies, healthy juices, coffee, egg &amp; bacon rolls, jewellery, cards, lollies, dried fruits &amp; nuts, cakes, sausage rolls, quiches, craft, knitting, preserves, and more!<strong>Hot Tip: Bring cash! $</strong></span></p><p><span><span>So, bring your automotive marvel, have a great coffee, grab an egg and bacon roll and enjoy meandering around some awesome cars!</span></span></p><p><span><span><strong><span><strong><span>Meet at<a href="https://www.google.com/maps/place/McDonald''s+Queanbeyan/@-35.3495486,149.2389269,17z/data=!3m1!4b1!4m6!3m5!1s0x6b164efd4f2f8941:0x705a5c253d85ee7b!8m2!3d-35.3495486!4d149.2415018!16s%252Fg%252F1thztz8s?entry=ttu" target="_blank" rel="noopener">McDonald''s Queanbeyan</a>at 8:00am, then cruise to the show at 8:10am sharp as a Club.</span></strong></span></strong><br></span></span></p><p><span>Venue: Wamboin Oval - off Norton Road (adjacent to the Wamboin Community Hall)</span></p><p><span>The show starts from 09:00am and goes to approx. 1:00pm</span></p><p><span><strong>Entry: Gold coin donation - proceeds to Wamboin RFS</strong></span></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-event-plug-2024-2-2b963941-a667d556.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-event-plug-2024-2-2b963941-d26315b2.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-event-plug-2024-2-2b963941-d26315b2.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Meeting at McDonald''s Queanbeyan', '2024-04-19T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-event-plug-2024-f728ed40-aaa7289f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5692434, 'BMW / Porsche Challenge & BMW Supersprint SS.3', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-porsche-challenge-event-pic-b7414d77-965c93f4.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-porsche-challenge-event-pic-b7414d77-2a07c31b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-porsche-challenge-event-pic-b7414d77-2a07c31b.webp" loading="lazy" alt="" title=""></picture><br></p><p><span>BMW Drivers Club NSW have invited us (BMWCCC) to join in on the fun at their<span><span>annual BMW / Porsche Challenge!</span></span></span></p><p><span><span>The aim is for 60 BMWs and 60 Porsches enjoying this Supersprint challenge.</span></span></p><p><span><strong><span>PLEASE NOTE: This event is organised by our friends at BMW Club NSW. Registrations and</span><span>all information can be found below.<a href="https://bmwclubnsw.asn.au/event-5546571" target="_blank" rel="noopener">bmwclubnsw.asn.au/event-5546571</a></span></strong></span></p><p><span><em>This invite is a place holder/reminder in our (BMWCCC) calendar. By registering via this invite, you ARE NOT<span>registering for the</span><span><span><span>BMW Porsche Challenge</span></span>and or the<span><span><span>SuperSprint.</span></span></span></span></em></span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Sydney Motorsport Park - Gardner Circuit', '2024-05-04T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-porsche-challenge-event-pic-b7414d77-2a07c31b.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503126, 'SDMA Hillclimb: 5 May - One lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-05-04T21:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5679174, 'Southern Highlands Social Drive', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/e654e666b7fd49db'||'af391bf58071ebe5-4508e93e-f85c0006.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/e654e666b7fd49db'||'af391bf58071ebe5-4508e93e-ee3e6aa5.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/e654e666b7fd49db'||'af391bf58071ebe5-4508e93e-ee3e6aa5.webp" loading="lazy" alt="" title=""></picture></span></p><p><span><span>Join in for a drive to the Southern Highlands for lunch, followed by a drive to the stunning Kangaroo Valley!</span><br></span></p><p>We are excited to announce our first co-club social drive and lunch as we are teaming up with our BMWDC mates from NSW! This is a great opportunity to make new friends, see some new wheels, enjoy some fun roads, and grab a delicious pub lunch in Berrima.</p><p><strong>Lunch venue:</strong>The Surveyor General Inn, 26 Old Hume Hwy, Berrima<br></p><p>This venue is the perfect place for a cozy lunch in the Southern Highlands as it was built in 1834. We''ve secured a function room that will comfortably sit our groups. Simply order what you like from the menu at the ordering counter, and purchase drinks on consumption from the bar.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-3-2238a137-5e65b600.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-3-2238a137-1d020aae.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-3-2238a137-1d020aae.webp" loading="lazy" alt="" title=""></picture><br></p><p><strong>After lunch drive</strong></p><p>After our delicious lunch, we will burn off some calories by driving from Berrima down into the stunning Kangaroo Valley. Once we arrive in the valley we will take some more photos of our group and the vehicles, before farewelling our new friends.</p><p>Important - Bring your winter woolies, it will be chilly at this time of year in the Southern Highlands!</p><p><strong>Important notes:</strong><br></p><ol><li>The exact meet location for ACT members and time will be provided to registered attendees one week prior to the event.</li><li>5 watt CB radios are highly recommended for use, so drivers are aware of upcoming turns and potential hazards. The club will offer a few radios on the day for loan, however we recommend our regular attendees purchase their own.</li><li>Cancellations can be made through the event via your login on the club website. This will allow someone who is on the waitlist to join us on the drive.</li></ol><p>Looking forward to see you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Berrima, Southern Highlands', '2024-05-17T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/e654e666b7fd49db'||'af391bf58071ebe5-4508e93e-ee3e6aa5.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5741291, 'May Cars and Coffee', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-1716332808672-7198821564751953013-94218b9c-29b0e66d.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-1716332808672-7198821564751953013-94218b9c-fd5d7586.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-1716332808672-7198821564751953013-94218b9c-fd5d7586.webp" loading="lazy" alt="" title=""></picture><br></p><p>Whether you''re driving the Daily Driver, the Weekender, the Project Car or the Garage Queen, come and join us for Cars and Coffee hosted by the Canberra Cars n Coffee Group!</p><p>It’s sure to be a great morning. Enjoy meandering around cars and bikes, catching-up with fellow club members while drinking a hot beverage or two!</p><p><strong><span>**Meeting at the<a href="https://www.google.com/maps/dir//-35.2982336,149.1250057/@-35.2978293,149.1248232,207m/data=!3m1!1e3!4m2!4m1!3e0?entry=ttu" target="_blank" rel="noopener">Hyatt Hotel car park on Kaye St</a>(opposite Albert Hall) at 7:30am, we''ll then cruise to the event at 7:40am SHARP as a Club.</span></strong></p><p>Looking forward to seeing you there and apologies for the short notice!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Kuttabul Pl, Acton ACT (Meet at Hyatt Hotel Car Park on Kaye St)', '2024-05-25T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-1716332808672-7198821564751953013-94218b9c-fd5d7586.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503127, 'SDMA Hillclimb: 2 June - Two lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-06-01T21:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5702014, 'Christmas in July Lunch', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/the-royal-event-pic-defbfede-cd5a55aa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/the-royal-event-pic-defbfede-c491bf6d.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/the-royal-event-pic-defbfede-c491bf6d.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>Join us for Christmas in July Lunch at The Royal Hotel Bungendore.</span></p><p><span>Promising good music, cold beer and good times, the Royal Hotel Bungendore offers wallet-friendly, old-fashioned pub fare alongside signature hospitality.</span></p><p><span><span>The<a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/royal-menu-07-04-24-254451f0-2a5f4c87.webp" target="_blank">menu</a>changes regularly but there will be roasts and the classic pub style meals available. There are also vegetarian, gluten-free and children''s<br>meals available.</span><br></span></p><p><span>There’s also an epic children’s playground area just down the road – perfect for the little ones to burn off some energy!</span></p><p><strong>We have reserved seating, so don’t delay in reserving your seat/s!</strong></p><p><strong>NOTE: If you have registered and are no longer able to attend, please cancel your registration so others can attend.</strong></p><p><span>For those interested, we’ll be arranging a Club drive to Bungendore taking the back roads. Drive route and details provided closer to the date.</span></p><p><span>*If you are planning to drink alcohol, please ensure that you drink responsibly!</span></p><h3>Registration</h3><ul><li>Christmas in July Lunch at The Royal Hotel Bungendore If you have registered and are no longer able to attend, please cancel your registration so others can attend.</li></ul>', 'The Royal Hotel Bungendore, 34 Gibraltar St, Bungendore', '2024-07-07T02:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/the-royal-event-pic-defbfede-c491bf6d.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5513926, 'Driver Training: Skidpan Day', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-2-5aacbf7f-fe01c399.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-2-5aacbf7f-3112a92a.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-2-5aacbf7f-3112a92a.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>We are excited to announce our 2nd driver training session for the year: The Skidpan at Sutton Road Driver Training Complex, Sunday 21 July 2024.</span></p><p><span>For those that aren''t familiar, the skidpan is a slippery circuit that replicates driving on snow/ice or hitting a patch of oil. It''s smooth concrete, water is applied to provide the slide..... Vehicle speeds are less than 50 km/h and as the<span>circuit</span>is so slippery, there is very little wear on tyres and very low risk. The fun factor is extreme as you attempt to control your car with little or no traction!</span></p><p><span><span><span>The Skidpan will help you to better understand your vehicle and car control in general, including what to do when there is understeer or oversteer.</span></span></span></p><p><span><span><span>This is a great learning event for everyone. We strongly encourage new drivers to come and learn more about their vehicle and for experienced drivers to refresh their skills and of course, have fun!</span></span></span><span>Skills learnt on the skidpan are invaluable and can save lives.</span></p><p>Some important things to note:</p><ul><li>No burnouts or black marks to be left on the skid pan</li><li>Suitable clothing and appropriate footwear (no thongs, open-toed shoes, or high heels).</li><li>There are noise limits…..Vehicles must not exceed a noise limit of 85db at 30 meters. Any road registered vehicle *should* be less than this.</li><li>Participants are solely responsible for any property damages.</li></ul><p>There will be more experienced members there to help out. If you would like some assistance please come see us after the briefing. If you would like to take passengers you are more than welcome to.</p><p><strong>Kerbside Coffee will be in attendance serving up some delicious coffee!</strong></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/kerbside-coffee-pic-v2-676c2104-7ae00822.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/kerbside-coffee-pic-v2-676c2104-1093dd23.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/kerbside-coffee-pic-v2-676c2104-1093dd23.webp" loading="lazy" alt="" title=""></picture><br></p><p>We recommend bringing lunch with you however, if you need to buy lunch Queanbeyan is only a few minutes drive away....</p><strong>*Drivers briefing will be at 8:15am sharp. The fun begins at 8:30*.</strong><p><span>NOTE: We''ve put together special pricing for everyone. $120 ($140 for non-members) is per vehicle with multiple drivers allowed, for the ENTIRE day. Places are limited, register early to avoid disappointment!</span></p><p><span>We are looking forward to seeing you there and most of all have FUN!</span></p><h3>Registration</h3><ul><li>July Skidpan Day - Member Price – $120.00 Official BMW Club Member Price.Participants may share a car, however it is $120 per car to book a place on the day.</li><li>July Skidpan Day - Non-Member Price – $140.00 Non-Member Price.Participants may share a car, however it is $140 per car to book a place on the day.</li></ul>', 'Sutton Road Driver Training Complex', '2024-07-20T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-2-5aacbf7f-3112a92a.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5766714, 'BMW Cars and Coffee', '<p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/yellow-and-white-modern-we-are-hiring-facebook-post-20240717-164637-0000-c2871922-2eb26979.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/yellow-and-white-modern-we-are-hiring-facebook-post-20240717-164637-0000-c2871922-99188c07.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/yellow-and-white-modern-we-are-hiring-facebook-post-20240717-164637-0000-c2871922-99188c07.webp" loading="lazy" alt="" title=""></picture>Join us for freshly brewed coffee by our friends from Brenda’s Batch and Brew while surrounded by an impressive line-up of BMW vehicles. Toasties (ham, cheese &amp; tomato) ham cheese croissants and baked treats also available!</p><p>In addition to savouring the finest coffee and mingling with fellow enthusiasts, you''ll also have the exciting opportunity to be treated to a thrilling showcase as members take to the Skidpan to demonstrate their driving skills and finesse behind the wheel!</p><p>Note: Only people registered for the Skidpan will be able to take their car on the Circuit.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-cars-and-coffee-event-tisc-c979efcb-ab0a2516.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-cars-and-coffee-event-tisc-c979efcb-cda4555d.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-cars-and-coffee-event-tisc-c979efcb-cda4555d.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Sutton Road Training Centre, 441 Sutton Rd', '2024-07-20T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/yellow-and-white-modern-we-are-hiring-facebook-post-20240717-164637-0000-c2871922-99188c07.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5741378, '7th Skyline Day 2024 - Show & Shine', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-boomer-bmw-nissan-wallpaper-preview-d6ccff3b-168307b1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-boomer-bmw-nissan-wallpaper-preview-d6ccff3b-ef66fdeb.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-boomer-bmw-nissan-wallpaper-preview-d6ccff3b-ef66fdeb.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>The Heritage Nissan Canberra Region Club has invited us to join them for their annual Show &amp; Shine.</span></p><p><span><strong>Open to all makes and models,</strong>from sleek sports cars to rugged 4x4s, and everything in between. Whether you''re driving a Nissan, BMW, or any other brand, you''re invited to join us for the day.</span></p><p><span>2024 marks the 4th consecutive year and for this years event they will be at a new location, with the SDMA Committee graciously opening the pits and track for the static display, get ready to be part of this automotive extravaganza!</span></p><p><span><strong>Vehicle Entry: $10<br>Spectators: Cold Coin</strong></span></p><p><span>Food:</span></p><p><span>Indulge in delicious offerings from a variety of local food and beverage vendors. You can expect Bacon and Egg rolls, Cheese Burgers, Hot dogs, a variety of pizza flavours, coffee, and a wide selection of other drinks. They will provide updates via social media in the coming days about the vendors of choice for 7th Skyline Day.</span></p><p><span><strong><span>**Meeting at McDonald''s Queanbeyan at 9:00am, we''ll then cruise to the event at 9:15am SHARP as a Club.**</span></strong><br></span></p><p><span>Please note:</span></p><p><span>Let''s keep the event enjoyable for everyone. They kindly ask guests to operate their vehicles responsibly. Hooning, excessive engine revving, and antisocial behaviour will not be tolerated.</span></p><p><span>All makes and models are welcome! Don''t miss out on this incredible gathering of automotive enthusiasts. See you there!</span></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1716335037531-63a90ccc-3c25add7.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1716335037531-63a90ccc-d646e90f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fb-img-1716335037531-63a90ccc-d646e90f.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Southern District Motorsport Association Hillclimb Track, Sutton Road', '2024-07-27T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-boomer-bmw-nissan-wallpaper-preview-d6ccff3b-ef66fdeb.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5814715, 'Friday Night Feast & Cruise', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-2023-06-05-160553-2390360b-77400191.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-2023-06-05-160553-2390360b-ada3e640.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-2023-06-05-160553-2390360b-ada3e640.webp" loading="lazy" alt="" title=""></picture><br></p><p>Rev your engines, bring your appetite and join us for a fun Friday evening!</p><p>**6:00 PM:** Meet &amp; Grease – Roll into<span>Brodburger Woden</span>for a meet-and-greet. Enjoy their legendary burgers while swapping car stories and admiring each other’s rides.</p><p>**7:00 PM:** The Great BMW Chase – After dinner, we’ll hit the road for a scenic cruise to Redhill. Enjoy the ride and the camaraderie as we take in the sights and sounds of our beautiful city. We''ll be sure to get some epic night shots of our cars.</p><p>**8:00 PM:** Sweet Endings – Our journey concludes with dessert at Gelato Messina, in Kingston. Treat yourself to a delicious end to the evening! See below on where to park.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/park-here-for-gelato-messina-in-kingston-8036e3ad-273ef5d8.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/park-here-for-gelato-messina-in-kingston-8036e3ad-80243aec.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/park-here-for-gelato-messina-in-kingston-8036e3ad-80243aec.webp" loading="lazy" alt="" title=""></picture><br></p><p><strong>Locations and drive route<a href="https://www.google.com/maps/dir/Brodburger,+91+Hindmarsh+Dr,+Phillip+ACT+2606/Red+Hill+Lookout,+Red+Hill+ACT/Gelato+Messina+Kingston/@-35.3331876,149.1156086,4555m/data=!3m1!1e3!4m30!4m29!1m15!1m1!1s0x6b17b5dd9877456f:0x115f8e1085c4dd17!2m2!1d149.086492!2d-35.3491459!3m4!1m2!1d149.0853742!2d-35.3511514!3s0x6b17b4be96b0f0eb:0x3852491a1ac3bea0!3m4!1m2!1d149.1270557!2d-35.3470936!3s0x6b164b5ff901c519:0xfbb939eb1dd97b3e!1m5!1m1!1s0x6b164cb7db6597d5:0xbda80f29a53593c!2m2!1d149.1138234!2d-35.3240926!1m5!1m1!1s0x6b164d929bb1871f:0xfd7f9e7cf6636ca!2m2!1d149.1424097!2d-35.316446!3e0?entry=ttu" target="_blank" rel="noopener">here</a></strong></p><p>Hope to see you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Brodburger Woden, 91 Hindmarsh Dr, Phillip', '2024-08-02T08:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-2023-06-05-160553-2390360b-ada3e640.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503128, 'SDMA Hillclimb: 4 August - One lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-08-03T21:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5799442, 'Cookies Cycles Annual Fish And Chip Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bimmers-in-the-bay-0d84717c-ffac80ab.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bimmers-in-the-bay-0d84717c-49aa6f56.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bimmers-in-the-bay-0d84717c-49aa6f56.webp" loading="lazy" alt="" title=""></picture><span><span><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/blue-white-modern-bold-charity-event-flyer-1-3e3f640e-a240d1b9.pdf" alt="" title="" loading="lazy"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/blue-white-modern-bold-charity-event-flyer-1-3e3f640e-a240d1b9.pdf" alt="" title="" loading="lazy"></span></span></p><p><span>Join us for the 3rd year in a row, along with the Volkswagen Club for Cookies Cycles annual Fish N Chip run to Corrigans Beach, Batemans Bay.</span></p><p><span><span>The Fish n Chip Run is a fundraiser for</span><a href="https://www.campquality.org.au/" target="_blank" rel="noopener"><span>Camp Quality</span></a><span>, an Australian children’s cancer charity improving the quality of life for kids facing cancer for 40 years.</span><br><span>All funds raised during the run will go towards the fundraising by the Cookies Cycles Cruisers Team who are participating in the 2024 Super Heroes Classic Cruise on September 8th.</span></span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20230820-005548749-mp-2-92ebd71c-c731afee.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20230820-005548749-mp-2-92ebd71c-a0fce7ef.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20230820-005548749-mp-2-92ebd71c-a0fce7ef.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span><span><span>7:30am meetup in front of Old Parliament House, 8:00am departure to cruise the Kings Highway to the Coast</span></span>. We’ll be stopping in at Braidwood for a coffee and then meeting the South coast guys at Nelligen pub, before continuing to Corrigans Beach for lunch. Corrigans Beach also has a big playground to keep the kids entertained, toilet amenities, covered eating areas and<span><span>shops nearby</span><span>.</span></span></span></p><p><span>Its a get-together for anyone interested in cars and those who enjoy a cruise and a good day out.</span><span>Looking forward to seeing you there!</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20230820-003941331-2-b4626215-2afa4878.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20230820-003941331-2-b4626215-c8adf086.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20230820-003941331-2-b4626215-c8adf086.webp" loading="lazy" alt="" title=""></picture><br></span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Old Parliament House (Meet Location) > Corrigans Beach, Batemans Bay.', '2024-08-24T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bimmers-in-the-bay-0d84717c-49aa6f56.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5861015, 'Convoy to SuperFest!', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/superfest-website-banner-superfest-v3-main-ea737762-bf94a5ca.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/superfest-website-banner-superfest-v3-main-ea737762-0b75fe1e.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/superfest-website-banner-superfest-v3-main-ea737762-0b75fe1e.webp" loading="lazy" alt="" title=""></picture><br></p><p>SuperFest is this Sunday! For those of you that are planning to drive up on the day, we thought it would be a great to have a convoy. If you haven''t registered to be in the show and shine and you want to be included, it is highly recommended that you do so ASAP to assist in planning for the show. It is cheaper than registering on the day ;)</p><p>If you are planning to join in the show and shine, all cars need to be parked by 10:30. You will note this is a 6:00am meet..... Trappers bakery in Goulburn will be a must stop for caffeine!</p><p>We will need volunteers to lead the group and be "tail end Charlie" to the destination. Depending on the number of cars planning to attend, we may need to have 2 groups</p><p>If you are interested in assisting with either of these roles can you please choose the relevant registration option. NOTE: There is an expectation that you keep an eye out for who is behind you. i.e. don''t get too far ahead of the rest of the group.</p><p>We encourage everyone to bring their CB radio to keep in contact.</p><p>Looking forward to seeing you there!</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/27fb5fb5d4074b3d'||'ae21b23671751d53-1ef1b1c5-4533e25f.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/27fb5fb5d4074b3d'||'ae21b23671751d53-1ef1b1c5-64850b29.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/27fb5fb5d4074b3d'||'ae21b23671751d53-1ef1b1c5-64850b29.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>General Driver No responsibility necessary, enjoy the drive!</li><li>Group 1 - leader Lead the way for group one</li><li>Group 1 - tail end Charlie Bring up the back of group one</li><li>Group 2 - leader Lead the way for group two</li><li>Group 2 - tail end Charlie Bring up the back of group two</li></ul>', 'Sydney Motorsport Park, Eastern Creek', '2024-09-07T20:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/superfest-website-banner-superfest-v3-main-ea737762-0b75fe1e.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503129, 'SDMA Hillclimb: 8 September - One lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-09-07T21:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5546673, 'BMW SuperFest 2024', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/superfest-website-banner-superfest-v3-main-ea737762-bf94a5ca.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/superfest-website-banner-superfest-v3-main-ea737762-0b75fe1e.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/superfest-website-banner-superfest-v3-main-ea737762-0b75fe1e.webp" loading="lazy" alt="" title=""></picture></span></p><p><span>BMW Drivers Club NSW is hosting Australia''s largest BMW event of 2024! Join us at the famous Sydney Motorsport Park at Eastern Creek for a spectacular combination of their annual car show and round 6 of the SuperSprint motorsport challenge series.</span></p><p><span>They''ve secured the prestigious GP Gardner Circuit for motorsport competitors, and the areas surrounding the racetrack for the car show. Entrants and spectactors can expect a full program including:</span></p><ul><li><span><span><strong>Over 250 BMWs on Display</strong>at the IGL Coatings ''Show N Shine'' and our separate ''Official Judged Category Vehicles''.</span></span></li><li><span><span><strong>Motorsport Action</strong>at the EUROWERKE SuperSprint Rnd 6 as our competitors tackle the GP Gardner Circuit.</span></span></li><li><span><span><strong>Parade Laps</strong>- car show entrants can take part in parade laps around the official track after the awards presentation ceremony.</span></span></li><li><span><span><strong>Rare BMWs on display -</strong>Have you ever seen a BMW Z8, or a BMW Art car in person? Now is your chance.</span></span></li><li><span><span><strong>Trade Stands -</strong>explore various trade stands with demonstrations and products for sale.</span></span></li><li><span><span><strong>Official BMW Lifestyle Merchandise</strong>will be available for purchase, as well as event-specific merchandise.</span></span></li></ul><p><span>It''s free entry for event spectators so don''t miss out - register now and be part of the ultimate BMW experience in Australia!</span></p><p><span><strong><span><span><span>Registrations and</span></span><span><span><span>all information can be found on the BMW SuperFest event page:</span></span><a href="https://www.bmwclubnsw.asn.au/event-5476871" target="_blank" rel="noopener"><span><span>https://www.bmwclubnsw.asn.au/event-5476871</span></span></a></span></span></strong></span></p><p><span><span><span><span><span><strong><span><span><span>R</span>egistrations for the Eurowerke SuperSprint round 6 on the Gardner GP Circuit are open now!</span></span></strong>To register for the SuperSprint on the day of the SuperFest, please access the event<a href="https://www.bmwclubnsw.asn.au/event-5546625" target="_blank" rel="noopener"><span><span><strong>here.</strong></span></span></a></span></span></span></span></span></p><p><span><span><span><span><span><span><span><strong><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/smsp-70ea8e45-5821a2cd.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/smsp-70ea8e45-5d60d0eb.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/smsp-70ea8e45-5d60d0eb.webp" loading="lazy" alt="" title=""></picture><br></strong></span></span></span></span></span></span></span></p><p><span><strong><span><span><span>For those interested, we''ll be organising a convoy up and back! Details will be sent closer to the date :)</span></span></span></strong></span></p><p><span><span><em>This invite is a place holder/reminder in our (BMWCCC) calendar. By registering via this invite, you ARE NOT<span><span>registering for the</span></span><span><span>Show n Shine and the<span><span><span><span>SuperSprint.</span></span></span></span></span></span></em></span></span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Sydney Motorsport Park, Eastern Creek', '2024-09-07T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/superfest-website-banner-superfest-v3-main-ea737762-0b75fe1e.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5838338, 'Volunteers Needed: German Auto Day 2024', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-cc894e50.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp" loading="lazy" alt="" title=""></picture><br></span></p><p>German Auto Day 2024 promises to be a spectacular event! As the organizing club this year, we need your help to make everything run smoothly.</p><p>We are seeking volunteers to assist with various tasks, including our club setup, judging our Show and Shine, and overall event management.</p><p>No prior experience in judging is required, though an eye for detail will be beneficial. For those new to judging, we will provide guidance before you start. If you are participating in the Show and Shine, you can still volunteer as a judge, but you will be assigned to a different category than the one your car is entered in.</p><p>Rest assured, there will be ample support and assistance available throughout the event. If you have any questions or need more information, please feel free to reach out. Further details will be sent to volunteers closer to the date.</p><p>Thank you for your support!</p><h3>Registration</h3><ul><li>BMWCCC Display Volunteer Assistance with setting up/down the club marquee/banners and lining up BMW cars.</li><li>BMWCCC Show and Shine Judge No experience necessary! This is a great opportunity to learn not only about judging, it will also provide you with insight as to what you can do to prepare your car for future events.</li><li>GAD Event Volunteer Assisting with directing entrant traffic on where to park in the venue. Assisting with Vendor placement/enquires. Other tasks that may arise.</li></ul>', 'Thoroughbred Park, Lyneham', '2024-09-21T21:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503089, 'German Auto Day 2024', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-3860-e80d8069-47fcda92.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-3860-e80d8069-e21253c7.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-3860-e80d8069-e21253c7.webp" loading="lazy" alt="" title=""></picture><br></span></p><span>Join us for German Auto Day (GAD) 2024, as it returns to the Canberra region at the picturesque location of Thoroughbred Park.</span><p><span>GAD is a one day German automotive display event held each year in the Canberra region and is a collaboration event organised by local German branded marques, Audi, BMW, Mercedes Benz, Porsche, Volkswagen and other rare marques.</span></p><p><span>2024 will see some special prizes introduced, including best display! This will not be car or model specific and there will be prizes for best dressed! Get your thinking caps on and get creative!</span></p><p><span><strong>General Entry will be $10, of which $5 goes to charity. We will also be holding the Clubs annual Show ''n'' Shine - BMWCCC Members Entry – $20.00 (entry fee goes towards trophies and event costs). NOTE: Show ''n'' Shine entries close Wednesday, 18 September to ensure judges have time to prepare.</strong></span></p><p><strong><span>**Please respond to the invitation so that adequate parking spaces can be secured.<strong>If you have registered and are no longer able to attend, please cancel your registration so others can attend**.</strong></span></strong></p><p><span>There will be plenty to do and see for the whole family - Food, coffee and activities to keep the kids entertained!</span></p><p><strong>IMPORTANT EVENT DETAILS BELOW</strong><br></p><p><span><strong>Day of event</strong></span></p><p><span>On the day of GAD, entrants can start arriving on site from 8:00am and to be in place before 9:30am on Sunday, 22 September 2024. We suggest getting in early to avoid access chaos.</span></p><p><span><strong>Entry to the venue for ALL vehicles is 1 Randwick Road, Lyneham</strong></span><strong>. Everyone will need to follow directions from Marshals as they enter the venue.</strong></p><p><span>Food and drink will be available on site during the day. Bring the family, for those not interested in cars the handmade markets are on at Exhibition Park just down the road.</span></p><p><strong>For the Kids</strong></p><p>There will be providing kids entertainment, including a jumping castle!</p><p><span>There are rest room facilities on site.</span><span>What happens if the weather is bad? We''ll make that call closer to the day.</span></p><p><span><strong>Parking</strong></span></p><p><span>There will be limited onsite parking for parking for persons with a disability and trailers. Please enter through the main venue entry and advise the traffic control officer of your requirements.</span></p><p>Looking forward to seeing you there!</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-1-98523b95-9fc0203b.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-1-98523b95-d0e884cb.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-1-98523b95-d0e884cb.webp" loading="lazy" alt="" title=""></picture><br></p><p><br></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture></span><br></p><h3>Registration</h3><ul><li>German Auto Day - Display Only – $10.00 Please respond to the invitation so that adequate parking spaces can be secured. If you have registered and are no longer able to attend, please cancel your registration so others can attend.</li></ul>', 'Thoroughbred Park, 1 Randwick Rd, Lyneham', '2024-09-21T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-3860-e80d8069-e21253c7.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503130, 'SDMA Hillclimb: 29 September - One lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-09-28T21:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503112, 'Distinguished Gentleman’s Drive 2024', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-7d3d6ca1.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-f309c37f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-f309c37f.webp" loading="lazy" alt=""></picture><br></p><p>We are proud to be hosting the Distinguished Gentleman’s Drive for the third time in Canberra!</p><p>NOTE: Despite the name, this is open for men and women to enter. It''s sure to be a sensational event, one we can all enjoy and support a great cause. Bring a partner if you like and dress dapper!</p><p>An extremely well-run organisation, we’re looking forward to continuing to grow this event.</p><p>The Distinguished Gentleman''s Drive is a celebration of classic style. It is an on-road motoring event, uniting pre-80s designed classic cars, encouraging drivers and passengers around the world to dress dapper and drive for men''s health. All funds raised are invested in vital research and programs for prostate cancer and men''s mental health by Movember.</p><p>For those interested I would encourage you to come join us. As the third time in the region, we really would like to see some participation to raise awareness.</p><p>To join in the drive and be in the running for fundraising rewards, register at<a href="http://www.gentlemansdrive.com/" target="_blank" rel="noopener">www.gentlemansdrive.com</a>and select the Canberra event. In addition, please register for the club event for our own records.</p><p>Important Information:</p><p>- The event is strictly for pre-80’s cars (built on or before December 31st, 1979)</p><p>- Registration are opened and required for participation</p><p>- Drive details are available on the website to registered drivers</p><p>- Local drive details are to remain confidential, do not share them</p><p>- Dress in-theme and visit our website for information prizes and rewards for 2024</p><p>- Follow the official Gentleman''s Drive pages on Facebook and Instagram (@gentlemansdrive)</p><p>If you have any questions, please don’t hesitate to ask.</p>', 'Canberra, Australia', '2024-09-28T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dgd-logo-portrait-official-01-8ff63fde-f309c37f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5879448, 'Supersprint @ OneRaceway: 19 October', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/oneraceway-logo-fd087f0f-5c3c4b28.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/oneraceway-logo-fd087f0f-ace8f523.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/oneraceway-logo-fd087f0f-ace8f523.webp" loading="lazy" alt="" title=""></picture><br></p><p><span><strong><span>IT''S OPEN!!! We are excited to announce registrations are open now for a SuperSprint at One Raceway (formerly Wakefield Park Raceway).</span></strong></span></p><p><span>To satisfy our desire for motorsport we have been invited as guests (Via BMW DC NSW) to Porsche Club NSW''s Supersprint at One Raceway on 19 Oct. This is a massive opportunity to give the new One Raceway a run!</span></p><p><span>To register, follow the instructions below:</span></p><ol><li><span>Visit the<a href="https://pcnsw.onefireplace.com/event-5864355" target="_blank" rel="noopener"><span>Porsche Club Website.</span></a>The password is INVITED.<br></span>Be sure to have your Motorsport Australia Speed Licence details handy as it''s a minimum entry requirement for this event.</li><li>Complete ALL the Porsche Club NSW paperwork.</li><li><span>Read the Supplementary Regulations on the event webpage.</span></li><li><span>Register your attendance through here so our club know you are attending and can communicate any important information easily with you.</span></li><li><span>Book your accommodation!</span></li></ol><span>BMW DC NSW Supersprint Round 6 at BMW SuperFest was a terrific event, thank you to the 106 drivers who enjoyed that event!</span><p><span>BMW DC NSW SuperSprint rounds 5 and 7 were cancelled due to low numbers, we are considering crediting BMW Club Supersprint Championship points that you earn at this One Raceway Supersprint to your 2024 BMW Championship.</span></p><p><span>Let us know that you are registering with Porsche by registering your intention here. Email motorsport@bmwclubnsw.asn.au with any questions.</span></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wakefield-04f9c69d-52904b80.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wakefield-04f9c69d-af4ea365.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wakefield-04f9c69d-af4ea365.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'One Raceway, Goulburn', '2024-10-18T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/oneraceway-logo-fd087f0f-ace8f523.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503131, 'SDMA Hillclimb: 20 October - One lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-10-19T20:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5513946, 'Driver Training: Skidpan Day', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-3-266d2aa1-3293c331.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-3-266d2aa1-f95024e0.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-3-266d2aa1-f95024e0.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>We are excited to announce our 3rd driver training session for the year: The Skidpan at Sutton Road Driver Training Complex, Sunday 3 November 2024.</span></p><p><span>For those that aren''t familiar, the skidpan is a slippery circuit that replicates driving on snow/ice or hitting a patch of oil. It''s smooth concrete, water is applied to provide the slide..... Vehicle speeds are less than 50 km/h and as the<span>circuit</span>is so slippery, there is very little wear on tyres and very low risk. The fun factor is extreme as you attempt to control your car with little or no traction!</span></p><p><span><span><span>The Skidpan will help you to better understand your vehicle and car control in general, including what to do when there is understeer or oversteer.</span></span></span></p><p><span><span><span>This is a great learning event for everyone. We strongly encourage new drivers to come and learn more about their vehicle and for experienced drivers to refresh their skills and of course, have fun!</span></span></span><span>Skills learnt on the skidpan are invaluable and can save lives.</span></p><p>Some important things to note:</p><ul><li>No burnouts or black marks to be left on the skid pan</li><li>Suitable clothing and appropriate footwear (no thongs, open-toed shoes, or high heels).</li><li>There are noise limits…..Vehicles must not exceed a noise limit of 85db at 30 meters. Any road registered vehicle *should* be less than this.</li><li>Participants are solely responsible for any property damages.</li><li>There will be more experienced members there to help out. If you would like some assistance please come see us after the briefing.</li></ul><p>If you would like to take passengers you are more than welcome to.</p><p>There will be light refreshments and tea/coffee facilities as well. We recommend bringing lunch with you however, if you need to buy lunch Queanbeyan is only a few minutes drive away....</p><strong>*Drivers briefing will be at 8:15am sharp. The fun begins at 8:30*.</strong><p><span>NOTE: We''ve put together special pricing for everyone. $120 ($140 for non-members) is per vehicle with multiple drivers allowed, for the ENTIRE day. Places are limited, register early to avoid disappointment!</span></p><p><span>We are looking forward to seeing you there and most of all have FUN!</span></p><h3>Registration</h3><ul><li>November Skidpan Day - Member Price – $120.00 Official BMW Club Member Price.Participants may share a car, however it is $120 per car to book a place on the day.</li><li>November Skidpan Day - Non-Member Price – $140.00 Non-Member Price.Participants may share a car, however it is $140 per car to book a place on the day.</li></ul>', 'Sutton Road Driver Training Complex', '2024-11-02T21:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-3-266d2aa1-f95024e0.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503132, 'SDMA Hillclimb: 10 November - Two lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-11-09T20:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5918220, '2024 Annual General Meeting (AGM)', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-277b1e9d-e593fbe3.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-277b1e9d-425a8051.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-277b1e9d-425a8051.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span><span>It is that time of year again - The Annual General Meeting (AGM)! The AGM</span><span>will be held on Tuesday 19 November from 7pm BUT we are trying a different venue. A German Car Club in a German Club. ''Willkommen</span><em>, Meine Damen und Herren</em><span>!''</span><span>The Harmonie German Club - 49 Jerrabomberra Avenue, Narrabundah.</span></span></p><p><span><strong>Join us in the Pool Room at 7pm for a chat and complementary finger food (Chefs selection hot platter and a fruit platter) (<em>Appetithappen</em>). The AGM will start at 7.30pm.</strong></span></p><p><span><span>You might like to consider coming early and having a meal. We are told Tuesdays are busy as it is $12 Snitty night -<a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/harmonie-food-menu-2022-web-d4c65ffc-a0e486d4.pdf" target="_blank" rel="noopener">Harmonie Club Menu</a>. Y</span><span>ou will just need to sign in at the door with some ID.</span></span></p><p><span>Please put it in your diary and consider standing for a committee position as your Club needs you, or, ''Ihr Club braucht Sie''.</span><span><strong>Come along and take the opportunity to meet fellow members and influence the direction of your Club.</strong></span></p><p><strong><span>The agenda for the AGM will be:</span></strong></p><div><ul><li><span>Confirmation of the minutes of the previous 2023 AGM (held November 2023)</span></li><li><span>President’s Report</span></li><li><span>Financial Report</span></li><li><span>Election of Committee (as per section 8 of the Constitution of the BMW Car Club Canberra)</span></li><li><span>General Business</span></li></ul></div><p><span>During the AGM, an election will take place to appoint the President and Committee for the 2024-2025 year. All current financial members are encouraged to nominate for committee positions which are listed below.</span></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/notice-of-agm-2024-ba3a5657-17e6a43e.pdf" target="_blank"><span>Notice of AGM and Committee Roles and Responsibilities</span></a></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/nomination-form-bmw-car-club-canberra-2024-8fcab28d-0b4cc69d.pdf" target="_blank"><span>Committee Nomination Form</span></a></p><p><span><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/proxy-form-bmw-car-club-canberra-21c86459-42880f99.pdf" target="_blank">Proxy Voting Form</a><br></span></p><p><span><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/postal-voting-form-bmw-car-club-canberra-13f90653-81826021.pdf" target="_blank">Postal Voting Form</a><br></span></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/minutes-of-annual-general-meeting-november-2023-f8dee908-4b517f79.docx" target="_blank"><span>Minutes of AGM 2023</span></a><br></p><p><span><strong>Only financial members as at Tuesday 19 November 2024 are eligible to vote.</strong>If you are unable to attend the AGM, you may choose to nominate a proxy to vote on your behalf, submit a nomination or send a postal vote, however these must be lodged with the Secretary by emailing<a href="mailto:secretary@bmwclubcanberra.org.au">secretary@bmwclubcanberra.org.au</a>.</span></p><p><span>You can also nominate on the night. If you wish to raise a notice of motion at the meeting, please email your motion to the Secretary by Monday 28 October 2024.</span></p><p><span>I hope you can attend the AGM and look forward to your continued support and involvement in the activities of the BMW Car Club Canberra.</span></p><p><span>Regards</span></p><p><span>Lorna Kunz<br>Secretary<br>BMW Car Club Canberra<br>secretary@bmwclubcanberra.org.au</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'The Harmonie German Club - 49 Jerrabomberra Avenue, Narrabundah', '2024-11-19T08:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-277b1e9d-425a8051.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5503133, 'SDMA Hillclimb: 24 November - One lap event', '<p>With a growing number of club members competing in SDMA hillclimb events, we are adding placeholder events to the calendar.</p><p>If you are considering getting involved, I would encourage you to register.</p><p><strong>Official registration for the SDMA Hillclimb event will only be available through SDMA. You will need to have Motorsport Australia speed licence and to join the SDMA club as well: https://www.sdmahillclimb.com.au</strong></p><p>Please RSVP to this event for our own records.</p>', 'SDMA Hillclimb', '2024-11-23T20:30:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5956514, 'Impromptu Sunday Morning Coffee & Drive', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/morning-coffee-and-drive-2e4d4a69-04d685b6.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/morning-coffee-and-drive-2e4d4a69-dc3f6086.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/morning-coffee-and-drive-2e4d4a69-dc3f6086.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for an "Impromptu"<span>Sunday Morning Coffee &amp; Drive.</span></p><p>Meeting at<a href="https://www.daughtersathall.com.au/" target="_blank" rel="noopener">Daughters Café</a>at Hall (there is parking at the back and front) for a delicious coffee and a bite to eat - perhaps a delicious Bacon and Egg Roll named "The Best Bacon and Egg Roll"? We''ll then be heading out via the Barton Hwy &gt;Nanima Rd &gt; Murrumbateman Rd &gt; Sutton Rd &gt; re-group at Sutton Bakery &gt; SDMA Hillclimb (for those keen).</p><p><a href="https://www.google.com/maps/dir/Daughters+at+Hall,+5+Victoria+St,+Hall+ACT+2618/Nanima+Rd,+Springrange+NSW+2618/Murrumbateman+Rd,+New+South+Wales/Little+Sutton+Bakehouse,+Victoria+Street,+Sutton+NSW/SDMA+Hillclimb,+Australian+Capital+Territory/@-35.1593144,149.1311426,43687m/data=!3m1!1e3!4m32!4m31!1m5!1m1!1s0x6b17ab7d34b831d9:0xbf21d708bd7bbbcc!2m2!1d149.0697592!2d-35.170419!1m5!1m1!1s0x6b17004152f1a833:0xee4c1e85fd447204!2m2!1d149.0845768!2d-35.0705388!1m5!1m1!1s0x6b16fdcf19749e0f:0x526aa70df8e4eddd!2m2!1d149.1231587!2d-35.0273874!1m5!1m1!1s0x6b1657b7fb1de583:0x7dfc8007177d94ba!2m2!1d149.2529703!2d-35.1641454!1m5!1m1!1s0x6b164e4c2692862d:0xb59d18ebfbdcc0d4!2m2!1d149.2378997!2d-35.3255157!3e0?entry=ttu&amp;g_ep=EgoyMDI0MTExOS4wIKXMDSoASAFQAw%3D%3D" target="_blank" rel="noopener">Drive route link here</a></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-2024-11-22-094126-79d435b6-2d589554.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-2024-11-22-094126-79d435b6-65f844a9.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/screenshot-2024-11-22-094126-79d435b6-65f844a9.webp" loading="lazy" alt="" title=""></picture><br></p><p>For those keen, we''ll also be stopping in at the SDMA Hillclimb to check out the last Hillclimb of the year. If you have CB radios, please bring them :)</p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Daughters Café, 5 Victoria St Hall', '2024-11-23T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/morning-coffee-and-drive-2e4d4a69-dc3f6086.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5961234, 'Last Event of the Year: Southern Tablelands Drive', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/southern-drive-event-pic-0bf0b9ea-f02196ed.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/southern-drive-event-pic-0bf0b9ea-eef9abdd.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/southern-drive-event-pic-0bf0b9ea-eef9abdd.webp" loading="lazy" alt="" title=""></picture><br></p><p>Come and join us on a local run to the north of Canberra (Binalong, Boorowa, Rugby, Crookwell, Gundaroo and Sutton) and enjoy a mix of roads, scenery, and local hospitality.</p><p><strong>First Stop:</strong><a href="https://www.facebook.com/cafeonqueenbinalong/" target="_blank" rel="noopener">Café on Queen</a>Binalong for morning tea</p><p><span><strong>Second Stop:</strong><a href="https://www.google.com/maps/uv?pb=!1s0x6b10d3aed10ac077%3A0x1691f28a4601162e!3m1!7e115!4s%2Fmaps%2Fplace%2FRugby%2BGeneral%2BStore%2F%40-34.393816%2C148.9948045%2C3a%2C75y%2C69.33h%2C90t%2Fdata%3D*213m4*211e1*213m2*211s9eaeoTRGKqZv-IMCLg9P-A*212e0*214m2*213m1*211s0x6b10d3aed10ac077%3A0x1691f28a4601162e%3Fsa%3DX%26ved%3D2ahUKEwjNyP-90fiJAxVzyDgGHfDXHLwQpx96BAgyEAA!5sRugby%20General%20Store%20-%20Google%20Search!15sCgIgAQ&amp;imagekey=!1e2!2s9eaeoTRGKqZv-IMCLg9P-A&amp;cr=le_a7&amp;hl=en&amp;ved=1t%3A206134&amp;ictx=111" target="_blank" rel="noopener">Rugby General Store</a>(Photo Op)</span></p><p><span><strong>Third Stop:</strong></span><a href="https://criterionhotelcrookwell.com/" target="_blank" rel="noopener">The Criterion Hotel</a>in Crookwell for lunch</p><p><span><strong>Fourth Stop:</strong><a href="https://littlesutton.com.au/" target="_blank" rel="noopener">Little Sutton Bakehouse</a>(regroup / end of run)</span></p><p>Please familiarise yourself with the drive route below. We will have a driver briefing before we depart and we''ll advise who the group leader and tail-end Charlie are.</p><a href="https://www.google.com/maps/dir/McDonald''s,+2+O''Hanlon+Pl,+Nicholls+ACT+2913/Cafe+on+Queen,+Queen+Street,+Binalong+NSW/Boorowa+NSW/''''/Criterion+Hotel,+Goulburn+Street,+Crookwell+NSW/Gundaroo+NSW/''''/@-34.7778526,148.9563638,165999m/data=!3m1!1e3!4m44!4m43!1m5!1m1!1s0x6b17acbdc35b0257:0x474d20239a55e044!2m2!1d149.0819307!2d-35.1899324!1m5!1m1!1s0x6b1769e832513d27:0xaed9b09dfa242fd!2m2!1d148.6325045!2d-34.668734!1m5!1m1!1s0x6b10ca96279a0199:0x40609b49043db10!2m2!1d148.7167614!2d-34.4364648!1m5!1m1!1s0x6b10d3aed10ac077:0x1691f28a4601162e!2m2!1d148.9949895!2d-34.3937584!1m5!1m1!1s0x6b113627268a5f33:0xa774924d0350b1ed!2m2!1d149.4697238!2d-34.457241!1m5!1m1!1s0x6b16fbc0026444e9:0x40609b49043de10!2m2!1d149.2547097!2d-35.0410869!1m5!1m1!1s0x6b1657b7fb1de583:0x7dfc8007177d94ba!2m2!1d149.2529703!2d-35.1641454!3e0?entry=ttu&amp;g_ep=EgoyMDI0MTExOS4yIKXMDSoASAFQAw%3D%3D" target="_blank" rel="noopener"><span>Drive Route</span></a><p>Please bring your CB radio with you. We''ll have some ones available for club members to use if you don''t have one (please make sure they are returned).</p><p><strong>Drivers briefing at 8:50AM then departing at 9.00AM sharp</strong>from McDonald''s, Nicholls.</p><p><strong>Please register to assist with booking numbers for lunch. If you are unable to make it, please let us know!</strong></p><p>Looking forward to seeing you there for a fun day out!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Departing from McDonald''s, Nicholls at 9AM Sharp', '2024-12-14T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/southern-drive-event-pic-0bf0b9ea-eef9abdd.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6015167, 'Cars, Coffee & BBQ - A Charity Event for Cancer Research', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/autobarn-tugg-event-2af6af96-19b4b7ea.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/autobarn-tugg-event-2af6af96-86d7e398.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/autobarn-tugg-event-2af6af96-86d7e398.webp" loading="lazy" alt="" title=""></picture><br></span></p><p>Bring your daily driver, project car, or garage queen and join us for Cars, Coffee &amp; BBQ in support of the Cancer Council &amp; Cancer Research!</p><p>What to bring: A gold coin donation, and be ready for great coffee, food, and amazing cars!</p><p>Highlights:</p><ul><li>Peaky Grinderz Coffee Co. will be serving the best coffee in Canberra and donating a percentage of their profits to the cause</li><li>Delicious BBQ from 10 AM</li><li>Enjoy fantastic specials at autObarn in-store on the day.</li></ul><p>Don’t miss out on a great day supporting a great cause with awesome cars and amazing coffee!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Autobarn Tuggeranong, Tuggeranong Square, Anketell St, Greenway', '2025-01-17T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/autobarn-tugg-event-2af6af96-86d7e398.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5960235, '2025 Poker Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/2025-poker-run-event-pic-18513761-b09beb34.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/2025-poker-run-event-pic-18513761-b08c8b13.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/2025-poker-run-event-pic-18513761-b08c8b13.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for our first event of 2025. For those of you that have not attended a Poker Run before, you collect a card at five different locations and the best hand wins a prize (they''ll be awesome prizes, thanks to our friends Canberra BMW)!</p><p><span>Meeting at</span><strong>McDonalds Molonglo on Kirkpatrick Street</strong>(1st card ). Driver briefing at 10.00am, leaving shortly after. Travel out the Cotter Road and turn right onto Brindabella Road passing Uriarra Village and turn right onto Uriarra Road (2nd card).</p><p>Continue on Uriarra Road which turns into Fairlight Road and turn right onto Mountain Creek Road. Turn right onto Wee Jasper Road (3rd card), turn right onto Yass Valley Way (4th card) and turn right at the second round about onto the Barton Highway.</p><p>Lunch will be at the Murrumbateman Pub where you will collect the 5th card.</p><p><a href="https://www.google.com/maps/dir/McDonald''s,+14A+Kirkpatrick+St,+Weston+ACT+2611/Uriarra+Village+ACT/Taemas+Bridge,+Wee+Jasper+Road,+Cavan+NSW/Murrumbateman+Country+Inn,+Barton+Highway,+Murrumbateman+NSW/@-35.0926364,149.0768774,10.79z/data=!4m31!4m30!1m5!1m1!1s0x6b17b3cef387775f:0x1facf1ceda7779cb!2m2!1d149.0565663!2d-35.3219007!1m10!1m1!1s0x6b17b756e9570ab1:0x986e1bf240ab21e1!2m2!1d148.9248239!2d-35.2958618!3m4!1m2!1d148.9505731!2d-35.2463242!3s0x6b17b044ad88c3bd:0xb5c72a85ecb5bbf8!1m5!1m1!1s0x6b17097c34537751:0x55578e270a44532b!2m2!1d148.8481134!2d-35.003359!1m5!1m1!1s0x6b1704ebeabe1b13:0xad08436a4afa44aa!2m2!1d149.0299224!2d-34.9691963!3e0?entry=ttu" target="_blank" rel="noopener">Drive Route Here</a></p><p><span>We intend to be at the Murrumbateman Pub by 12.00-12.30. We may even do a quiz/trivia also at lunch,<span><span>likelihood</span></span>the topic will be on BMW. ;)</span></p><p><strong>Please bring your UFH/CB radio if you have one, we''ll have some club ones available to borrow if needed. We''ll also nominate a Lead Driver and a Tail-End Charlie on the day to assist with keeping the group together (t</strong><strong>his will be a leisurely drive) . Please familiarise yourself with the route (above).</strong></p><p><span><span>Registration is essential for catering. If you are no longer able to attend, please let us know.</span></span></p><p>We look forward to seeing you on the Poker Run!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Start at McDonalds Molonglo, Lunch at Murrumbateman Pub', '2025-01-18T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/2025-poker-run-event-pic-18513761-b08c8b13.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5975689, 'BMW Display at Canberra Festival of Speed', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/art-cars-5-101-1024x480-1aee108a-645ee8cb.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/art-cars-5-101-1024x480-1aee108a-d73a02d9.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/art-cars-5-101-1024x480-1aee108a-d73a02d9.webp" loading="lazy" alt="" title=""></picture><br></p><p>2025 marks the second Canberra Festival of Speed and BMW ///M will be in the spotlight.</p><p>As the local source of all things BMW, we would love to create another memorable display at the Canberra Festival of Speed, this time with the performance models in mind. January 25-26 will be our time to shine!</p><p>We are hoping to provide a generational lineup of all M3s along with the other BMW ///M models (e.g. M1, M2, M4, M5, M6, M8/850CSi, Z3M, Z4M) as well as some of the lesser known heritage Motorsport cars like the 2002 Turbo, 3.0 CSL, E12 530MLE and M535i for the weekend. Other special models like those from Alpina, Hartge and AC Schnitzer would also be considered. For those with something incredibly unique we would love to see it as well!</p><p>As a celebration of the marque we would like to see cars as they came from the factory or as close as possible to standard configuration.</p><p>If you own a Motorsport BMW and would like to see your pride and joy on display, please register and let us know what your preferences are. We will be in contact with individual registrants in due course.</p><p>If you have any questions please don’t hesitate to ask.</p><p>Regards,<br>Luke Wise<br>Vice President | BMW Car Club Canberra<br>Official BMW Club<br><a href="/">BMW Car Club Canberra</a></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>M3 Heritage Display Confirming availability for M3 specific group</li><li>Other BMW Registration option for anything other than M3</li></ul>', 'Thoroughbred Park', '2025-01-24T20:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/art-cars-5-101-1024x480-1aee108a-d73a02d9.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5973922, 'Wheels - Show & Shine 2025', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-2025-2dfa1228-2c79e1d2.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-2025-2dfa1228-f945f054.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-2025-2dfa1228-f945f054.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>Join us for<span><span><span>Wheels 2025</span>, one of the region''s biggest automotive events!</span></span></span></p><p><span><span>Wheels charity Car, Bike &amp; Truck show will be held at the Queanbeyan Showground on<strong>Sunday 16 February 2025</strong>.</span><span>The annual display is organised by the Council of ACT Motor Clubs for it''s 78 affiliated clubs.</span></span></p><p><span>Wheels brings together veteran, vintage, historic, classic, and modified cars and bikes as well as modern and electric vehicles from across the region.</span></p><p><span><strong><span>Please see the below important information below to assist you on the day</span></strong></span></p><ul><li><span><span><span><span><span><span><strong>Display entry is between 8:00am and 9:30am, and remain in place until 1:30pm - after the event award presentations.<br><br></strong></span></span></span></span></span></span></li><li><span><span><span><span><span><strong>Entry to the Showgrounds is via the main gate on Glebe Avenue, where Marshals will direct vehicles to the Arena.<br><br></strong></span></span></span></span></span></li><li><span><span><span><span><span><strong><span>The entry fee for Wheels will be $10 per vehicle - t</span><span>here is no admission fee for passengers or pedestrian visitors.<br><br></span></strong></span></span></span></span></span></li><li><span><span><span><span><strong><span><span><span><span>In the interest of pedestrian/visitor safety, vehicle movements within the Showgrounds Arena will NOT be permitted between 9:45am and 1:30pm.<br><br></span></span></span></span></strong></span></span></span></span></li><li><span><strong><span>Food and drink will be available on site during the day, additionally, there are several options nearby on Kings Highway (Canberra Avenue). You could even bring a picnic lunch! There are also rest room facilities on site.<br><br></span></strong></span></li><li><span><strong><span>There is limited seating, so best to bring your own camp chair/mat. We''ll have the clubs marquees, you are most welcome to make use of them!<br><br></span></strong></span></li><li><span><span><span><span><span><strong>Vehicles EXITing the Showgrounds Arena, are to use the gate at the eastern end of the Showgrounds complex - leading onto Cooma Street.</strong></span></span></span></span></span></li></ul><span><strong><span><span><span>**Volunteers Needed**</span></span></span></strong></span><span><span><span>We''ll need some volunteers to assist with setting up/down the club</span></span></span><span><span><span><span>marquees, flags, lining up the cars etc. If you are able to assist, please arrive on site at 7:30am - it would be greatly appreciated.</span></span></span></span><br><ul></ul><p><span><span><span><span><span><span>Lets try to win best club display! :)</span></span></span><br></span></span></span></p><p><span>Wheels 2025 is being held in conjunction with the<a href="https://www.facebook.com/TheQueanbeyanMarket" target="_blank" rel="noopener">Queanbeyan Markets</a>.<br>Wheels will be located within the Showgrounds Arena, while the Markets are located at the western end of the Showgrounds complex.</span><span><span>There will be</span><span>craft, jewellery, fashion, homewares and plenty of food &amp; drink stalls; thereby benefiting all who attend for either event.</span></span></p><p><span><strong><span><span><span><span>If you have reregistered and are no longer able to attend, please let us know!</span></span></span></span></strong><br></span></p><p><span><span>Be sure to bring the whole family for a great day out -</span><span>Looking forward to seeing you there!</span></span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Queanbeyan Showgrounds', '2025-02-15T21:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-2025-2dfa1228-f945f054.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6057086, 'Pheasant Wood Circuit Track Day', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-eb62e6d3.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-80610a9f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-80610a9f.webp" loading="lazy" alt="" title=""></picture><br></p><p>Whether you''re a seasoned driver, weekend warrior or first-timer, come and join us for a fun day at our Pheasant Wood Circuit Track Day! All enthusiasts welcome, BMW or otherwise.</p><p>With an open pit lane format, you''ll have the time you need to perfect your driving. There will be dedicated beginner sessions and passenger laps (non-timed) also. Our fun and welcoming environment will ensure you have a great time.</p><p>To re-cap, there are some mandatory requirements to attend:</p><ul><li>Long sleeve cotton shirt, full length pants and enclosed footwear</li><li>Helmet (hire is available)</li><li>Motorsport (Motorsport Australia or AASA) or track (Pheasant Wood) licence: A day licence can be purchased for $30 @ the track. Note: Can be upgraded on the day to an annual licence for an additional $69</li></ul><p>There will be people available to help you get the best out of the day, sharpen your skills and give you some tips and get the best out of your track time.</p><p><strong>This will be a fully catered event - Your registration fee includes all lunch, snacks and drinks (water, soft drink, tea and coffee). Simply turn up and enjoy the day!</strong></p><p><strong>Gates open at 7:30am. Everyone MUST Arrive no later than 8:15am (to complete sign on). There will be a drivers briefing commencing at 8:45am. All drivers MUST attend and be ready to hit the track at 9:00am.</strong></p><p>On top of being an already impressive day, we will have awards for a number of categories as well.</p><p>NOTE: We will need volunteers to assist in the café area and admin duties. Volunteers will be provided with lunch, snacks, drinks, etc.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pic2-7c1dc79d-ad633fa5.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pic2-7c1dc79d-c55aab93.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pic2-7c1dc79d-c55aab93.webp" loading="lazy" alt="" title=""></picture><br></p><p>Registrations are limited, be sure to register ASAP to avoid disappointment!</p><p>If you have any questions please don’t hesitate to ask. Further information will be sent out to registrants closer to the day.</p><p>Come and practice, test your car or just play for the day - We hope to see you there!!</p><h3>Registration</h3><ul><li>Member Registration – $315.00 Members pricePlease include the club name and your club member number.</li><li>Member''s Guest Drive Registration – $315.00 Members pricePlease include the club name and your club member number.</li><li>Non-Member registration – $360.00 Non-member pricing</li><li>Viewing Guest Registration – $25.00 This is for all participants that are attending to watch the day and wish to be catered for.Price includes, lunch, snack, drink, etc.</li><li>Volunteer Registration This is for volunteers that are coming to watch and assist with organising the day. this includes catering and admin duties for the day.As a volunteer you will be provide with lunch, snacks, drinks, etc.</li></ul>', 'Pheasant Wood Circuit, Marulan', '2025-03-07T20:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-80610a9f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5861013, 'Club Drive: Drive to Pambula, lunch @ Wheeler''s Seafood Restaurant', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pambula-7f98ec27-dc8cadfd.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pambula-7f98ec27-688629c5.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pambula-7f98ec27-688629c5.webp" loading="lazy" alt="" title=""></picture><br></p><p>Please join us for another sensational drive to Pambula on some truly great driving roads! Route details will be sent to registrants closer to the date.</p><p>Lunch will be at<a href="https://www.wheelersoysters.com.au/" target="_blank" rel="noopener">Wheeler''s Seafood Restaurant</a>for some of the best seafood you''ll ever have.</p><p>To ensure we keep everyone together, we will split the drive into two groups. We will need volunteers to lead each group and be "tail end Charlie" to the destination.</p><p>If you are interested in assisting with either of these roles, please choose the relevant registration option. NOTE: As leader, there is an expectation that you keep an eye out for who is behind you. i.e. don''t get too far ahead of the rest of the group.</p><p>The club has CB radios that can be used however, we encourage everyone to have their own.</p><p>Pack a hat, sunscreen and some swimmers. The beach is calling!</p><p>Looking forward to seeing you there!</p><p><br></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/27fb5fb5d4074b3d'||'ae21b23671751d53-1ef1b1c5-4533e25f.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/27fb5fb5d4074b3d'||'ae21b23671751d53-1ef1b1c5-64850b29.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/27fb5fb5d4074b3d'||'ae21b23671751d53-1ef1b1c5-64850b29.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>General Driver No responsibility necessary, enjoy the drive!</li><li>Group 1 - leader Lead the way for group one, the ''spirited'' group</li><li>Group 1 - tail end Charlie Bring up the back of group one, the ''spirited'' group</li><li>Group 2 - leader Lead the way for group two, the ''cruising'' group</li><li>Group 2 - tail end Charlie Bring up the back of group two, the ''cruising'' group</li></ul>', 'Wheeler''s Seafood Restaurant, Pambula, NSW', '2025-03-15T21:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pambula-7f98ec27-688629c5.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6107713, 'Social Drive: to Bungendore - The Gathering Cafe', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/spririt1-39d82e71-4360b29b.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/spririt1-39d82e71-d0af0ae3.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/spririt1-39d82e71-d0af0ae3.webp" loading="lazy" alt="" title=""></picture><br></p><p><span>Join us for the first of our social drives and lunch on Friday 21st March!</span></p><p><span>The destination for the first of our social drive and lunch will be at ‘The Gathering Cafe'' in the lovely town of Bungendore from 11.30-2.00. The Gathering is nice and casual, attendees simply order and pay inside at the counter.</span></p><span><p><span><span><strong>Find the<span><span><u><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/5c7775-75e7708ace5642e6'||'914571fc3f9c4381-06f2d412-a7d211b5.pdf" title="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/5c7775-75e7708ace5642e6'||'914571fc3f9c4381-06f2d412-a7d211b5.pdf" data-auth="NotApplicable" data-linkindex="0"><span>Menu here</span></a></u></span></span></strong></span></span></p></span>Whether you are retired or have a day off come along to enjoy a nice drive and a lovely meal and instead of just driving back to Canberra, take a stroll around town, and make sure you include a stop in the Bungendore Wood Works Gallery with its stunning array of beautifully hand-crafted items.<br><p>Visit:<a href="https://www.visitnsw.com/destinations/country-nsw/queanbeyan-area/bungendore" title="https://www.visitnsw.com/destinations/country-nsw/queanbeyan-area/bungendore" target="_blank" rel="noopener">https://www.visitnsw.com/destinations/country-nsw/queanbeyan-area/bungendore</a></p><span><p><span><strong>Getting there</strong></span></p></span>You can either drive out to Bungendore and meet us at the cafe, or if you would like to travel in convoy we will meet you in the Spotlight/Super Cheap carpark in Queanbeyan at 10.45.<br><br>Final numbers are required no later than 5:00pm Tuesday 18th March as we need to advise the cafe.<span><p><span>How to get there -<span><a href="https://www.google.com/search?q=canberra+to+bungendore&amp;oq=canberra+to+bun&amp;gs_lcrp=EgZjaHJvbWUqDAgAEAAYFBiHAhiABDIMCAAQABgUGIcCGIAEMgwIARAAGBQYhwIYgAQyBwgCEAAYgAQyBwgDEAAYgAQyBwgEEAAYgAQyBggFEEUYOTIHCAYQABiABDIHCAcQABiABDIHCAgQABiABDIHCAkQABiABNIBCTcxMTdqMGoxNagCCLACAfEFnZfJ38BFF1I&amp;sourceid=chrome&amp;ie=UTF-8" title="https://www.google.com/search?q=canberra+to+bungendore&amp;oq=canberra+to+bun&amp;gs_lcrp=EgZjaHJvbWUqDAgAEAAYFBiHAhiABDIMCAAQABgUGIcCGIAEMgwIARAAGBQYhwIYgAQyBwgCEAAYgAQyBwgDEAAYgAQyBwgEEAAYgAQyBggFEEUYOTIHCAYQABiABDIHCAcQABiABDIHCAgQABiABDIHCAkQABiABNIBCTcxMTdqMGoxNagCCLACAfEFnZfJ38BFF1I&amp;sourceid=chrome&amp;ie=UTF-8" data-auth="NotApplicable" data-linkindex="2" target="_blank" rel="noopener">Canberra to Bungendore</a></span></span></p></span>For any inquires please reach out to Yvonne - mobile 0428 488 053 or email<a href="mailto:y_wise@hotmail.com" title="mailto:y_wise@hotmail.com">y_wise@hotmail.com</a><br><br>Regards,<br><p><span>Yvonne</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Spotlight Queanbeyan', '2025-03-20T23:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/spririt1-39d82e71-d0af0ae3.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6089055, 'Canberra Cars and Coffee', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/feb-cnc-event-pic-b92d0045-f537d297.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/feb-cnc-event-pic-b92d0045-c9d24d2d.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/feb-cnc-event-pic-b92d0045-c9d24d2d.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for the Canberra Cars and Coffee March Edition at Thoroughbred Park.</p><p>Whether you''re driving your daily driver, the SUV, the project car, or the garage car, bring it along and let''s enjoy a morning full of cars, conversation, and good company—all while enjoying a hot beverage of your choice!</p><p>This popular event always brings a large turnout, and we want to make sure we park together as a club. Here are the details:</p><p><strong>Meeting Location (Pre-meet):</strong></p><p>Opposite<a href="https://www.google.com.au/maps/place/bp+Truckstop/@-35.2250838,149.1645629,404m/data=!3m2!1e3!4b1!4m6!3m5!1s0x6b1653bb95d73e09:0xf7d24a047c7f4682!8m2!3d-35.225086!4d149.165853!16s%252Fg%252F1pwfvgk94?entry=ttu&amp;g_ep=EgoyMDI1MDIxOS4xIKXMDSoASAFQAw%3D%3D" target="_blank" rel="noopener">BP Watson</a>, on Antill St - See below.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-cars-and-coffee-meet-spot-a632890e-e68ade50.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-cars-and-coffee-meet-spot-a632890e-de719465.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-cars-and-coffee-meet-spot-a632890e-de719465.webp" loading="lazy" alt="" title=""></picture><br></p><p><strong>Time:</strong></p><p>Please arrive by 7:30 AM</p><p>At 7:45 AM sharp, we will cruise up the road together to Thoroughbred Park.</p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Opposite BP Watson, on Antill St, (Pre-meet)', '2025-03-22T20:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/feb-cnc-event-pic-b92d0045-c9d24d2d.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6038023, 'April Driver Training: Skidpan Day', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-3-266d2aa1-3293c331.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-3-266d2aa1-f95024e0.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-3-266d2aa1-f95024e0.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>We are excited to announce our 1st driver training session for the year: The Skidpan at Sutton Road Driver Training Complex, Sunday 13 April 2025.</span></p><p><span>This year we are trialling a split day with 2 sessions. This will help to ensure everyone gets plenty of opportunity on the skid pan without delay. Session times are as follows:</span></p><p><span>Morning: 8:00 am - 12:00 pm</span></p><p><span>Afternoon: 12:00 pm - 4:00 pm</span></p><p><span>For those that aren''t familiar, the skidpan is a slippery circuit that replicates driving on snow/ice or hitting a patch of oil. It''s smooth concrete, water is applied to provide the slide..... Vehicle speeds are less than 50 km/h and as the<span>circuit</span>is so slippery, there is very little wear on tyres and very low risk. The fun factor is extreme as you attempt to control your car with little or no traction!</span></p><p><span><span><span>The Skidpan will help you to better understand your vehicle and car control in general, including what to do when there is understeer or oversteer.</span></span></span></p><p><span><span><span>This is a great learning event for everyone. We strongly encourage new drivers to come and learn more about their vehicle and for experienced drivers to refresh their skills and of course, have fun!</span></span></span><span>Skills learnt on the skidpan are invaluable and can save lives.</span></p><p>Some important things to note:</p><ul><li>No burnouts or black marks to be left on the skid pan</li><li>Suitable clothing and appropriate footwear (no thongs, open-toed shoes, or high heels).</li><li>There are noise limits…..Vehicles must not exceed a noise limit of 85db at 30 meters. Any road registered vehicle *should* be less than this.</li><li>Participants are solely responsible for any property damages.</li><li>There will be more experienced members there to help out. If you would like some assistance please come see us after the briefing.</li></ul><p>If you would like to take passengers you are more than welcome to.</p><p>There will be light refreshments and tea/coffee facilities as well. We recommend bringing lunch with you however, if you need to buy lunch Queanbeyan is only a few minutes drive away....</p><strong>*Drivers briefings will be at 7:50am sharp and 11:50am sharp. The fun begins at 8:00am and 12:00pm*.</strong><p><span>NOTE: We''ve put together special pricing for everyone. $120 ($140 for non-members) is per vehicle with multiple drivers allowed, for the ENTIRE day. Places are limited, register early to avoid disappointment!</span></p><p><span>We are looking forward to seeing you there and most of all have FUN!</span></p><h3>Registration</h3><ul><li>Afternoon Session - Member Price – $120.00 Official BMW Club Member Price.Participants may share a car, however it is $120 per car to book a place on the day.</li><li>Afternoon Session - Non-Member Price – $140.00 Non-Member Price.Participants may share a car, however it is $140 per car to book a place on the day.</li><li>Morning Session - Member Price – $120.00 Official BMW Club Member Price.Participants may share a car, however it is $120 per car to book a place on the day.</li><li>Morning Session - Non-Member Price – $140.00 Non-Member Price.Participants may share a car, however it is $140 per car to book a place on the day.</li></ul>', 'Sutton Road Driver Training Complex', '2025-04-12T21:45:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/skidpan-event-pic-3-266d2aa1-f95024e0.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (5873775, 'BMW Clubs Australia Nationals 2025', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/nationals2025-225581b5-6cecda44.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/nationals2025-225581b5-1955da50.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/nationals2025-225581b5-1955da50.webp" loading="lazy" alt="" title=""></picture><br></p><p><span>BMW Drivers Club Melbourne are hosting the BMW Clubs Australia Nationals based at the</span>Mercure WestWaters Entertainment Complex in Caroline Springs<span>on the 24th - 27th of April 2025.</span></p><p><span>The BMW Clubs Australia Nationals is a chance for members of BMW car clubs across Australia to meet up and enjoy each other''s company and attend some great events. The BMW Nationals are run every 2 years with a different State/Territory hosting the event each time.</span></p><p><span>Please see the<a href="https://bmwclubnationals.com.au/" target="_blank" rel="noopener">BMW Club Nationals website</a>for more information.</span></p><p><strong>**You MUST register on the Nationals website to attend!**</strong></p><p>We’ll organise a trip from Canberra for those wanting to convoy together to the Nationals. In addition to your Nationals registration, please register your interest in this event for our visilibity and to help coordinate closer to the event.</p><p><span>The BMW Nationals are great fun. The events, motorsport and sight seeing are awesome.... And it''s alway great to catch up with old friends and make new ones along the way!</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Melbourne', '2025-04-23T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/nationals2025-225581b5-1955da50.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6155793, 'Wheels of Wamboin 2025', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wamboin2025-1f419b42-04c64f00.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wamboin2025-1f419b42-cc0d91d2.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wamboin2025-1f419b42-cc0d91d2.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for Wheels of<span><span>Wamboin</span></span>2025<span>!</span></p><p><span>Wheels of Wamboin is a motoring enthusiasts'' event with vintage, classic and street machines - from Model ''T''s to Tesla and everything in between!</span></p><p><span>The Wamboin Home Produce Market will also be on (Wamboin Community Hall, next to Wamboin Oval ). There will be a v</span><span>ariety of stalls, including lots of fresh fruit &amp; vegies, healthy juices, coffee, egg &amp; bacon rolls, jewellery, cards, lollies, dried fruits &amp; nuts, cakes, sausage rolls, quiches, craft, knitting, preserves, and more!<strong>Hot Tip: Bring cash! $</strong></span></p><p><span><span>So, bring your automotive marvel, have a great coffee, grab an egg and bacon roll and enjoy meandering around some awesome cars!</span></span></p><p><span><span><strong><span><strong><span>Meet at<a href="https://www.google.com/maps/place/McDonald''s+Queanbeyan/@-35.3495486,149.2389269,17z/data=!3m1!4b1!4m6!3m5!1s0x6b164efd4f2f8941:0x705a5c253d85ee7b!8m2!3d-35.3495486!4d149.2415018!16s%252Fg%252F1thztz8s?entry=ttu" target="_blank" rel="noopener">McDonald''s Queanbeyan</a>at 8:00am, then cruise to the show at 8:10am sharp as a Club.</span></strong></span></strong><br></span></span></p><p><span>Venue: Wamboin Community Hall</span></p><p><span>The show starts from 09:00am and goes to approx. 1:00pm</span></p><p><span><strong>Entry: Gold coin donation - proceeds to Wamboin RFS</strong></span></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-event-plug-2024-2-2b963941-a667d556.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-event-plug-2024-2-2b963941-d26315b2.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wheels-event-plug-2024-2-2b963941-d26315b2.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Meeting at McDonald''s Queanbeyan', '2025-05-16T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/wamboin2025-1f419b42-cc0d91d2.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6180015, 'Canberra Cars and Coffee', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/candc-pic-8eef2477-f381f8c5.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/candc-pic-8eef2477-8359733f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/candc-pic-8eef2477-8359733f.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for the Canberra Cars and Coffee May edition at Thoroughbred Park.</p><p>Whether you''re driving your daily driver, the SUV, the project car, or the garage car, bring it along and let''s enjoy a morning full of cars, conversation, and good company, all while enjoying a hot beverage of your choice!</p><p>This popular event always brings a large turnout, and we want to make sure we park together as a club. Here are the details:</p><p><strong>Meeting Location (Pre-meet):</strong></p><p>Opposite<a href="https://www.google.com.au/maps/place/bp+Truckstop/@-35.2250838,149.1645629,404m/data=!3m2!1e3!4b1!4m6!3m5!1s0x6b1653bb95d73e09:0xf7d24a047c7f4682!8m2!3d-35.225086!4d149.165853!16s%252Fg%252F1pwfvgk94?entry=ttu&amp;g_ep=EgoyMDI1MDIxOS4xIKXMDSoASAFQAw%3D%3D" target="_blank" rel="noopener">BP Watson</a>, on Antill St - See below.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-cars-and-coffee-meet-spot-a632890e-e68ade50.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-cars-and-coffee-meet-spot-a632890e-de719465.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-cars-and-coffee-meet-spot-a632890e-de719465.webp" loading="lazy" alt="" title=""></picture><br></p><p><strong>Time:</strong></p><p>Please arrive by 7:30 AM</p><p>At 7:45 AM sharp, we will cruise up the road together to Thoroughbred Park.</p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Opposite BP Watson, on Antill St, (Pre-meet)', '2025-05-24T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/candc-pic-8eef2477-8359733f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6108265, 'CANCELLED: One Raceway Track Day', '<p><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/oneraceway-b76f44c2-58469ac5.jpeg" alt="" title="" loading="lazy"><br></p><p>The moment you''ve all been waiting for, we''re heading back to our favourite local track! Our fun and welcoming environment will ensure you have a great time.</p><p>Your entry is per driver and includes timing. You are welcome to double enter your vehicle, each entry is full fare. We will factor dual entries into the grouping to ensure sufficient time for changeover, swapping lap timer, etc.</p><p>For those interested in using one of the pit lane garages, please register your interest. These will be available at the special price of $60 for our club event. Unfortunately if there isn''t enough interest to fill all spaces we may need to leave this to OneRaceway to facilitate @ $100/garage. Only one car can fit in each garage.</p><p>There are some changes for our OneRaceway event. Unfortunately we are unable to provide passenger laps due to the Motorsport Australia permit requirements. This excludes official instructors that are licensed to go in your vehicle at these events.</p><p>To re-cap, there are some mandatory requirements to attend any of our track days:</p><ul><li>Long sleeve cotton shirt, full length pants and enclosed footwear</li><li>Helmet (hire is available)</li><li>Motorsport (Motorsport Australia only for this event) or track (One Raceway) licence: A day licence can be purchased for $35 @ the track. Note: Can be upgraded on the day to an annual licence.</li></ul><p>For the beginners: There will be plenty of experienced drivers on the day to help you get the best out of your time on the track, we may have official instructors as well - still to be confirmed.</p><p>There will be 4 group sessions (15 minutes per session) for varying levels of experience. This may change on the day depending on final numbers.</p><p><strong>This will be a fully catered event - Your registration fee includes all lunch, snacks and drinks (water, soft drink, tea and coffee). Simply turn up and enjoy the day!</strong></p><p><strong>Gates open at 7:30am. Everyone MUST Arrive no later than 8:15am (to complete sign on). There will be a drivers briefing, ALL drivers MUST attend and be ready to hit the track at 9:00am SHARP.</strong></p><p>NOTE: We will need volunteers to assist in the café area and admin duties. Volunteers will be provided with lunch, snacks, drinks, etc.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/oneraceway-logo-fd087f0f-5c3c4b28.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/oneraceway-logo-fd087f0f-ace8f523.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/oneraceway-logo-fd087f0f-ace8f523.webp" loading="lazy" alt="" title=""></picture><br></p><p>Registrations are limited, be sure to register ASAP to avoid disappointment!</p><p>Bank account details below for those wanting to make direct payment, please ensure you email<a href="mailto:treasurer@bmwclubcanberra.org.au">treasurer@bmwclubcanberra.org.au</a>with payment confirmation once complete:</p><p>Account Name: BMW Car Club Canberra<br>BSB: 633-000<br>Account Number: 125925727<br>Reference: xSURNAME+1Rx</p><p>If you have any questions please don’t hesitate to ask. Further information will be sent out to registrants closer to the day.</p><p>Come and practice, test your car or just play for the day - We hope to see you there!!</p><h3>Registration</h3><ul><li>Member Registration – $375.00 Members pricePlease include the club name and your club member number.</li><li>Member''s Guest Drive Registration – $375.00 Members pricePlease include the club name and your club member number.</li><li>Non-Member registration – $400.00 Non-member pricing</li><li>Pit lane garage - EOI We have been offered access to the pit lane garages at a special club price however, this will only be possible if we can fill all 30 spaces.Member pricing will be $60 for the day. If we are unable to fill them, OneRaceway can cater to individual garages for $100.Please Register your interest and we will update everyone if the option can be made available.</li><li>Viewing Guest Registration – $25.00 This is for all participants that are attending to watch the day and wish to be catered for.Price includes, lunch, snack, drink, etc.</li><li>Volunteer Registration This is for volunteers that are coming to watch and assist with organising the day. this includes catering and admin duties for the day.As a volunteer you will be provide with lunch, snacks, drinks, etc.</li></ul>', 'One Raceway, Goulburn', '2025-06-06T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/oneraceway-b76f44c2-58469ac5.jpeg', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6155138, 'July Driver Training: Skidpan Day', '<p><span><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/skidpan0425-471f1a48-ef402f43.jpeg" alt="" title="" loading="lazy"><br></span></p><p><span>We are excited to announce our 2nd driver training session for the year: The Skidpan at Sutton Road Driver Training Complex, Sunday 13 July 2025.</span></p><p><span>We will again be running a split day with 2 sessions. This will help to ensure everyone gets plenty of opportunity on the skid pan without delay.<strong>NOTE:</strong>There is the option to register for the entire day however,<strong>places are limited</strong>. Session times are as follows:</span></p><p><span>Morning: 8:00 am - 12:00 pm</span></p><p><span>Afternoon: 12:00 pm - 4:00 pm</span></p><p><span>For those that aren''t familiar, the skidpan is a slippery circuit that replicates driving on snow/ice or hitting a patch of oil. It''s smooth concrete, water is applied to provide the slide..... Vehicle speeds are less than 50 km/h and as the<span>circuit</span>is so slippery, there is very little wear on tyres and very low risk. The fun factor is extreme as you attempt to control your car with little or no traction!</span></p><p><span><span><span>The Skidpan will help you to better understand your vehicle and car control in general, including what to do when there is understeer or oversteer.</span></span></span></p><p><span><span><span>This is a great learning event for everyone. We strongly encourage new drivers to come and learn more about their vehicle and for experienced drivers to refresh their skills and of course, have fun!</span></span></span><span>Skills learnt on the skidpan are invaluable and can save lives.</span></p><p>Some important things to note:</p><ul><li>No burnouts or black marks to be left on the skid pan</li><li>Suitable clothing and appropriate footwear (no thongs, open-toed shoes, or high heels).</li><li>There are noise limits…..Vehicles must not exceed a noise limit of 85db at 30 meters. Any road registered vehicle *should* be less than this.</li><li>Participants are solely responsible for any property damages.</li><li>There will be more experienced members there to help out. If you would like some assistance please come see us after the briefing.</li><li>Payment required upon registration. If there are issues with payment please contact us ASAP.</li></ul><p>Bank account details below for those wanting to make direct payment, please ensure you email<a href="mailto:treasurer@bmwclubcanberra.org.au" target="_blank">treasurer@bmwclubcanberra.org.au</a>with payment confirmation once complete:</p><p>Account Name: BMW Car Club Canberra<br>BSB: 633-000<br>Account Number: 125925727<br>Reference: xSURNAME+JULY SKIDPANx</p><p>If you would like to take passengers you are more than welcome to.</p><p>There will be light refreshments and tea/coffee facilities as well. We recommend bringing lunch with you however, if you need to buy lunch Queanbeyan is only a few minutes drive away....</p><strong>*Drivers briefings will be at 7:50am sharp and 11:50am sharp. The fun begins at 8:00am and 12:00pm*.</strong><p><span>NOTE: Due to increased hire costs, pricing has been updated. $135 ($160 for non-members) per vehicle, with multiple drivers allowed. Places are limited, register early to avoid disappointment!</span></p><p><span>We are looking forward to seeing you there and most of all, have FUN!</span></p><h3>Registration</h3><ul><li>Afternoon Session - Member Price – $135.00 Official BMW Club Member Price.Participants may share a car, however it is $135 per car to book a place on the day.</li><li>Afternoon Session - Non-Member Price – $160.00 Non-Member Price.Participants may share a car, however it is $160 per car to book a place on the day.</li><li>Morning Session - Member Price – $135.00 Official BMW Club Member Price.Participants may share a car, however it is $135 per car to book a place on the day.</li><li>Morning Session - Non-Member Price – $160.00 Non-Member Price.Participants may share a car, however it is $160 per car to book a place on the day.</li><li>Whole Day - Members – $195.00 Join us for both morning and afternoon sessions</li><li>Whole Day - Non-Members – $220.00 Join us for both morning and afternoon sessions</li></ul>', 'Sutton Road Driver Training Complex', '2025-07-12T21:45:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/skidpan0425-471f1a48-ef402f43.jpeg', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6234910, 'CARS 4 CANCER', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1000045811-e75bd995-ea03a1cf.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1000045811-e75bd995-1adc6a6a.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1000045811-e75bd995-1adc6a6a.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for a great cause and an even greater day out! We’re raising funds for the Cancer Council and supporting vital cancer research.</p><p>Bring your car, bike, truck, or EV, a gold coin donation, and a few bucks for coffee and BBQ! Peaky Grinderz Coffee Co will be serving up Canberra’s finest coffee and donating a portion of the day’s profits to the cause.</p><p><strong>**8:15am pre-meet at<a href="https://www.google.com.au/maps/place//@-35.4207562,149.0706291,253m/data=!3m2!1e3!4b1!4m6!1m5!3m4!2zMzXCsDI1JzE0LjIiUyAxNDnCsDA0JzEzLjgiRQ!8m2!3d-35.4206111!4d149.0705?entry=ttu&amp;g_ep=EgoyMDI1MDYxNi4wIKXMDSoASAFQAw%3D%3D" target="_blank" rel="noopener">Bunnings Tuggeranong Car Park</a>(Sheerin St side), we''ll then drive next door to the event and park together as a club**</strong></p><p><strong>On the Day:</strong></p><ul><li>Snag some incredible in-store deals</li><li>Enjoy heaps of giveaways</li><li>Check out the famous Autobarn “Astro Boy” WAG UTE, Mystery Box Rally car!</li></ul><p><strong>Their fundraising total is currently at $7,900 – but if they hit $9,000 by 19 July, Wade Simon, manager of Autobarn Tuggeranong, will be shaving Dale Tomes'' (club member) head live at the event!!!</strong></p><p>Every $10 donation = 1 entry into the draw for some amazing prizes – including a Couple’s Staycation Package from The Canberra REX Hotel!</p><p><strong>Donate here (tax-deductible):</strong></p><p><a href="https://2025.mysteryboxrally.com.au/like-father-like-son-20" title="https://2025.mysteryboxrally.com.au/like-father-like-son-20" target="_blank" rel="noopener">https://2025.mysteryboxrally.com.au/like-father-like-son-20</a></p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1000045810-e18f284a-03e6f830.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1000045810-e18f284a-0a7d36e9.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1000045810-e18f284a-0a7d36e9.webp" loading="lazy" alt="" title=""></picture><br></p><p>THANK YOU for your support - let’s drive change together and we hope to see you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Autobarn Tuggeranong, Tuggeranong Square, Anketell Street', '2025-07-18T22:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1000045811-e75bd995-1adc6a6a.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6155166, 'Country Day Drive: Binalong, Boorowa, Crookwell', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/binalong-gs-11f946cb-8114a386.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/binalong-gs-11f946cb-dcaf88d2.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/binalong-gs-11f946cb-dcaf88d2.webp" loading="lazy" alt="" title=""></picture></p><p><span>Beat away the winter blues and join us for a sensational drive to the quaint little towns in the region. Enjoy a mix of fun country roads, surrounded by beautiful scenery and great local hospitality.</span></p><p><span>We will meet at Daughters at Hall for those needing a quick shot of caffeine before hitting the road @ 8:30am sharp.</span></p><p><span>Morning tea at Binalong, providing ample time to explore the town and all the goodies Binalong General Store has to offer.</span></p><p><span>Lunch is booked for 12:30 at The Criterion Hotel (Middle Pub) in Crookwell.</span></p><p><span>After lunch we have some great roads to explore</span>(via Gunning and Gundaroo) as we make our way home. For those willing and looking for a reason to kick on, we will stop in at a local establishment (location TBC).</p><p>The drive details can be found here: https://maps.app.goo.gl/5bTJBsfiwABTNr3Q9</p><h3>Registration</h3><ul><li>Binalong, Boorowa, Crookwell</li></ul>', 'Hall General Store', '2025-07-25T21:45:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/binalong-gs-11f946cb-dcaf88d2.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6282269, 'Drive and Show: Trackside Torque @ OneRaceway', '<p>Come join us for a day out at the place that makes us smile.</p><p>One Raceway are putting on another great event and supporting Cystic Fibrosis Goulburn District.</p><p>Meet: Bunnings Majura Park<br>Time: 7:15 for 7:30am departure<br>What to bring: Cash</p><p>We''re looking forward to seeing you there</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1r-aug24-3a900a16-9932a2e4.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1r-aug24-3a900a16-35aea1b3.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1r-aug24-3a900a16-35aea1b3.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'One Raceway, Goulburn', '2025-08-23T21:15:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1r-aug24-3a900a16-35aea1b3.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6292482, 'Canberra Cars and Coffee', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/candc-pic-8eef2477-f381f8c5.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/candc-pic-8eef2477-8359733f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/candc-pic-8eef2477-8359733f.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for the Canberra Cars and Coffee August edition at Thoroughbred Park.</p><p>Whether you''re driving your daily driver, the SUV, the project car, or the garage car, bring it along and let''s enjoy a morning full of cars, conversation, and good company, all while enjoying a hot beverage of your choice!</p><p>This popular event always brings a large turnout, and we want to make sure we park together as a club. Here are the details:</p><p><strong>Meeting Location (Pre-meet):</strong></p><p>Opposite<a href="https://www.google.com.au/maps/place/bp+Truckstop/@-35.2250838,149.1645629,404m/data=!3m2!1e3!4b1!4m6!3m5!1s0x6b1653bb95d73e09:0xf7d24a047c7f4682!8m2!3d-35.225086!4d149.165853!16s%252Fg%252F1pwfvgk94?entry=ttu&amp;g_ep=EgoyMDI1MDIxOS4xIKXMDSoASAFQAw%3D%3D" target="_blank" rel="noopener">BP Watson</a>, on Antill St - See below.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-cars-and-coffee-meet-spot-a632890e-e68ade50.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-cars-and-coffee-meet-spot-a632890e-de719465.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-cars-and-coffee-meet-spot-a632890e-de719465.webp" loading="lazy" alt="" title=""></picture><br></p><p><strong>Time:</strong></p><p>Please arrive by 7:30 AM</p><p>At 7:45 AM sharp, we will cruise up the road together to Thoroughbred Park.</p><p>Looking forward to seeing you there!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Opposite BP Watson, on Antill St, (Pre-meet)', '2025-08-30T21:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/candc-pic-8eef2477-8359733f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6312539, 'Social Drive: Cooma with Lunch', '<p><span><span><span>Social Drive: To Cooma with lunch at Rose’s Restaurant</span></span><br></span></p><p><span>Join us for another social drive with lunch on Friday 19<span><span><span>th</span></span></span>September!</span></p><p><span>The destination for this social drive is the lovely town of Cooma, the Gateway to the Snowy Mountains. Lunch will be at<a href="https://www.rosesrestaurant.com.au/" target="_blank" rel="noopener"><span><span>Rose’s Restaurant</span></span></a>- 69 Massie Street, Cooma NSW 2630.</span></p><p><span>We’ve made booking from 11:30 – 2:00, you can f</span><span>ind the</span><span><span><a href="https://www.rosesrestaurant.com.au/menus/" target="_blank" rel="noopener">Menu here</a>.</span></span></p><p><span>Whether you are retired or have a day off come along to enjoy a great drive and a lovely meal. When it’s time to leave, instead of just driving back to Canberra, have a wander around town, or if you love Christmas ornaments perhaps consider making a stop in Bredbo on your way back and visit the<a href="https://www.bredbochristmasbarn.com.au/" target="_blank" rel="noopener"><span><span>Christmas Barn</span></span></a>, it’s only a few months till Christmas.</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bredbochristmasbarn1-mjbwoy-7cba39f9-423542ef.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bredbochristmasbarn1-mjbwoy-7cba39f9-6c4443cf.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bredbochristmasbarn1-mjbwoy-7cba39f9-6c4443cf.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>Visit:<a href="https://visitcooma.com.au/about-cooma/" target="_blank" rel="noopener"><span><span>https://visitcooma.com.au/about-cooma/</span></span></a></span></p><p><span><strong>Getting there</strong></span></p><p><span><span>We will meet just behind the Calwell Club at 9:45am for a 10:00am departure.</span><span>Please ensure you register, we need to confirm numbers no later than Tuesday 16</span><span><span><span>th</span></span></span><span>September.</span></span></p><p><span>How to get there -<a href="https://www.google.com/maps/dir/canberra/cooma/@-35.7555733,148.4906395,174233m/data=!3m2!1e3!4b1!4m14!4m13!1m5!1m1!1s0x6b164ca3b20b34bb:0x400ea6ea7695970!2m2!1d149.1310324!2d-35.2801846!1m5!1m1!1s0x6b3dae96ec533b89:0x40609b49043dcc0!2m2!1d149.1270444!2d-36.2345567!3e0?entry=ttu&amp;g_ep=EgoyMDI1MDgxOS4wIKXMDSoASAFQAw==" target="_blank" rel="noopener"><span><span>Canberra to Cooma</span></span></a></span></p><p><span>For any inquires please reach out to Yvonne on her mobile 0428 488 053 or email<span><a href="mailto:y_wise@hotmail.com"><span>y_wise@hotmail.com</span></a></span></span></p><p><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Roses Restaurant Cooma', '2025-09-18T23:45:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bredbochristmasbarn1-mjbwoy-7cba39f9-6c4443cf.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6277061, 'Family fun: Spectacular Gunning Fireworks Festival', '<picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gunningfireworks-0046beee-2007aaec.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gunningfireworks-0046beee-e87d9905.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gunningfireworks-0046beee-e87d9905.webp" loading="lazy" alt="" title=""></picture><p><span><span>The Gunning Fireworks Festival is back!</span></span></p><p><span><span>Come join us for a drive to Gunning and stay for the festivities on Saturday 20th Sept 2025. It is a truly fantastic way to spend an afternoon and evening in the country.</span></span></p><p><span><span><span><span><strong>Background on the Event</strong></span></span></span></span></p><p><span><span><span><span>Since 1999 Fireworks Australia has run demonstrations to showcase the latest and greatest fireworks for their clients. The early showcase events attracted large public crowds along with fireworks professionals from around the country. Moving forward a few years, and due to popular public demand, the Gunning Fireworks Festival was born.</span></span><br></span></span></p><p><span>A fantastic family friendly event including rides, food stalls and of course FIREWORKS! Sure to be a great night out for young and old.</span></p><p><span>2025 will feature two synchronised musical fireworks displays, a new daytime smoke demonstration, performance of "Beating the Retreat" by the Tuggeranong Valley Band complete with live cannon simulations! as well as the ever-popular fireworks demonstration!</span></p><p><span>Gates to open from 3:00pm with the fireworks commencing from approx. 4:00pm. Our tip is to get in early to secure the best vantage point.</span></p><p><span><strong>Timetable of Events:</strong></span></p><table><tbody><tr><td>3.00pm</td><td>Gates open! Carnival rides, food &amp; market stalls.</td></tr><tr><td>4.30pm</td><td>Daytime smoke demonstration and performance of "Beating the Retreat" by the Tuggeranong Valley Band.</td></tr><tr><td>6.30pm</td><td>Opening Pyromusical Spectacular</td></tr><tr><td>7.00pm</td><td>Fireworks Demonstration</td></tr><tr><td>8.00pm</td><td>Closing Pyromusical Extravaganza</td></tr><tr><td>9.00pm</td><td>Gates close</td></tr></tbody></table><p><span><strong>Getting There</strong></span></p><p><span>We are planning to convoy from Bunnings Majura Park to Gunning, Departing 2:00pm. Please register if you are planning to come along.</span></p><p><span>When we arrive in Gunning there will be signs on the main street directing you to the<strong>Gunning Showground</strong>.</span></p><p><span>Limited parking will be within the showground complex. Entrance is $20 per adult $10 per child or $50 per vehicle / family. Note: We are waiting for a response from the organisers about a potential BMW Club display within the grounds, watch this space....</span></p><p><span>Pass-outs will be given if you wish to leave and return later for the fireworks.</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gunningshowgroundmap2016-6f836754-b035c707.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gunningshowgroundmap2016-6f836754-fb4d54f6.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gunningshowgroundmap2016-6f836754-fb4d54f6.webp" loading="lazy" alt="" title=""></picture></span></p><p><span>Looking forward to seeing you there!</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Gunning Showgrounds', '2025-09-20T04:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/gunningfireworks-0046beee-e87d9905.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6267897, 'BMW Cars & Coffee', '<p><strong><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwcnc-dfaec7ab-4fc6260b.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwcnc-dfaec7ab-b28781ed.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwcnc-dfaec7ab-b28781ed.webp" loading="lazy" alt="" title=""></picture><br></span></strong></p><p><strong><span>Cars and Coffee.... and all the delicious things!</span></strong></p><p><span>Winter is on its way out, it''s time to start getting ready for Spring and all the fun things!</span></p><p><span>Come join us as the weather warms up and enjoy a meet ''n'' greet at Dirty Jane''s Fyshwick. Grab a beverage and bite to eat @ Salters Canberra and admire your fellow enthusiasts pride and joy - be it polished to perfection, modified, new acquisition or daily steed: this is the time to enjoy our passion with other like-minded lovers of all things BMW.</span></p><p><span>Salters Canberra, situated within Dirty Jane''s warehouse, is their cafe &amp; coffee shop and offer up great coffee and delicious treats.</span></p><p><span>Dirty Jane''s warehouse - selling every form of treasure including furniture, garden wares, ornaments, paintings, collectibles, jewellery, vintage clothing, and decorator items.</span></p><p><span>This event is open to all BMW enthusiasts, no need to be a member to attend.</span><span>.</span></p><p><span>If there is enough interest on the day, there may be a drive to follow.</span></p><p><span>We look forward in seeing you soon!</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Dirty Jane''s Canberra', '2025-09-20T22:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwcnc-dfaec7ab-b28781ed.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6350424, 'Multi-club dinner 1 - Solita Italian', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/solita2-bbf15d60-b66ecde3.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/solita2-bbf15d60-549384a8.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/solita2-bbf15d60-549384a8.webp" loading="lazy" alt="" title=""></picture><br></p><p><span><span>As part of our inter-club celebrations we are planning dinner at two great restaurants in the city. Join us on Friday night @ Solita for an Italian banquet! Fantastic food and company:</span><br></span></p><p><span>SoLita Pizzeria &amp; Pasta Bar - Unit 12 Baileys Corner, 143 London Circuit, Canberra City</span></p><p><span>We will be having the banquet menu which consists of shared pizza breads, and a selection of shared pastas and pizzas, and a few side salads.</span></p><p><span>The cost for dinner is approximately $42 per person. Drinks are to be ordered and paid for on consumption at the restaurant bar.</span></p><p><span>Note: NSW clubs members are already registered for this event.<br></span></p><p><span>Payment for dinner is to the club''s bank account (preferred) or via the PayPal payment gateway, you can use a credit card if you don''t have a PayPal account. Payment details:</span></p><p><span>Account Name: BMW CCC<br>BSB: 633-000<br>Account Number: 159596998<br>Reference: Surname Interclub dinner1</span></p><p><span>Dietary requirements – Ensure you notify of any dietaries at the time of registration, or they will not be able to be accommodated.</span></p><h3>Registration</h3><ul><li>Dinner – $42.00 Please select number of guests.</li></ul>', 'Solita Italian', '2025-09-26T09:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/solita2-bbf15d60-549384a8.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6051876, 'Social Drive and lunch', '<picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-97ab3a1d-d80efa32.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-97ab3a1d-6ab87777.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-97ab3a1d-6ab87777.webp" loading="lazy" alt="" title=""></picture><br><p>Interstate BMW Club friends are coming to the Nations Capital for German Auto Day (GAD) 2025, let''s show them some of the well-kept secrets in the region!</p><p>Join us for coffee @ one of the great bakeries in Curtin - Evoke Bakery, followed by a drive of some great backroads and lunch at the Wee Jasper Distillery:<a href="https://maps.app.goo.gl/KdnT156pdKHsyjGL8" target="_blank" rel="noopener">The Drive Route</a></p><p>To ensure our visitors cars are shiny and clean for GAD some of us will be heading to the Hume truckwash where the festivities can continue. If you haven''t already done so, please register for GAD here:<a href="https://www.google.com/url?sa=t&amp;source=web&amp;rct=j&amp;opi=89978449&amp;url=BMW Car Club Canberraevent-6046527&amp;ved=2ahUKEwiB4qHU99yPAxUSr1YBHTsoO6cQFnoECAsQAQ&amp;usg=AOvVaw1VAjDz5ha3ejZSHx2gn1wo" target="_blank" rel="noopener">German Auto Day 2025 BMW Car Club Canberra</a></p>', 'Canberra', '2025-09-26T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/canberra-97ab3a1d-6ab87777.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6350420, 'Multi-club dinner 2 - Bamiyan Afghan', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bamiyanafghan-ed1c5240-9dd30ab7.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bamiyanafghan-ed1c5240-07ceba48.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bamiyanafghan-ed1c5240-07ceba48.webp" loading="lazy" alt="" title=""></picture></p><p><span><span>As part of our inter-club celebrations we are planning dinner at two great restaurants in the city. Join us on Saturday night @ Bamiyan for an Afghan banquet! Fantastic food and company, a great night that will be had by all:</span><br></span></p><p><span><span>We will enjoy a standard banquet - $50 per person which includes</span><br><span>2 Entrees and 3 Mains:</span></span></p><p><span><span>- Entrée: Steam Dumpling and Kachaloo Boulanee</span></span></p><p><span><span>- Main: Choice of Grill Skewer, Choice of 1 Qorma dishes from Lamb, Beef, Chicken, Vegetarian and Sindhi Biryani served with Naan bread side salad &amp; raita. (1 Skewer per person)</span></span></p><p><span><span>Drinks are payable on consumption at the bar.</span></span></p><p><span>Note: NSW clubs members are already registered for this event.</span></p><p><span>Payment for dinner is to the club''s bank account (preferred) or via the PayPal payment gateway, you can use a credit card if you don''t have a PayPal account. Payment details:</span></p><p><span>Account Name: BMW CCC<br>BSB: 633-000<br>Account Number: 159596998<br>Reference: Surname Interclub dinner2</span></p><p><span><span>Dietary requirements – Ensure you notify of any dietaries at the time of registration or they will not be able to be accommodated.</span></span></p><p><span>Friday evening we will be heading to Solita for some delicious Italian food.</span></p><h3>Registration</h3><ul><li>Dinner – $50.00 Please select number of guests.</li></ul>', 'Bamiyan Braddon', '2025-09-27T09:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bamiyanafghan-ed1c5240-07ceba48.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6324305, 'Volunteers Needed: German Auto Day 2025', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-cc894e50.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp" loading="lazy" alt="" title=""></picture><br></span></p><p>German Auto Day 2025 is shaping up to be an incredible celebration and we need your help to make it even better!</p><p>We''re looking for volunteers to assist with a variety of tasks, including club setup and judging our<span>Show and Shine</span>.</p><p>No judging experience? No problem! If you have a good eye for detail, we’ll provide all the guidance you need before the event begins. Participants in the<span>Show and Shine</span>are also welcome to volunteer as judges, you''ll simply be assigned to a different category than your own entry.</p><p>You won’t be on your own, plenty of support will be available throughout the day. If you have any questions or would like more information, feel free to reach out.</p><p>Full details will be shared with volunteers as the event approaches.</p><h3>Registration</h3><ul><li>BMWCCC Display Volunteer Assistance with setting up/down the club marquee/banners and lining up BMW cars.</li><li>BMWCCC Show and Shine Judge No experience necessary! This is a great opportunity to learn not only about judging, it will also provide you with insight as to what you can do to prepare your car for future events.</li></ul>', 'Questacon Carpark, Parkes Pl W, Parkes ACT', '2025-09-27T21:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-we-need-you-e834810b-ea0e1e18.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6046527, 'German Auto Day 2025 - BMW Registration Only', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-3860-e80d8069-47fcda92.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-3860-e80d8069-e21253c7.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-3860-e80d8069-e21253c7.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span><span>Join us for German Auto Day (GAD) 2025!</span><span>GAD is a one day German automotive display event held each year in the Canberra region and is a collaboration event organised by local German branded marques, Audi, BMW, Mercedes Benz, Porsche, Volkswagen and other rare marques.</span></span></p><p><span><strong>General Entry will be $10, of which $5 goes to charity. We will also be holding the Clubs annual Show ''n'' Shine - BMWCCC Members Entry – $20.00 (entry fee goes towards trophies and event costs). NOTE: Show ''n'' Shine entries close Wednesday, 25 September to ensure judges have time to prepare.</strong></span></p><p><strong><span>**Please respond to the invitation so that adequate parking spaces can be secured.<strong>If you have registered and are no longer able to attend, please cancel your registration so others can attend**.</strong></span></strong></p><p><strong><span><strong><span><span>BMWCCC members - don’t forget to register for the Show &amp; Shine! It’s a fun and friendly competition, with trophies up for grabs. No need for concours-level prep, just make sure your car is clean and looking its best.</span></span><br></strong></span></strong></p><p><span>There will be plenty to do and see for the whole family - Food, coffee and activities to keep the kids entertained!</span></p><p><span><strong>**IMPORTANT EVENT DETAILS BELOW**</strong><br></span></p><p><span><strong>Day of event</strong></span></p><p><span>On the day of GAD, entrants can start arriving on site from 8:00am and to be in place before 9:30am on Sunday, 28 September 2025. We suggest getting in early to avoid access chaos.</span></p><p><span><span>There are rest room facilities on site.</span><span>What happens if the weather is bad? We''ll make that call closer to the day.</span></span></p><p><span><strong>Parking</strong></span></p><p><span><span>Please enter through the main venue entry and advise the traffic control officer of your requirements.</span></span></p><p><span><span><strong>Location Change</strong></span></span></p><p><span><span>The National Capital Authority (NCA) has informed us that rehabilitation works are now scheduled for Patrick White Lawns, our original event site. As a result, German Auto Day will now be held across the road at the Questacon Carpark (Parkes Pl W, Parkes ACT).</span></span></p><p><span><span><strong>Special 3 Series Display - 50 Years of BMW 3 Series</strong></span></span></p><p><span><span>To mark the 50th anniversary of the BMW 3 Series, we’re planning a special lineup showcasing all generations - starting from the iconic E21 onwards.</span><br><span>If you own a 3 Series, we’d love for you to bring it along and be part of this milestone celebration!</span></span></p><p><span>Looking forward to seeing you there!</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-1-98523b95-9fc0203b.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-1-98523b95-d0e884cb.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/download-1-98523b95-d0e884cb.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><br></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-801debaa.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmwccc-1-fbfad2ca-d47a0d75.webp" loading="lazy" alt="" title=""></picture></span><br></p><h3>Registration</h3><ul><li>German Auto Day - BMW Display Only – $10.00 Please respond to the invitation so that adequate parking spaces can be secured. If you have registered and are no longer able to attend, please cancel your registration so others can attend.</li></ul>', 'Questacon Carpark, Parkes Pl W, Parkes ACT', '2025-09-27T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/img-3860-e80d8069-e21253c7.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6197783, 'One Raceway Track Day', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/542151327-1197143725778743-1938507653346119074-n-6ef39d1b-9ed9bf65.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/542151327-1197143725778743-1938507653346119074-n-6ef39d1b-3b5516a9.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/542151327-1197143725778743-1938507653346119074-n-6ef39d1b-3b5516a9.webp" loading="lazy" alt="" title=""></picture><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/oneraceway-b76f44c2-58469ac5.jpeg" alt="" title="" loading="lazy"><br></p><p>We''re heading back to our favourite local track! Our fun and welcoming environment will ensure you have a great time.</p><p>Your entry is per driver and includes timing. You are welcome to double enter your vehicle, each entry is full fare. We will factor dual entries into the grouping to ensure sufficient time for changeover, swapping lap timer, etc.</p><p>For those interested in using one of the pit lane garages, please register your interest. These will be available at the special price of $60 for our club event. Unfortunately if there isn''t enough interest to fill all spaces we may need to leave this to OneRaceway to facilitate @ $95/garage. Only one car can fit in each garage.</p><p><strong>Passenger laps are allowed! There will be an untimed passenger lap session, provided all passengers have signed on and are wearing full safety gear.</strong></p><p>To re-cap, there are some mandatory requirements to attend any of our track days:</p><ul><li>Long sleeve cotton shirt, full length pants and enclosed footwear</li><li>Helmet (hire is available)</li><li>Motorsport (Motorsport Australia only for this event) or track (One Raceway) licence: A day licence can be purchased for $35 @ the track. Note: Can be upgraded on the day to an annual licence.</li></ul><p>For the beginners: There will be plenty of experienced drivers on the day to help you get the best out of your time on the track, we may have official instructors as well - still to be confirmed.</p><p>There will be 4 group sessions (15 minutes per session) for varying levels of experience. This may change on the day depending on final numbers.</p><p><strong>This will be a fully catered event - Your registration fee includes all lunch, snacks and drinks (water, soft drink, tea and coffee). Simply turn up and enjoy the day!</strong></p><p><strong>Cost: $375 for members, $400 for non-members.</strong></p><p><strong>Gates open at 7:00am. Everyone MUST Arrive no later than 8:15am (to complete sign on). There will be a drivers briefing, ALL drivers MUST attend and be ready to hit the track at 9:00am SHARP.</strong></p><p>NOTE: We will need volunteers to assist in the café area and admin duties. Volunteers will be provided with lunch, snacks, drinks, etc.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/oneraceway-logo-fd087f0f-5c3c4b28.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/oneraceway-logo-fd087f0f-ace8f523.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/oneraceway-logo-fd087f0f-ace8f523.webp" loading="lazy" alt="" title=""></picture><br></p><p>Registrations are limited, be sure to register ASAP to avoid disappointment!</p><p>We are happy to accept payment via bank transfer however, please ensure you contact<a href="mailto:treasurer@bmwclubcanberra.org.au">treasurer@bmwclubcanberra.org.au</a>prior to registering to process this - Bank account details below:</p><p>Account Name: BMW Car Club Canberra<br>BSB: 633-000<br>Account Number: 125925727<br>Reference: xSURNAME+1Rx</p><p>If you have any questions please don’t hesitate to ask. Further information will be sent out to registrants closer to the day.</p><p>Come and practice, test your car or just play for the day - We hope to see you there!!</p><h3>Registration</h3><ul><li>Member Registration – $375.00 Members pricePlease include the club name and your club member number.</li><li>Member''s Guest Drive Registration – $375.00 Members pricePlease include the club name and your club member number.</li><li>Non-Member registration – $400.00 Non-member pricing</li><li>Pit lane garage - EOI We have been offered access to the pit lane garages at a special club price however, this will only be possible if we can fill all 30 spaces.Member pricing will be $60 for the day. If we are unable to fill them, OneRaceway can cater to individual garages for $100.Please Register your interest and we will update everyone if the option can be made available.</li><li>Viewing Guest Registration – $25.00 This is for all participants that are attending to watch the day and wish to be catered for.Price includes, lunch, snack, drink, etc.</li><li>Volunteer Registration This is for volunteers that are coming to watch and assist with organising the day. this includes catering and admin duties for the day.As a volunteer you will be provide with lunch, snacks, drinks, etc.</li></ul>', 'One Raceway, Goulburn', '2025-10-10T20:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/542151327-1197143725778743-1938507653346119074-n-6ef39d1b-3b5516a9.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6405468, 'This Saturday: Convoy to BMW SuperFest 2025', '<p><span><span><strong><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-312-cc-e2c41076-c3f4b870.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-312-cc-e2c41076-ec6ef01d.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-312-cc-e2c41076-ec6ef01d.webp" loading="lazy" alt="" title=""></picture><br></strong></span></span></p><p><span><span><strong>For those heading up on Saturday, a convoy will be meeting @ BP Watson for a 12:00 pm departure</strong></span></span></p><p><span><span><span>It''s not too late to join in on the action! Please see below for SuperFest event registration details:</span></span></span></p><p><br></p><p><span><span><strong>A Celebration of BMW Passion - Bigger &amp; Better in 2025!</strong></span></span></p><p><span>Experience the ultimate celebration of BMW passion at Sydney Motorsport Park as BMW Drivers Club NSW proudly presents BMW SuperFest 2025! A dynamic fusion of their annual car show and Round 4 of the Supersprint Motorsport Championship.</span></p><p><span><strong><span>What’s On:</span></strong></span></p><div><ul><li><span><span><span>Over 300 BMWs on display</span></span></span><span><span>– from rare classics to modern icons</span></span></li><li>Special judged display categories</li><li><span>Collecting Cars SuperFest Auction Display</span><span>–<span>exclusive showcase</span></span></li><li><span><span>Parade laps</span>on the GP Gardner Circuit</span><span>for all Show &amp; Shine participants</span></li><li><span>100+ cars on track</span><span>for the<span>thrilling SuperSprint</span></span></li><li>Sponsor showcases, trade stands &amp; official BMW merchandise</li><li><span><span>Family-friendly</span></span><span>with food trucks, kids’ activities, and more</span></li><li><span>FREE</span><span>entry for spectators</span></li></ul></div><span><span><strong><span><br><span>IMPORTANT -</span></span></strong></span></span><span>If you’re entering the Show &amp; Shine OR the SuperSprint, you</span><strong>MUST register below!</strong><p><span><span><span><strong>Show &amp; Shine Registration:</strong></span></span><br><a href="https://www.bmwclubnsw.asn.au/event-6209637" target="_blank" rel="noopener"><span><span>https://www.bmwclubnsw.asn.au/event-6209637</span></span></a></span></p><p><span><span><strong>SuperSprint Registration:</strong></span></span></p><p><a href="https://www.bmwclubnsw.asn.au/event-6271878" target="_blank" rel="noopener"><span><span>https://www.bmwclubnsw.asn.au/event-6271878</span></span></a></p><p><span><span>Don''t miss this incredible celebration of BMW heritage, performance, and community. Whether you''re showing, racing, or spectating - we can''t wait to see you there!</span></span></p><p><span><span><em><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-3122-ddd41dc2-a0051cc0.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-3122-ddd41dc2-bb9e4c2f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-3122-ddd41dc2-bb9e4c2f.webp" loading="lazy" alt="" title=""></picture><br></span></em></span></span></p><p><span><span><em><span>This event invite is being used to promote<em><span>BMW SuperFest to</span></em>BMWCCC members.</span><span>If you plan to participate in the Show &amp; Shine or the SuperSprint, you MUST register using the links above.</span>Registration is essential!</em></span></span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'BP Watson', '2025-10-25T01:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-312-cc-e2c41076-ec6ef01d.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6324387, 'BMW SuperFest 2025', '<p><span><span><strong><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-312-cc-e2c41076-c3f4b870.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-312-cc-e2c41076-ec6ef01d.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-312-cc-e2c41076-ec6ef01d.webp" loading="lazy" alt="" title=""></picture><br></strong></span></span></p><p><span><span><strong>A Celebration of BMW Passion - Bigger &amp; Better in 2025!</strong></span></span></p><p><span>Experience the ultimate celebration of BMW passion at Sydney Motorsport Park as BMW Drivers Club NSW proudly presents BMW SuperFest 2025! A dynamic fusion of their annual car show and Round 4 of the Supersprint Motorsport Championship.</span></p><p><span><strong><span>What’s On:</span></strong></span></p><div><ul><li><span><span><span>Over 300 BMWs on display</span></span></span><span><span>– from rare classics to modern icons</span></span></li><li>Special judged display categories</li><li><span>Collecting Cars SuperFest Auction Display</span><span>–<span>exclusive showcase</span></span></li><li><span><span>Parade laps</span>on the GP Gardner Circuit</span><span>for all Show &amp; Shine participants</span></li><li><span>100+ cars on track</span><span>for the<span>thrilling SuperSprint</span></span></li><li>Sponsor showcases, trade stands &amp; official BMW merchandise</li><li><span><span>Family-friendly</span></span><span>with food trucks, kids’ activities, and more</span></li><li><span>FREE</span><span>entry for spectators</span></li></ul></div><span><span><strong><span><br><span>IMPORTANT -</span></span></strong></span></span><span>If you’re entering the Show &amp; Shine OR the SuperSprint, you</span><strong>MUST register below!</strong><p><span><span><span><strong>Show &amp; Shine Registration:</strong></span></span><br><a href="https://www.bmwclubnsw.asn.au/event-6209637" target="_blank" rel="noopener"><span><span>https://www.bmwclubnsw.asn.au/event-6209637</span></span></a></span></p><p><span><span><strong>SuperSprint Registration:</strong></span></span></p><p><a href="https://www.bmwclubnsw.asn.au/event-6271878" target="_blank" rel="noopener"><span><span>https://www.bmwclubnsw.asn.au/event-6271878</span></span></a></p><p><span><span>Don''t miss this incredible celebration of BMW heritage, performance, and community. Whether you''re showing, racing, or spectating - we can''t wait to see you there!</span></span></p><p><span><span><em><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-3122-ddd41dc2-a0051cc0.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-3122-ddd41dc2-bb9e4c2f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-3122-ddd41dc2-bb9e4c2f.webp" loading="lazy" alt="" title=""></picture><br></span></em></span></span></p><p><span><span><em><span>This event invite is being used to promote<em><span>BMW SuperFest to</span></em>BMWCCC members.</span><span>If you plan to participate in the Show &amp; Shine or the SuperSprint, you MUST register using the links above.</span>Registration is essential!</em></span></span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Sydney Motorsport Park, Eastern Creek', '2025-10-25T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/facebook-page-cover-photo-2025-820-x-312-cc-e2c41076-ec6ef01d.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6155163, '*Postponed* November Driver Training: Skidpan Day', '<p><span><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/skidpan0425-471f1a48-ef402f43.jpeg" alt="" title="" loading="lazy"><br></span></p><p><span>We are excited to announce our 3rd driver training session for the year: The Skidpan at Sutton Road Driver Training Complex, Sunday 2 November 2025.</span></p><p><span>We will again be running a split day with 2 sessions. This will help to ensure everyone gets plenty of opportunity on the skid pan without delay.<strong>NOTE:</strong>There is the option to register for the entire day however,<strong>places are limited</strong>. Session times are as follows:</span></p><p><span>Morning: 8:00 am - 12:00 pm</span></p><p><span>Afternoon: 12:00 pm - 4:00 pm</span></p><p><span>For those that aren''t familiar, the skidpan is a slippery circuit that replicates driving on snow/ice or hitting a patch of oil. It''s smooth concrete, water is applied to provide the slide..... Vehicle speeds are less than 50 km/h and as the<span>circuit</span>is so slippery, there is very little wear on tyres and very low risk. The fun factor is extreme as you attempt to control your car with little or no traction!</span></p><p><span><span><span>The Skidpan will help you to better understand your vehicle and car control in general, including what to do when there is understeer or oversteer.</span></span></span></p><p><span><span><span>This is a great learning event for everyone. We strongly encourage new drivers to come and learn more about their vehicle and for experienced drivers to refresh their skills and of course, have fun!</span></span></span><span>Skills learnt on the skidpan are invaluable and can save lives.</span></p><p>Some important things to note:</p><ul><li>No burnouts or black marks to be left on the skid pan</li><li>Suitable clothing and appropriate footwear (no thongs, open-toed shoes, or high heels).</li><li>There are noise limits…..Vehicles must not exceed a noise limit of 85db at 30 meters. Any road registered vehicle *should* be less than this.</li><li>Participants are solely responsible for any property damages.</li><li>There will be more experienced members there to help out. If you would like some assistance please come see us after the briefing.</li><li>Payment required upon registration. If there are issues with payment please contact us ASAP.</li></ul><p>Bank account details below for those wanting to make direct payment, please ensure you email<a href="mailto:treasurer@bmwclubcanberra.org.au" target="_blank">treasurer@bmwclubcanberra.org.au</a>with payment confirmation once complete:</p><p>Account Name: BMW Car Club Canberra<br>BSB: 633-000<br>Account Number: 125925727<br>Reference: xSURNAME+JULY SKIDPANx</p><p>If you would like to take passengers you are more than welcome to.</p><p>There will be light refreshments and tea/coffee facilities as well. We recommend bringing lunch with you however, if you need to buy lunch Queanbeyan is only a few minutes drive away....</p><strong>*Drivers briefings will be at 7:50am sharp and 11:50am sharp. The fun begins at 8:00am and 12:00pm*.</strong><p><span>NOTE: Due to increased hire costs, pricing has been updated. $135 ($160 for non-members) per vehicle, with multiple drivers allowed. Places are limited, register early to avoid disappointment!</span></p><p><span>We are looking forward to seeing you there and most of all, have FUN!</span></p><h3>Registration</h3><ul><li>Afternoon Session - Member Price – $135.00 Official BMW Club Member Price.Participants may share a car, however it is $135 per car to book a place on the day.</li><li>Afternoon Session - Non-Member Price – $160.00 Non-Member Price.Participants may share a car, however it is $160 per car to book a place on the day.</li><li>Morning Session - Member Price – $135.00 Official BMW Club Member Price.Participants may share a car, however it is $135 per car to book a place on the day.</li><li>Morning Session - Non-Member Price – $160.00 Non-Member Price.Participants may share a car, however it is $160 per car to book a place on the day.</li><li>Whole Day - Members – $195.00 Join us for both morning and afternoon sessions</li><li>Whole Day - Non-Members – $220.00 Join us for both morning and afternoon sessions</li></ul>', 'Sutton Road Driver Training Complex', '2025-11-01T20:45:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/skidpan0425-471f1a48-ef402f43.jpeg', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6065613, 'The Ultimate Alpine Drive and Getaway', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1-0b5a48cd-53cc6804.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1-0b5a48cd-a7672c06.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1-0b5a48cd-a7672c06.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for The Ultimate Alpine Drive and Getaway! Experience stunning alpine roads and sweeping countryside views. Explore charming country towns (plenty of shopping opportunities), capture unforgettable moments at scenic photo stops, and unwind with memorable group dinners!</p><p><strong><span>Tour Schedule:</span></strong></p><p><strong><span>DAY ONE</span><span>– Friday: Canberra to Cooma</span></strong></p><p>We’ll begin our adventure with an early departure, giving everyone time to settle in and relax before the big weekend.</p><ul><li><strong>Convoy Departure Point:</strong>Calwell Shopping Centre Car Park</li><li><strong>Departure Time:</strong><strong>12:15 PM sharp</strong></li></ul><p>You''re welcome to meet us later in Cooma if you prefer to drive at your own pace.</p><p><strong>Afternoon in Cooma:</strong></p><ul><li>Shopping options include<strong>Birdsnest</strong>,<strong>The Kitchen Bench</strong>, and other boutique stores on the main street.</li><li><strong>Check-in to accommodation</strong>and prepare for a relaxing evening.</li></ul><p><strong>Dinner:</strong></p><ul><li><strong>Rose’s Lebanese Restaurant</strong>– a delicious banquet experience</li><li><strong>Cost:</strong>$45 per person</li></ul><p><strong>Accommodation options in Cooma:</strong></p><ul><li><strong>Kinross Inn</strong>– $150 per night<br>Call<strong>(02) 6452 3577</strong>and mention the<strong>BMW Club</strong></li><li><strong>Cooma Motor Lodge</strong>– $180 per night<br>Call<strong>(02) 6452 1888</strong>and mention the<strong>BMW Club</strong></li></ul><p><strong><span>DAY TWO – Saturday: Cooma to Thredbo via Khancoban</span></strong></p><p><strong>Breakfast:</strong></p><ul><li>Meet at<strong>123 Cafe</strong>, Main Street, Cooma</li></ul><p><strong>Scenic Driving Tour Begins:</strong><br>Our Cooma-based club members have put together an incredible driving route, including a stop at a<strong>Snowy Hydro site</strong>for a photo opportunity and short tour.</p><p><strong>Group Dinner:</strong></p><ul><li><strong>Cascades Restaurant</strong>, Thredbo – a great way to unwind after an amazing day of driving</li><li><strong>Cost:</strong>$60 per person</li></ul><p><strong>Drive Map:</strong><br><a href="https://maps.app.goo.gl/gX2ws2AQ8fjekcdP7" target="_blank" rel="noopener">Google Maps Route</a></p><p><strong>Driving Highlights:</strong></p><ul><li>~320 km over 6 hours, including scenic stops</li><li>A mix of sweeping corners, technical twisties, and elevation changes</li><li>Roads through national parks, lakes, forests, and mountain passes</li></ul><p><strong>Wildlife Watch:</strong>Keep an eye out for kangaroos, wombats, deer, and wild brumbies!</p><p><strong>Accommodation in Thredbo:</strong></p><ul><li><strong>Thredbo Alpine Hotel</strong>– Special rates for BMW Car Club Canberra members<br>Mention the club when booking<br><em><strong>Note:</strong>Cancellation policy applies</em></li><li><span>Please call Mechelle Petty: (02) 6459 4299 -OR- email: Tahfunctions@evt.com<br>This is the information needed when booking:</span></li><li><div><em>Name of guest/s</em></div><div><em>1 or 2 Guests</em></div><div><em>Phone number</em></div><div><em>Double or Single Room</em></div><div><em>Email address:</em></div></li></ul><p><strong>Detailed Drive Segments</strong></p><p><strong>Cooma → Adaminaby</strong></p><ul><li>Gentle curves and wide-open countryside</li><li>Coffee stop and leg stretch in Adaminaby</li></ul><p><strong>Adaminaby → Cabramurra</strong></p><ul><li>Climbing into alpine forests</li><li>Tighter bends and cool mountain air</li><li>Lunch at<strong>Cabramurra Pub</strong></li></ul><p><strong>Cabramurra → Khancoban</strong></p><ul><li>Technical downhill drive with stunning valley views</li><li>Coffee and baked goods at<strong>Pickled Parrot Providore</strong></li></ul><p><strong>Khancoban → Thredbo</strong></p><ul><li>Epic stretch along the Alpine Way</li><li>Hairpin bends, smooth tarmac, and spectacular views of Kosciuszko National Park</li></ul><p><strong><span>Important Reminders</span></strong></p><ul><li><strong>UHF Radio:</strong>Bring a fully charged radio (minimum 2W; 5W with external antenna recommended)</li><li><strong>Fuel Up in Cooma:</strong>Limited and expensive options in the high country</li><li><strong>Driving Etiquette:</strong>Maintain safe distances and visual contact with the car behind you</li><li><strong>National Parks Pass:</strong>Required for Thredbo<br>Bring your annual pass or purchase a day pass on arrival</li></ul><p><strong><span>DAY THREE – Sunday: Explore &amp; Return</span></strong></p><p><strong>Drive Map:</strong><br><a href="https://maps.app.goo.gl/LxSeLcoydXbeECkj9" target="_blank" rel="noopener">Sunday Route</a></p><p>Sunday is more relaxed and flexible. We’ll have optional activities in the area (to be revealed closer to the event), but<strong>one highlight is confirmed</strong>:</p><p><strong>Wild Brumby Distillery Stop</strong></p><ul><li>Enjoy schnapps, great food, coffee, and mountain views</li><li>Stroll the grounds and enjoy the peaceful vibe (and the hard-working chickens!)</li></ul><p><strong>Return Drive:</strong><br>Take the scenic route home at your own pace. Suggested path:</p><p>Berridale &gt; Old Adaminaby (great photo stop) &gt; Adaminaby (refreshments) &gt; Cooma &gt; ACT</p><p>We’ll be joined by our friends from<strong>BMW Drivers Club NSW</strong>, making this an even more exciting social and driving event.</p><p><strong>BMW DC NSW Pre-Weekend Events (Optional)</strong></p><p><strong>Thursday &amp; Friday Morning</strong><br>BMW DC NSW is hosting events on Thursday and Friday morning before our clubs combine for the weekend.<br>If you''re interested in joining these earlier sessions, please register via the<strong>BMW DC NSW event page</strong>and contact<strong>Luke</strong>from our club.</p><p><strong>Don''t Miss Out!</strong></p><p>This is shaping up to be a<strong>sensational weekend</strong>of scenic drives, social connection, great food, and unforgettable moments. We look forward to seeing you on the road!</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/snowy-drive-7c14ac21-5af27e0a.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/snowy-drive-7c14ac21-c5147715.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/snowy-drive-7c14ac21-c5147715.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>Cooma and Thredbo Dinners – $120.00 Please choose this if you are joining us for dinner both nights: Lebanese banquet @ Roses Restaurant and Cascades @ Thredbo Alpine Hotel.</li><li>Thredbo Dinner – $75.00 Please choose this if you are joining us for dinner at Cascades @ Thredbo Alpine Hotel ONLY</li></ul>', 'Cooma, NSW', '2025-11-07T04:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/1-0b5a48cd-a7672c06.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6324410, 'Goulburn Car and Motorcycle Show', '<p><span><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/526763822-1048542337441184-6253094913180027429-n-16ea4ade-545bbbcc.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/526763822-1048542337441184-6253094913180027429-n-16ea4ade-cf7976c5.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/526763822-1048542337441184-6253094913180027429-n-16ea4ade-cf7976c5.webp" loading="lazy" alt="" title=""></picture><br></span></span></p><p><span><span>Join Us for the 7th Annual Goulburn Car &amp; Motorcycle Show!</span></span></p><p><span>Get ready for a day of horsepower and community spirit as the Goulburn Car and Motorcycle Show returns for its seventh year, now in partnership with<span>One Raceway</span>and proudly supported by the<span>Rotary Club of Goulburn</span>.</span></p><p><span><span><strong>Event Highlights:</strong></span></span></p><ul><li><span>A stunning showcase of classic and modern cars and motorcycles</span></li><li><span>Delicious food and beverage stalls</span></li><li><span>A great day out for enthusiasts, families, and the whole community</span></li></ul><ul></ul><p><span><span><strong>Meeting Point:</strong></span><br></span></p><ul><li><span><span><span><strong><a href="https://www.google.com/maps/place/Harris+Farm+Markets+Majura+Park/@-35.2954122,149.1863302,616m/data=!3m1!1e3!4m14!1m7!3m6!1s0x6b164dca83286bad:0x8cd5877a2fc960da!2sHarris+Farm+Markets+Majura+Park!8m2!3d-35.2954122!4d149.1889051!16s%252Fg%252F11y4br4n87!3m5!1s0x6b164dca83286bad:0x8cd5877a2fc960da!8m2!3d-35.2954122!4d149.1889051!16s%252Fg%252F11y4br4n87?entry=ttu&amp;g_ep=EgoyMDI1MDkxNC4wIKXMDSoASAFQAw%3D%3D" target="_blank" rel="noopener">Three Mills Bakery, Harris Farm, Majura Park,</a><span><span>Arrive by 7:45 AM</span></span></strong></span></span></span></li><li><span><span><span><strong>Departure to One Raceway at<span>8:00 AM sharp</span></strong></span></span></span></li></ul><p><span>Don''t miss this fantastic event – whether you''re a motorhead or just love a great community day out!</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'One Raceway, Goulburn (Pre-meet: Harris Farm, Majura Park)', '2025-11-15T20:45:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/526763822-1048542337441184-6253094913180027429-n-16ea4ade-cf7976c5.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6392732, '2025 Annual General Meeting (AGM)', '<p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-2025-682f02e8-e9b63785.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-2025-682f02e8-ebff2049.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-2025-682f02e8-ebff2049.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span>It is that time of year again - The Annual General Meeting (AGM). The AGM will be held on Tuesday 18 November from 7.30pm at the Harmonie German Club, 49 Jerrabomberra Avenue, Narrabundah.</span></p><p><span><strong><span>Join us in the Pool Room (upstairs next to the restaurant) at 7pm for a chat and complementary finger food and a fruit platter. The AGM will start at 7.30pm.</span></strong></span></p><p><span><strong><strong><span>**Please note if you have forwarded documents to the secretary box and have not received an acknowledgement email from the Secretary, please call Lorna on the number on the notice**.</span></strong></strong></span></p><p><span>You might like to consider coming early and having a meal. Tuesdays are busy as it is $12 Snitty night—<a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/harmonie-food-menu-2022-web-d4c65ffc-a0e486d4.pdf" target="_blank" rel="noopener"><span>Harmonie Club Menu</span></a>. You will just need to sign in at the door with some ID.</span></p><p><span>Please put it in your diary and consider standing for a committee position as your Club needs you.<strong>Come along and take the opportunity to meet fellow members and influence the direction of your Club.</strong></span></p><p><span><strong><span>The agenda for the AGM will be:</span></strong></span></p><ul><li><span>Confirmation of the minutes of the previous 2024 AGM (held November 2024)</span></li><li><span>President’s Report</span></li><li><span>Financial Report</span></li><li><span>Election of Committee (as per section 8 of the Constitution of the BMW Car Club Canberra)</span></li><li><span>General Business</span></li></ul><p><span>During the AGM, an election will take place to appoint the President and Committee for the 2025-2026 year. All current financial members are encouraged to nominate for committee positions. Attached to this notice are the formal AGM notification including committee roles, a nomination form, a proxy voting form, a postal vote form and the minutes of the 2024 AGM.</span></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/notice-of-agm-2025-and-roles-ba5abcef-8056c300.pdf" target="_blank"><span><span>Notice of AGM and Committee Roles and Responsibilities</span></span></a></p><p><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/nomination-form-bmw-car-club-canberra-2025-2233c925-4b1afcef.pdf" target="_blank"><span>Committee</span><span>Nomination Form</span></a></p><p><span><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/proxy-form-bmw-car-club-canberra-2025-959c2b10-70632ddf.pdf" target="_blank">Proxy Voting Form</a><br></span></p><p><span><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/postal-voting-form-bmw-car-club-canberra-2025-254afcf4-8495ab3d.pdf" target="_blank">Postal Voting Form</a><br></span></p><p><span><a href="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/minutes-of-annual-general-meeting-november-2024-b725bc1f-66019798.pdf" target="_blank"><span>Minutes of AGM 2024</span></a><br></span></p><p><span><strong>Only financial (excluding associate) members as at Tuesday 18 November 2025 are eligible to vote.</strong>If you are unable to attend the AGM, you may choose to nominate a proxy to vote on your behalf, submit a nomination or send a postal vote, however these must be lodged with the Secretary by emailing<a href="mailto:secretary@bmwclubcanberra.org.au">secretary@bmwclubcanberra.org.au</a>.</span></p><p><strong><span>**Please note: If you do not receive an acknowledgement email from the Secretary, please call Lorna (number listed in the Notice) before the AGM.**</span></strong></p><p><span>If you wish to raise a notice of motion at the meeting, please email your motion to the Secretary by Monday 27 October 2025.</span></p><p><span>You can also nominate on the night. If two or more members have nominated for the same position this year, we will be using a ballot system rather than a show of hands.</span></p><p><span>I hope you can attend the AGM and look forward to your continued support and involvement in the activities of the BMW Car Club Canberra.</span></p><p><span>Regards</span></p><p>Lorna Kunz</p><p>Secretary</p><p>BMW Car Club Canberra</p><p>secretary@bmwclubcanberra.org.au</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'The Harmonie German Club - 49 Jerrabomberra Avenue, Narrabundah', '2025-11-18T08:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/bmw-car-club-canberra-annual-genral-meeting-2025-682f02e8-ebff2049.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6511376, '2026 Poker Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-7603-b396362e-a798b799.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-7603-b396362e-f98c687e.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-7603-b396362e-f98c687e.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for our first event of 2026. For those of you that have not attended a Poker Run before, you collect a card at five different locations and the best hand wins a prize.</p><p><span>Meeting at</span><strong>McDonalds Molonglo on Kirkpatrick Street</strong>(1st card ). Driver briefing at 10.00am, leaving shortly after. Travel out the Cotter Road and turn right onto Brindabella Road passing Uriarra Village and turn right onto Uriarra Road (2nd card).</p><p>Continue on Uriarra Road which turns into Fairlight Road and turn right onto Mountain Creek Road. Turn right onto Wee Jasper Road (3rd card), turn right onto Yass Valley Way (4th card) and turn right at the second round about onto the Barton Highway.</p><p>Lunch will be at the Murrumbateman Pub where you will collect the 5th card.</p><p><a href="https://www.google.com/maps/dir/McDonald''s,+14A+Kirkpatrick+St,+Weston+ACT+2611/Uriarra+Village+ACT/Taemas+Bridge,+Wee+Jasper+Road,+Cavan+NSW/Murrumbateman+Country+Inn,+Barton+Highway,+Murrumbateman+NSW/@-35.0926364,149.0768774,10.79z/data=!4m31!4m30!1m5!1m1!1s0x6b17b3cef387775f:0x1facf1ceda7779cb!2m2!1d149.0565663!2d-35.3219007!1m10!1m1!1s0x6b17b756e9570ab1:0x986e1bf240ab21e1!2m2!1d148.9248239!2d-35.2958618!3m4!1m2!1d148.9505731!2d-35.2463242!3s0x6b17b044ad88c3bd:0xb5c72a85ecb5bbf8!1m5!1m1!1s0x6b17097c34537751:0x55578e270a44532b!2m2!1d148.8481134!2d-35.003359!1m5!1m1!1s0x6b1704ebeabe1b13:0xad08436a4afa44aa!2m2!1d149.0299224!2d-34.9691963!3e0?entry=ttu" target="_blank" rel="noopener">Drive Route Here</a></p><p><span>We intend to be at the Murrumbateman Pub by 12.00-12.30. We may even do a quiz/trivia also at lunch,<span><span>likelihood</span></span>the topic will be on BMW. ;)</span></p><p><strong>Please bring your UFH/CB radio if you have one, we''ll have some club ones available to borrow if needed. We''ll also nominate a Lead Driver and a Tail-End Charlie on the day to assist with keeping the group together (t</strong><strong>his will be a leisurely drive) . Please familiarise yourself with the route (above).</strong></p><p><span><span>Registration is essential for catering. If you are no longer able to attend, please let us know.</span></span></p><p>We look forward to seeing you on the Poker Run!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Start at McDonalds Molonglo, Lunch at Murrumbateman Pub', '2026-01-24T23:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dsc-7603-b396362e-f98c687e.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6536777, 'Friday Night Cruise - Bimmers & Burgers', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fri-night-cruise-d3eccd18-9e41a4ce.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fri-night-cruise-d3eccd18-38642ca6.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fri-night-cruise-d3eccd18-38642ca6.webp" loading="lazy" alt="" title=""></picture><br></p><p>Start your engines, bring your appetite, and get ready for a great Friday night out.</p><p><strong>6:00 PM – Meet &amp; Grease</strong><br>Cruise into Brodburger Woden to kick things off with a relaxed meet-and-greet. Grab one of their famous burgers, chat with fellow enthusiasts, and check out each other’s rides.</p><p><strong>7:00 PM – The Cruise</strong><br>Once we’re fuelled up, we’ll roll out for a scenic drive to Red Hill. Enjoy the views, the company, and the open road as we take in the city at night. We’ll also capture some awesome night shots along the way.</p><p><strong>8:00 PM – Sweet Endings</strong><br>We’ll wrap up the evening in Kingston with dessert at Gelato Messina. Treat yourself to something sweet and unwind after a great cruise.</p><p>Parking details options below:</p><ul><li><span>2 hours of free underground parking -</span><span><span>Supabarn Kingston (Eyre Street Market)</span></span></li><li><span>Open air parking space opposite the</span><span><span>underground parking -<span><span>Supabarn Kingston entry.</span></span></span></span></li></ul><p><strong>Locations and drive route<a href="https://www.google.com/maps/dir/Brodburger,+91+Hindmarsh+Dr,+Phillip+ACT+2606/Red+Hill+Lookout,+Red+Hill+ACT/Gelato+Messina+Kingston/@-35.3331876,149.1156086,4555m/data=!3m1!1e3!4m30!4m29!1m15!1m1!1s0x6b17b5dd9877456f:0x115f8e1085c4dd17!2m2!1d149.086492!2d-35.3491459!3m4!1m2!1d149.0853742!2d-35.3511514!3s0x6b17b4be96b0f0eb:0x3852491a1ac3bea0!3m4!1m2!1d149.1270557!2d-35.3470936!3s0x6b164b5ff901c519:0xfbb939eb1dd97b3e!1m5!1m1!1s0x6b164cb7db6597d5:0xbda80f29a53593c!2m2!1d149.1138234!2d-35.3240926!1m5!1m1!1s0x6b164d929bb1871f:0xfd7f9e7cf6636ca!2m2!1d149.1424097!2d-35.316446!3e0?entry=ttu" target="_blank" rel="noopener">here</a></strong></p><p>We hope to see you there! :)</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Brodburger Woden, 91 Hindmarsh Dr, Phillip', '2026-02-06T07:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/fri-night-cruise-d3eccd18-38642ca6.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6523483, 'February Driver Training: Skidpan Day', '<p><span><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/skidpan0425-471f1a48-ef402f43.jpeg" alt="" title="" loading="lazy"><br></span></p><p><span>We are excited to announce our first driver training session for the year: The Skidpan at Sutton Road Driver Training Complex, Sunday 15 February 2026.</span></p><p><span>We will again be running a split day with 2 sessions. This will help to ensure everyone gets plenty of opportunity on the skid pan without delay.<strong>NOTE:</strong>There is the option to register for the entire day however,<strong>places are limited</strong>. Session times are as follows:</span></p><p><span>Morning: 8:00 am - 12:00 pm</span></p><p><span>Afternoon: 12:00 pm - 4:00 pm</span></p><p><span>For those that aren''t familiar, the skidpan is a slippery circuit that replicates driving on snow/ice or hitting a patch of oil. It''s smooth concrete, water is applied to provide the slide..... Vehicle speeds are less than 50 km/h and as the<span>circuit</span>is so slippery, there is very little wear on tyres and very low risk. The fun factor is extreme as you attempt to control your car with little or no traction!</span></p><p><span><span><span>The Skidpan will help you to better understand your vehicle and car control in general, including what to do when there is understeer or oversteer.</span></span></span></p><p><span><span><span>This is a great learning event for everyone. We strongly encourage new drivers to come and learn more about their vehicle and for experienced drivers to refresh their skills and of course, have fun!</span></span></span><span>Skills learnt on the skidpan are invaluable and can save lives.</span></p><p>Some important things to note:</p><ul><li>No burnouts or black marks to be left on the skid pan</li><li>Suitable clothing and appropriate footwear (no thongs, open-toed shoes, or high heels).</li><li>There are noise limits…..Vehicles must not exceed a noise limit of 85db at 30 meters. Any road registered vehicle *should* be less than this.</li><li>Participants are solely responsible for any property damages.</li><li>There will be more experienced members there to help out. If you would like some assistance please come see us after the briefing.</li><li>Payment required upon registration. If there are issues with payment please contact us ASAP.</li></ul><p>Bank account details below for those wanting to make direct payment, please ensure you email<a href="mailto:treasurer@bmwclubcanberra.org.au" target="_blank">treasurer@bmwclubcanberra.org.au</a>with payment confirmation once complete:</p><p>Account Name: BMW Car Club Canberra<br>BSB: 633-000<br>Account Number: 125925727<br>Reference: xSURNAME+FEB SKIDPANx</p><p>If you would like to take passengers you are more than welcome to.</p><p>There will be light refreshments and tea/coffee facilities as well. We recommend bringing lunch with you however, if you need to buy lunch Queanbeyan is only a few minutes drive away....</p><strong>*Drivers briefings will be at 7:50am sharp and 11:50am sharp. The fun begins at 8:00am and 12:00pm*.</strong><p><span>NOTE: Due to increased hire costs, pricing has been updated. $135 ($160 for non-members) per vehicle, with multiple drivers allowed. Places are limited, register early to avoid disappointment!</span></p><p><span>We are looking forward to seeing you there and most of all, have FUN!</span></p><h3>Registration</h3><ul><li>Afternoon Session - Member Price – $135.00 Official BMW Club Member Price.Participants may share a car, however it is $135 per car to book a place on the day.</li><li>Afternoon Session - Non-Member Price – $160.00 Non-Member Price.Participants may share a car, however it is $160 per car to book a place on the day.</li><li>Whole Day - Members – $195.00 Join us for both morning and afternoon sessions</li><li>Whole Day - Non-Members – $220.00 Join us for both morning and afternoon sessions</li></ul>', 'Sutton Road Driver Training Complex', '2026-02-14T20:45:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/skidpan0425-471f1a48-ef402f43.jpeg', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6536739, 'Country Cruise to Dalton, NSW', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dalton-pub-lunch-rub-29511aad-988af991.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dalton-pub-lunch-rub-29511aad-05e7c0f4.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dalton-pub-lunch-rub-29511aad-05e7c0f4.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for a country drive as we head out to the historic<strong><a href="https://www.theroyalhoteldalton.com.au/" target="_blank" rel="noopener">Royal Hotel in Dalton</a></strong>for a delicious lunch and great company. It’s the perfect chance to stretch your BMW’s legs, enjoy some scenic backroads, and catch up with fellow enthusiasts.</p><p><strong>Meeting Point:</strong>Red Rooster Queanbeyan –<em>3 Bungendore Rd</em><br><strong>Meet time:</strong>10:30am<br><strong>Departure time:</strong>10:45am</p><p><span><strong>Drive Route:</strong></span><a href="https://maps.app.goo.gl/Zs6sHwJs7JiJu4yc9" target="_blank" rel="noopener"><span>Google Maps</span></a></p><p><span>We’ll cruise together along a beautiful country route straight to the Royal Hotel, where a hearty pub lunch awaits.</span></p><p><strong>Please register</strong>so we can confirm numbers and organise a table booking at the pub.</p><p>Can’t wait to see you and your BMW out on the open road!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Meet Red Rooster QBN > Royal Hotel for lunch, Dalton, NSW', '2026-02-28T23:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/dalton-pub-lunch-rub-29511aad-05e7c0f4.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6566936, 'Social Drive: Southern Tablelands - Lake George Winery', '<p><span><strong>Social Drive: Morning Tea at Sutton and lunch at Lake George Winery</strong></span></p><p><span>Please come and join us on the first of our social drives for 2026.</span></p><p><span><span>Meet at McDonald''s Lyneham (Exhibition Park) @ 10am, departing 10.15am. First stop will be Sutton Bakery for morning tea and a chat.</span></span><br></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/suttonbakery-7ba07594-fb740ebe.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/suttonbakery-7ba07594-ba3ee124.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/suttonbakery-7ba07594-ba3ee124.webp" loading="lazy" alt="" title=""></picture><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/suttonbakery2-938bcb32-250155af.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/suttonbakery2-938bcb32-6ebe0c4b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/suttonbakery2-938bcb32-6ebe0c4b.webp" loading="lazy" alt="" title=""></picture><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/suttonbakery1-93712aae-9d7b995a.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/suttonbakery1-93712aae-31aa5c61.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/suttonbakery1-93712aae-31aa5c61.webp" loading="lazy" alt="" title=""></picture><br></span></p><p><span><span>We will leave Sutton to drive to Lake George Winery by 11.30 for lunch at 12 noon in the Westering Restaurant, 173 The Vineyard Rd, Lake George.</span></span><br></p><p><span>You can view the menu online at<a href="https://www.lakegeorgewinery.com.au/dine/" target="_blank" rel="noopener">https://www.lakegeorgewinery.com.au/dine/</a>. Depending on numbers (15 or over) we may need to pre-order. We will need to confirm numbers by Tuesday 3 March with the restaurant.</span></p><p><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/lgw3-bb8f1a29-1db86e2f.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/lgw3-bb8f1a29-514b9c82.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/lgw3-bb8f1a29-514b9c82.webp" loading="lazy" alt="" title=""></picture><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/lgw-c8b86988-ef4fde5d.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/lgw-c8b86988-81274bd4.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/lgw-c8b86988-81274bd4.webp" loading="lazy" alt="" title=""></picture><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/lgw1-6481aa14-3551037a.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/lgw1-6481aa14-d3f3da3f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/lgw1-6481aa14-d3f3da3f.webp" loading="lazy" alt="" title=""></picture></span></p><p><span><span>Whether you are retired or have a day off come along to enjoy a great drive, a lovely meal and meet other members in a different setting.</span></span></p><p><span>When it’s time to leave, instead of just driving back to Canberra, you can check out the cellar door or explore Collector -<a href="https://www.collectorvillage.com/" target="_blank" rel="noopener">https://www.collectorvillage.com/</a></span></p><p><span>Here is a map of our route for you to view -<a href="https://www.google.com/maps/dir/McDonald''s,+661+Northbourne+Avenue,+Lyneham+ACT+2911/Little+Sutton+Bakehouse,+1+Victoria+St,+Sutton+NSW+2620/Lake+George+Winery,+173+The+Vineyards+Rd,+Lake+George+NSW+2581/@-35.1069548,149.1035227,43911m/data=!3m2!1e3!4b1!4m20!4m19!1m5!1m1!1s0x6b1653aa72f82e1f:0x40345bf5c5c8857b!2m2!1d149.1504026!2d-35.2304756!1m5!1m1!1s0x6b1657b7fb1de583:0x7dfc8007177d94ba!2m2!1d149.2529149!2d-35.1641348!1m5!1m1!1s0x6b16f18fb86ce49b:0x695a16616fede395!2m2!1d149.3821914!2d-34.9840221!3e0?entry=ttu&amp;g_ep=EgoyMDI2MDIwNC4wIKXMDSoASAFQAw%3D%3D" target="_blank" rel="noopener">Social Drive to Lake George Winery via Little Sutton Bakehouse</a></span></p><p><br></p><p><span>If you have any questions please contact Yvonne M: 0428 488 053 or Lorna M: 0408 621 119</span></p>', 'Lake George Winery', '2026-03-05T22:45:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/suttonbakery-7ba07594-ba3ee124.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6523491, 'Pheasant Wood Circuit Track Day', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-eb62e6d3.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-80610a9f.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-80610a9f.webp" loading="lazy" alt="" title=""></picture><br></p><p>Welcome to 2026! Time to shift gears and build on the success of our previous events at Pheasant Wood Circuit.</p><p>Let''s make this a day for all to enjoy. Bring your friends, family and enthusiasts out for the day.</p><p><strong>Registrations are limited, be sure to register ASAP to avoid disappointment!</strong></p><p>As with previous events, we will be providing catering so that all you need to do is turn up and enjoy the day.</p><p>Whether you''re a seasoned driver, weekend warrior or first-timer, come and join us for a fun day at our Pheasant Wood Circuit Track Day! All enthusiasts welcome, BMW or otherwise.</p><p>With an open pit lane format, you''ll have the time you need to perfect your driving. There will be dedicated beginner sessions and passenger laps (non-timed) also. Our fun and welcoming environment will ensure you have a great time.</p><p><strong>Cost:</strong><br>Members: $300<br>Non-members: $350</p><p>There are some mandatory requirements to attend:</p><ul><li>Long sleeve cotton shirt, full length pants and enclosed footwear</li><li>Helmet (hire is available)</li><li>Motorsport (Motorsport Australia or AASA) or track (Pheasant Wood) licence: A day licence can be purchased for $35 @ the track. Note: Can be upgraded on the day to an annual licence for an additional $69</li></ul><p>There will be people available to help you get the best out of the day, sharpen your skills and give you some tips and get the best out of your track time.</p><p><strong>Again, this will be a fully catered event - Your registration fee includes all lunch, snacks and drinks (water, soft drink, tea and coffee). Simply turn up and enjoy the day!</strong></p><p><strong>Gates open at 7:30am. Everyone MUST Arrive no later than 8:15am (to complete sign on). There will be a drivers briefing commencing at 8:45am. All drivers MUST attend and be ready to hit the track at 9:00am.</strong></p><p>On top of being an already impressive day, we will have awards for a number of categories as well.</p><p>NOTE: We will need volunteers to assist in the café area and admin duties. Volunteers will be provided with lunch, snacks, drinks, etc.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pic2-7c1dc79d-ad633fa5.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pic2-7c1dc79d-c55aab93.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pic2-7c1dc79d-c55aab93.webp" loading="lazy" alt="" title=""></picture><br></p><p>If you have any questions please don’t hesitate to ask. Further information will be sent out to registrants closer to the day.</p><p>Come and practice, test your car or just play for the day - We hope to see you there!!</p><h3>Registration</h3><ul><li>Member Registration – $300.00 Members pricePlease include the club name and your club member number.</li><li>Member''s Guest Drive Registration – $300.00 Members pricePlease include the club name and your club member number.</li><li>Non-Member registration – $350.00 Non-member pricing</li><li>Viewing Guest Registration – $25.00 This is for all participants that are attending to watch the day and wish to be catered for.Price includes, lunch, snack, drink, etc.</li><li>Volunteer Registration This is for volunteers that are coming to watch and assist with organising the day. this includes catering and admin duties for the day.As a volunteer you will be provide with lunch, snacks, drinks, etc.</li></ul>', 'Pheasant Wood Circuit, Marulan', '2026-03-14T20:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pwc-track-event-pic-cover-70332fe8-80610a9f.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6455029, 'Wheels 2026 – Back in Canberra! (BMW Registration Only)', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/media-bc6061f8-a1039a13.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/media-bc6061f8-b993276b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/media-bc6061f8-b993276b.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us for the<strong>45th edition of the region’s biggest annual automotive showcase</strong>, where heritage motoring meets modern innovation. This is your chance to experience an incredible<strong>static display of cars, bikes, trucks, and more</strong>– from veteran and vintage classics to modified masterpieces, plus the latest electric vehicles from across the ACT and regional NSW.</p><p><strong>Why you should be there:</strong></p><ul><li>See hundreds of stunning vehicles up close</li><li>Connect with passionate motoring enthusiasts</li><li>Celebrate automotive history and the future of driving</li></ul><p><strong>Exhibitor Details:</strong></p><ul><li><strong>Entry Fee:</strong>$10 per vehicle</li><li><strong>Tickets:</strong>Pre-purchased tickets must be shown at entry (available at the gate too)</li><li><strong>Passengers &amp; Visitors:</strong>FREE admission!</li><li>All exhibited vehicles<strong>must be registered and insured</strong></li></ul><p>Let’s make this year unforgettable!<strong>Help us win the trophy for Best Display by a CACTMC Affiliated Club</strong>– bring your best and let’s create an epic showcase together.</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/media-1-09eb702b-7c1315ac.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/media-1-09eb702b-3fa8f9f0.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/media-1-09eb702b-3fa8f9f0.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Thoroughbred Park, ACT', '2026-03-21T21:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/media-bc6061f8-b993276b.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6536765, 'Coffee, Cruising & Lunch', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/majors-creek-pub-pic-2-f8e01f67-0bf69fb0.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/majors-creek-pub-pic-2-f8e01f67-7c259343.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/majors-creek-pub-pic-2-f8e01f67-7c259343.webp" loading="lazy" alt="" title=""></picture><br></p><p>Feel like a cruisy day out? Bring the trusty steed and come hang with the club!</p><p>We’re kicking things off at<strong>Sutton Bakery</strong>for coffee, pastries, and a bit of a chat. Once everyone’s caffeinated and smiling, we’ll jump in the cars and take the scenic backroads all the way to<strong>Majors Creek Pub</strong>for a relaxed lunch.</p><p><strong>Meet Location:</strong>Sutton Bakery,<span><span>Victoria St, Sutton NSW</span></span><br><strong>Meeting Time:</strong><span>10:00am<br><strong>Departure Time:</strong></span>10:30am</p><p><strong>Drive Route:<a href="https://www.google.com/maps/dir/Little+Sutton+Bakehouse,+1+Victoria+St,+Sutton+NSW+2620/Bungendore,+New+South+Wales+2621/Braidwood,+New+South+Wales+2622/Majors+Creek+Hotel,+2+Seymour+St,+Majors+Creek+NSW+2622/@-35.3308544,149.2665946,102135m/data=!3m1!1e3!4m26!4m25!1m5!1m1!1s0x6b1657b7fb1de583:0x7dfc8007177d94ba!2m2!1d149.2529149!2d-35.1641348!1m5!1m1!1s0x6b165e1d3c7710c9:0x40609b49043dbc0!2m2!1d149.440445!2d-35.2562507!1m5!1m1!1s0x6b15d3117cb5021b:0x40609b490440720!2m2!1d149.7990648!2d-35.4460326!1m5!1m1!1s0x6b16735cb1cdea4d:0x97f55895ef6c5d8f!2m2!1d149.738449!2d-35.566925!3e0?entry=ttu&amp;g_ep=EgoyMDI2MDQwOC4wIKXMDSoASAFQAw%3D%3D" target="_blank" rel="noopener"><span>Google Maps</span></a></strong></p><p><strong><strong>Please register</strong></strong><span>so we can confirm numbers and organise a table booking at the pub.</span></p><p><span>Can’t wait to see you and your trusty steed !</span></p><p><strong><span><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/majors-creek-pub-91f9f039-bede8f71.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/majors-creek-pub-91f9f039-e3d31631.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/majors-creek-pub-91f9f039-e3d31631.webp" loading="lazy" alt="" title=""></picture></span></strong></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Meet Sutton Bakery > Majors Creek Pub', '2026-04-12T00:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/majors-creek-pub-pic-2-f8e01f67-7c259343.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6665068, 'The Ultimate Mystery Drive', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/copilot-20260420-192526-83672036-08c53c2b.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/copilot-20260420-192526-83672036-334ecd2b.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/copilot-20260420-192526-83672036-334ecd2b.webp" loading="lazy" alt="" title=""></picture><br></p><p><span>We’re kicking off our first ever Mystery Drive and you’re invited to join the adventure, the curiosity, and the convoy fun!</span></p><p><span>We’re heading out on a ~70 km adventure to a top‑secret destination. No hints, no spoilers - you’ll find out only when you arrive. What we can promise: stunning roads, great company, and scenery you’ll be glad you didn’t miss.</span></p><span>Meet us at<span>Two Before Ten Denman</span>for a coffee at<span>10:30am</span>, then we’ll hit the road at<span>11am sharp</span>.</span>Lunch awaits at our mystery location, so bring your appetite.<p><span>Please register so we can confirm numbers with the venue, and let us know if your plans change and you’re unable to attend.</span></p><p><span>Reminder to bring your CB radios. Club radios will be available for anyone who needs one.</span></p><p><span>It’s going to be a fun one, we hope you can join the adventure!</span></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Meeting Location, Two Before Ten, Denman Prospect Shops', '2026-05-17T00:30:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/copilot-20260420-192526-83672036-334ecd2b.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6670663, 'Cookies Cycles Annual Fish And Chip Run', '<p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20240825-013826308-da98a2a3-ec485528.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20240825-013826308-da98a2a3-6da49b78.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20240825-013826308-da98a2a3-6da49b78.webp" loading="lazy" alt="" title=""></picture><br></p><p>Join us together with the Volkswagen Club for Cookies Cycles’ annual Fish N Chip Run to Corrigans Beach, Batemans Bay.</p><p>The Fish N Chip Run is a fundraiser supporting Camp Quality, an Australian children’s cancer charity that has been improving the quality of life for kids facing cancer for over 40 years. All funds raised on the day will contribute to the Cookies Cycles Cruisers Team, who are taking part in the 2026 Super Heroes Classic Cruise.</p><p><strong>Event details:</strong></p><ul><li>8:00am – Meet at the front of Old Parliament House</li><li>8:30am – Departure, cruising the Kings Highway to the coast</li><li>Coffee stop in Braidwood</li><li>Meet up with our South Coast friends at the Nelligen Pub</li><li>Continue on to Corrigans Beach for lunch</li></ul><p>Corrigans Beach offers something for everyone, including a large playground for kids, toilet facilities, covered eating areas, and shops nearby.</p><p>This is a relaxed get‑together for anyone who loves cars, a scenic drive, and a great day out for a good cause. We look forward to seeing you there!</p><p><picture><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20240824-220039646-89812505-03bd3e0a.avif" type="image/avif"><source srcset="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20240824-220039646-89812505-cddbf50c.webp" type="image/webp"><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20240824-220039646-89812505-cddbf50c.webp" loading="lazy" alt="" title=""></picture><br></p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Old Parliament House (Meet Location) > Corrigans Beach, Batemans Bay.', '2026-08-15T22:00:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/web/pxl-20240825-013826308-da98a2a3-6da49b78.webp', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6584178, 'October Driver Training: Skidpan Day', '<p><span><img src="https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/skidpan0425-471f1a48-ef402f43.jpeg" alt="" title="" loading="lazy"><br></span></p><p><span>We are excited to announce our second driver training session for the year: The Skidpan at Sutton Road Driver Training Complex, Sunday 25 October 2026.</span></p><p><span>We will again be running a split day with 2 sessions. This will help to ensure everyone gets plenty of opportunity on the skid pan without delay.<strong>NOTE:</strong>There is the option to register for the entire day however,<strong>places are limited</strong>. Session times are as follows:</span></p><p><span>Morning: 8:00 am - 12:00 pm</span></p><p><span>Afternoon: 12:00 pm - 4:00 pm</span></p><p><span>For those that aren''t familiar, the skidpan is a slippery circuit that replicates driving on snow/ice or hitting a patch of oil. It''s smooth concrete, water is applied to provide the slide..... Vehicle speeds are less than 50 km/h and as the<span>circuit</span>is so slippery, there is very little wear on tyres and very low risk. The fun factor is extreme as you attempt to control your car with little or no traction!</span></p><p><span><span><span>The Skidpan will help you to better understand your vehicle and car control in general, including what to do when there is understeer or oversteer.</span></span></span></p><p><span><span><span>This is a great learning event for everyone. We strongly encourage new drivers to come and learn more about their vehicle and for experienced drivers to refresh their skills and of course, have fun!</span></span></span><span>Skills learnt on the skidpan are invaluable and can save lives.</span></p><p>Some important things to note:</p><ul><li>No burnouts or black marks to be left on the skid pan</li><li>Suitable clothing and appropriate footwear (no thongs, open-toed shoes, or high heels).</li><li>There are noise limits…..Vehicles must not exceed a noise limit of 85db at 30 meters. Any road registered vehicle *should* be less than this.</li><li>Participants are solely responsible for any property damages.</li><li>There will be more experienced members there to help out. If you would like some assistance please come see us after the briefing.</li><li>Payment required upon registration. If there are issues with payment please contact us ASAP.</li></ul><p>Bank account details below for those wanting to make direct payment, please ensure you email<a href="mailto:treasurer@bmwclubcanberra.org.au" target="_blank">treasurer@bmwclubcanberra.org.au</a>with payment confirmation once complete:</p><p>Account Name: BMW Car Club Canberra<br>BSB: 633-000<br>Account Number: 125925727<br>Reference: xSURNAME+OCT SKIDPANx</p><p>If you would like to take passengers you are more than welcome to.</p><p>There will be light refreshments and tea/coffee facilities as well. We recommend bringing lunch with you however, if you need to buy lunch Queanbeyan is only a few minutes drive away....</p><strong>*Drivers briefings will be at 7:50am sharp and 11:50am sharp. The fun begins at 8:00am and 12:00pm*.</strong><p><span>Pricing: $135 ($160 for non-members) per vehicle, with multiple drivers allowed. Places are limited, register early to avoid disappointment!</span></p><p><span>We are looking forward to seeing you there and most of all, have FUN!</span></p><h3>Registration</h3><ul><li>Afternoon Session - Member Price – $135.00 Official BMW Club Member Price.Participants may share a car, however it is $135 per car to book a place on the day.</li><li>Afternoon Session - Non-Member Price – $160.00 Non-Member Price.Participants may share a car, however it is $160 per car to book a place on the day.</li><li>Morning Session - Member Price – $135.00 Official BMW Club Member Price.Participants may share a car, however it is $135 per car to book a place on the day.</li><li>Morning Session - Non-Member Price – $160.00 Non-Member Price.Participants may share a car, however it is $160 per car to book a place on the day.</li><li>Whole Day - Members – $195.00 Join us for both morning and afternoon sessions</li><li>Whole Day - Non-Members – $220.00 Join us for both morning and afternoon sessions</li></ul>', 'Sutton Road Driver Training Complex', '2026-10-24T20:45:00.000Z', NULL, NULL, 'https://pr-qxm2kr.run402.com/_blob/assets/bmwclubcanberra/skidpan0425-471f1a48-ef402f43.jpeg', false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
INSERT INTO events (id, title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, source_timezone, source_timezone_label, time_display_mode, import_review_state, source_metadata, created_by) VALUES (6611128, 'Cooma Motorfest 2026', '<p><br></p><p>Join us for Motorfest 2026 which is set to be a sensational event.</p><p>Every two years, the Cooma Car Club hosts the regions'' largest festival of motoring - Motorfest.</p><p>Over 400 cars, trucks and motorbikes are displayed. Together with corporate displays and entertainment, the event takes on a carnival atmosphere where the public can admire the contribution to motoring history that members of the Cooma Car Club have collected, restored, and maintained. The event attracts over 4,000 visitors!</p><p>The Cooma Car Club has decided to waive the registration fees for this year''s Motorfest - that''s right, all vehicles can be entered for FREE! No charge to display your vehicle and be in the running for a share of the trophies. There is just a $5 per person general entry fee.</p><p>If you wish to display your car, you<u>MUST</u>register via<a href="https://www.coomacarclub.com.au/event-4624824/Registration" target="_blank" rel="noopener">Cooma Car Club - Motorfest 2022</a></p><p>For those wanting to convoy and park together, please meet at Calwell Shopping Centre Car Park, we’ll departing @ 7:00am sharp!</p><h3>Registration</h3><ul><li>RSVP</li></ul>', 'Cooma Showground', '2026-11-06T20:00:00.000Z', NULL, NULL, NULL, false, 'Australia/Sydney', NULL, 'source', 'reviewed', '{}'::jsonb, (SELECT id FROM members WHERE email='port-handoff@bmwclubcanberra.example.invalid'));
